function saveSession(data) {
  try {
    const u = data.user || {};
    const session = { id: u.id, email: u.email, name: (u.user_metadata && u.user_metadata.name) || "", created_at: u.created_at || null, is_marketer: !!(u.user_metadata && u.user_metadata.is_marketer), access_token: data.access_token, refresh_token: data.refresh_token };
    localStorage.setItem("chelgy_session", JSON.stringify(session));
    return session;
  } catch { return null; }
}
function loadSession() {
  try { const s = localStorage.getItem("chelgy_session"); return s ? JSON.parse(s) : null; } catch { return null; }
}
function clearSession() { try { localStorage.removeItem("chelgy_session"); } catch {} }

// Turn a timestamp into "just now / 5m ago / 3h ago / 2d ago"
function relTime(iso){
  try {
    const then=new Date(iso).getTime(); const diff=Math.max(0,Date.now()-then); const m=Math.floor(diff/60000);
    if(m<1) return "just now"; if(m<60) return m+"m ago";
    const h=Math.floor(m/60); if(h<24) return h+"h ago";
    const d=Math.floor(h/24); if(d<7) return d+"d ago";
    return new Date(iso).toLocaleDateString();
  } catch { return ""; }
}

// ─── Keep the login token fresh (Supabase tokens expire ~hourly) ─────────────
function decodeExp(token){ try { const p = JSON.parse(atob(token.split(".")[1])); return p.exp ? p.exp * 1000 : 0; } catch { return 0; } }
function decodeJwtPayload(token){ try { return JSON.parse(atob(token.split(".")[1].replace(/-/g,"+").replace(/_/g,"/"))); } catch { return null; } }
// Supabase ROTATES refresh tokens: each refresh returns a new one and invalidates
// the old. Two refreshes racing (multiple tabs, or parallel upload chunks) both
// send the same old token — the second is rejected and the session dies, which
// surfaces as a sudden 401 mid-upload. So: only ever one refresh in flight, and
// everyone else awaits the same result.
let _refreshInFlight = null;
async function refreshSession(){
  if (_refreshInFlight) return await _refreshInFlight;
  _refreshInFlight = (async () => {
    try { return await doRefreshSession(); }
    finally { setTimeout(()=>{ _refreshInFlight = null; }, 0); }
  })();
  return await _refreshInFlight;
}
async function doRefreshSession(){
  const s = loadSession();
  if (!s || !s.refresh_token) return null;
  try {
    const res = await fetch(AUTH_URL + "/token?grant_type=refresh_token", {
      method: "POST",
      headers: { "apikey": SUPABASE_KEY, "Content-Type": "application/json" },
      body: JSON.stringify({ refresh_token: s.refresh_token })
    });
    const data = await res.json();
    if (!res.ok || !data.access_token) return null;
    const ns = { ...s, access_token: data.access_token, refresh_token: data.refresh_token || s.refresh_token };
    if (data.user) { ns.id = data.user.id; ns.email = data.user.email; ns.name = (data.user.user_metadata && data.user.user_metadata.name) || ns.name; ns.created_at = data.user.created_at || s.created_at; ns.is_marketer = !!(data.user.user_metadata && data.user.user_metadata.is_marketer) || !!s.is_marketer; }
    try { localStorage.setItem("chelgy_session", JSON.stringify(ns)); } catch {}
    return ns.access_token;
  } catch { return null; }
}
// Returns a valid (non-expired) access token, refreshing if needed, or null.
async function freshToken(){
  const s = loadSession();
  if (!s || !s.access_token) return await refreshSession();
  const exp = decodeExp(s.access_token);
  if (exp && Date.now() > exp - 60000) return await refreshSession(); // expired or about to
  return s.access_token;
}
