let lastFfError = "";        // real error from the render engine, surfaced to the user
async function pollVideo(taskId, onProgress) {
  const tid = String(taskId||"");
  lastFfError = "";
  const isFf = tid.indexOf("ff:")===0;                     // our own ffmpeg render engine
  const endpoint = isFf ? "/api/studio-ffmpeg"
    : tid.indexOf("omni:")===0 ? "/api/omni-result"
    : tid.indexOf("cm:")===0 ? "/api/studio-status"
    : "/api/video-result";
  // Long edits genuinely take a while: fetching a multi-GB source, cutting dozens
  // of segments, then a full encode and upload. The old 15-minute ceiling made the
  // browser declare failure (and refund) while the render server was still working
  // — the job often finished fine and nobody ever saw it.
  const maxMs = isFf ? 90 * 60 * 1000 : 15 * 60 * 1000;
  const startedAt = Date.now();
  for (let i = 0; Date.now() - startedAt < maxMs; i++) {
    // Poll briskly at first, then ease off so a long render isn't hammering the API.
    await new Promise(r => setTimeout(r, i < 40 ? 3000 : i < 120 ? 6000 : 10000));
    try {
      const token = isFf ? await freshToken() : null;
      const res = await fetch(endpoint, {
        method: "POST",
        headers: { "Content-Type": "application/json", ...(token?{Authorization:"Bearer "+token}:{}) },
        body: JSON.stringify(isFf ? { action:"status", id: taskId } : { id: taskId })
      });
      const data = await res.json();
      if (isFf){
        if (typeof data.progress === "number" && onProgress) onProgress(data.progress, data.status);
        if (data.status === "done" && data.url) return data.url;
        if (data.status === "error") { lastFfError = data.error || ""; return null; }
        continue;
      }
      if (data.output) return data.output;                 // finished — we have the video
      if (data.status === "completed") return data.output || null;
      if (data.status === "failed") return null;
    } catch {}
  }
  if (isFf) lastFfError = "This edit is taking longer than usual and is still rendering on our side. Check your library in a few minutes — if it completed, it'll be there.";
  return null;
}

// ─── VIDEO EDIT (Fake It) helpers ────────────────────────────────────────────
// Upload a source clip straight from the browser to Supabase Storage (NOT through
// /api — that would hit Vercel's ~4.5MB body cap). Returns a public URL + the
// storage path, so we can delete the input the moment the edit finishes.
// Upload the user's original video to Supabase — audio and all, at real camera-file sizes.
// Small files go up in one direct POST. Anything bigger uses Supabase's RESUMABLE
// upload protocol via the official tus-js-client library (loaded from a CDN, no
// install needed): the file goes up in 6MB chunks with live progress, and if the
// connection drops it resumes from where it left off instead of starting over.
// The browser never holds the whole file in memory — it streams chunks off disk.
const UPLOAD_MAX_GB = 50;                     // guard rail; resumable/TUS supports up to 50GB

// Load tus-js-client once from a CDN and cache it on window.
let _tusPromise = null;
function loadTus(){
  if(typeof window !== "undefined" && window.tus) return Promise.resolve(window.tus);
  if(_tusPromise) return _tusPromise;
  _tusPromise = new Promise((resolve, reject)=>{
    try{
      const s = document.createElement("script");
      s.src = "https://cdn.jsdelivr.net/npm/tus-js-client@4.3.1/dist/tus.min.js";
      s.async = true;
      s.onload = ()=> window.tus ? resolve(window.tus) : reject(new Error("tus unavailable"));
      s.onerror = ()=> reject(new Error("Couldn't load the uploader. Check your connection and retry."));
      document.head.appendChild(s);
    }catch(e){ reject(e); }
  });
  return _tusPromise;
}

async function uploadVideoInput(file, path, onStatus){
  try{
    const token = await freshToken();
    if(!token) return { ok:false, error:"Your session expired — please sign in again." };
    if(file.size > UPLOAD_MAX_GB * 1024 * 1024 * 1024)
      return { ok:false, error:"That file is over " + UPLOAD_MAX_GB + "GB. Trim the clip or export a smaller version first." };
    const mime = file.type || "video/mp4";
    const publicUrl = SUPABASE_URL + "/storage/v1/object/public/sites/" + path;

    // ── Small files: one direct POST (fast path, no library needed) ──
    if(file.size <= 20 * 1024 * 1024){
      const res = await fetch(SUPABASE_URL + "/storage/v1/object/sites/" + path, {
        method: "POST",
        headers: { apikey: SUPABASE_KEY, Authorization: "Bearer " + token, "x-upsert": "true", "Content-Type": mime },
        body: file
      });
      if(!res.ok){
        const body = await res.json().catch(()=>({}));
        return { ok:false, error: String((body && body.error) || ("Upload failed (" + res.status + ")")) };
      }
      return { ok:true, url: publicUrl, path };
    }

    // ── Large files: resumable upload via tus-js-client ──
    let tus;
    try { tus = await loadTus(); }
    catch(e){ return { ok:false, error: (e && e.message) || "Couldn't load the uploader." }; }

    const totalMb = Math.round(file.size / (1024*1024));
    return await new Promise((resolve)=>{
      const upload = new tus.Upload(file, {
        endpoint: SUPABASE_URL + "/storage/v1/upload/resumable",
        retryDelays: [0, 3000, 5000, 10000, 20000, 30000],
        headers: {
          apikey: SUPABASE_KEY,
          "x-upsert": "true"
        },
        // Authorization is set ONLY here — setting it in `headers` too would make
        // XHR append a second value ("Bearer x, Bearer x") and Supabase would
        // reject it as an invalid JWT. This also keeps the token fresh per request,
        // which matters on uploads that run longer than a token's lifetime.
        onBeforeRequest: async (req) => {
          try {
            const t = (await freshToken()) || token;
            if (t) req.setHeader("authorization", "Bearer " + t);
          } catch {
            if (token) req.setHeader("authorization", "Bearer " + token);
          }
        },
        uploadDataDuringCreation: true,
        removeFingerprintOnSuccess: true,
        chunkSize: 6 * 1024 * 1024,          // Supabase requires 6MB chunks
        metadata: {
          bucketName: "sites",
          objectName: path,
          contentType: mime,
          cacheControl: "3600"
        },
        onShouldRetry: (err) => {
          const status = (err && err.originalResponse && err.originalResponse.getStatus && err.originalResponse.getStatus()) || 0;
          if (status === 401 || status === 403) return true;   // token refreshed on retry
          return status === 0 || status === 409 || status === 423 || (status >= 500 && status < 600);
        },
        onError: (err)=>{
          // Surface what the storage service ACTUALLY said. A friendly-but-vague
          // summary hides the real cause and makes these impossible to diagnose.
          const m = String((err && err.message) || err || "");
          let status = 0, bodyText = "";
          try {
            const r = err && err.originalResponse;
            if (r){
              if (r.getStatus) status = r.getStatus();
              if (r.getBody) bodyText = String(r.getBody() || "").slice(0, 300);
            }
          } catch {}
          console.error("[upload] tus error", { status, bodyText, message: m });
          const detail = (status ? ("HTTP " + status + " ") : "") + (bodyText || m).slice(0, 220);
          if(/413|exceeded|maximum allowed size|too large/i.test(m + bodyText))
            resolve({ ok:false, error:"That file exceeds your Supabase Storage limit. In Supabase: Storage → Settings → raise the Global file size limit. (" + detail + ")" });
          else
            resolve({ ok:false, error:"Upload failed. " + detail });
        },
        onProgress: (uploaded, total)=>{
          if(onStatus){
            const pct = Math.min(99, Math.floor((uploaded / (total||file.size)) * 100));
            onStatus("uploading", "Uploading your footage — " + pct + "% of " + totalMb + "MB…");
          }
        },
        onSuccess: ()=>{
          if(onStatus) onStatus("uploaded", "Upload complete — starting the edit…");
          resolve({ ok:true, url: publicUrl, path });
        }
      });
      // Resume a prior interrupted upload of the same file if one exists.
      upload.findPreviousUploads().then((prev)=>{
        if(prev && prev.length) upload.resumeFromPreviousUpload(prev[0]);
        upload.start();
      }).catch(()=> upload.start());
    });
  }catch(e){
    return { ok:false, error:"Upload failed — check your connection and try again." };
  }
}
