// ElevenLabs voiceover generation
async function generateVoiceover(text, voiceId="JBFqnCBsd6RMkjVDRZzb") {
  const token = await freshToken();
  const res = await fetch("/api/voice", {
    method: "POST",
    headers: { "Content-Type": "application/json", ...(token ? { Authorization: "Bearer " + token } : {}) },
    body: JSON.stringify({ text, voiceId })
  });
  if (!res.ok) {
    let msg = "Voiceover failed";
    try { const d = await res.json(); msg = d.error || msg; } catch (_) {}
    throw new Error(msg);
  }
  const balHeader = res.headers.get("X-Credits-Balance");
  const balance = balHeader !== null ? Number(balHeader) : null;
  const blob = await res.blob();
  return { url: URL.createObjectURL(blob), balance };
}

// ─── DOWNLOAD A GENERATED IMAGE AS A REAL JPEG ───────────────────────────────
// The models hand back image bytes inside a base64 data: URL — frequently PNG or
// WebP. Saving those straight to "name.jpg" produces a file whose extension lies
// about its contents: macOS can't build a Finder thumbnail, AirDrop ships a
// degraded preview to the phone, and right-clicking a data: URL to "Save Image
// As" silently fails (only a real <a download> works). Re-drawing the image to a
// canvas and exporting image/jpeg gives genuine JPEG bytes with a matching
// extension — so the file, its thumbnail and AirDrop all behave. Falls back to
// the original bytes (with an honest extension) if the canvas can't be used.
function saveBlobUrl(url, filename, revoke){
  const a = document.createElement("a");
  a.href = url; a.download = filename;
  document.body.appendChild(a); a.click(); a.remove();
  if (revoke) setTimeout(()=>{ try{ URL.revokeObjectURL(url); }catch(_){} }, 8000);
}
async function downloadPic(src, filename){
  const base = (filename||"chelgy").replace(/\.[^./]+$/,"");
  try{
    const img = await new Promise((res,rej)=>{
      const i = new Image();
      i.crossOrigin = "anonymous";
      i.onload = ()=>res(i);
      i.onerror = ()=>rej(new Error("load"));
      i.src = src;
    });
    const c = document.createElement("canvas");
    c.width  = img.naturalWidth  || img.width;
    c.height = img.naturalHeight || img.height;
    const ctx = c.getContext("2d");
    ctx.fillStyle = "#fff"; ctx.fillRect(0,0,c.width,c.height); // JPEG has no alpha — flatten to white
    ctx.drawImage(img, 0, 0);
    const blob = await new Promise(r=>c.toBlob(r, "image/jpeg", 0.95));
    if(!blob) throw new Error("encode");
    saveBlobUrl(URL.createObjectURL(blob), base+".jpg", true);
    return true;
  }catch(_){
    const m = (src||"").match(/^data:([^;]+);base64,(.*)$/);
    if(m){
      try{
        const mime = m[1];
        const ext = mime==="image/png" ? "png" : mime==="image/webp" ? "webp" : "jpg";
        const bin = atob(m[2]); const arr = new Uint8Array(bin.length);
        for(let i=0;i<bin.length;i++) arr[i]=bin.charCodeAt(i);
        saveBlobUrl(URL.createObjectURL(new Blob([arr],{type:mime})), base+"."+ext, true);
        return true;
      }catch(__){}
    }
    saveBlobUrl(src, base+".jpg", false); // last resort (e.g. a cross-origin URL)
    return false;
  }
}

// Bundle a set of generated images into ONE .zip so "Download all" is a single
// file — not a burst of separate saves the browser throttles into "one by one."
// Loads JSZip from a CDN at runtime (no build/install dependency); if that fails,
// falls back to staggered individual downloads so nothing is lost.
// Save a video result. The file lives on the provider's server (cross-origin), so
// a plain <a download> is ignored by the browser and just opens a tab. Fetching it
// as a blob first lets us force a real download; if CORS blocks the fetch we fall
// back to opening it so the person can still save it manually.
async function downloadVideo(src, filename){
  const name = /\.(mp4|webm|mov|m4v)$/i.test(filename||"") ? filename : ((filename||"chelgy").replace(/\.[^./]+$/,"") + ".mp4");
  try{
    const res = await fetch(src, { mode: "cors" });
    if(!res.ok) throw new Error("bad status");
    const blob = await res.blob();
    saveBlobUrl(URL.createObjectURL(blob), name, true);
  }catch(_){
    window.open(src, "_blank", "noopener");
  }
}

async function ensureJSZip(){
  if (typeof window !== "undefined" && window.JSZip) return window.JSZip;
  await new Promise((resolve, reject)=>{
    const s = document.createElement("script");
    s.src = "https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js";
    s.onload = resolve; s.onerror = ()=>reject(new Error("zip library failed to load"));
    document.head.appendChild(s);
  });
  return window.JSZip;
}
async function downloadAllImages(urls, baseName, zipName){
  const list = (urls || []).filter(Boolean);
  if (!list.length) return;
  try {
    const JSZip = await ensureJSZip();
    const zip = new JSZip();
    for (let i = 0; i < list.length; i++) {
      try {
        const blob = await (await fetch(list[i])).blob();
        const ext = blob.type === "image/png" ? "png" : blob.type === "image/webp" ? "webp" : "jpg";
        zip.file((baseName || "image") + "-" + (i + 1) + "." + ext, blob);
      } catch (_) { /* skip one we couldn't fetch, keep the rest */ }
    }
    const out = await zip.generateAsync({ type: "blob" });
    saveBlobUrl(URL.createObjectURL(out), (zipName || "chelgy-photos") + ".zip", true);
  } catch (_) {
    list.forEach((u, i) => setTimeout(()=>saveBlobUrl(u, (baseName || "image") + "-" + (i + 1) + ".jpg", false), i * 400));
  }
}

