function getLevel(pts) { return [...LEVELS].reverse().find(l => pts >= l.min) || LEVELS[0]; }
function nextLevel(pts) { return LEVELS.find(l => l.min > pts); }

async function callClaude(prompt, maxTokens, webSearch=false, image=null) {
  try {
    const res = await fetch("/api/claude", {
      method:"POST", headers:{"Content-Type":"application/json"},
      body:JSON.stringify({ prompt, max_tokens: maxTokens, web_search: webSearch, ...(image?{image}:{}) })
    });
    const d = await res.json();
    return d.text || "Unable to generate. Please try again.";
  } catch { return "Something went wrong. Please try again."; }
}

async function generateOpenAIImage(prompt, inputImages, aspectRatio, quality, background) {
  const token = await freshToken();
  const imgs = Array.isArray(inputImages) ? inputImages : (inputImages ? [inputImages] : []);
  const res = await fetch("/api/openai-image", {
    method: "POST",
    headers: { "Content-Type": "application/json", ...(token ? { Authorization: "Bearer " + token } : {}) },
    body: JSON.stringify({ prompt, inputImages: imgs, inputImage: imgs[0] || null, aspectRatio: aspectRatio || "1:1", quality: quality || "standard", background: background || undefined }),
  });
  const d = await res.json();
  if (!d.image) throw new Error(d.error || "No image");
  return d; // { image, balance }
}
async function writeImagePrompt(idea, imageType, target, image=null) {
  const isVideo = target === "video";
  const instr = isVideo
    ? "You are an expert at writing prompts for AI video generators. Turn the user's rough idea into ONE vivid, detailed, ready-to-paste video prompt. Cover subject, action, setting, camera movement, lighting, mood and style. Return a single tight paragraph only — no preamble, labels, or quotation marks."
    : "You are an expert at writing prompts for AI image generators. Turn the user's rough idea into ONE vivid, detailed, ready-to-paste image prompt for "+(imageType||"a marketing image")+". Cover subject, composition, style, lighting, colors and mood. Return a single tight paragraph only — no preamble, labels, or quotation marks.";
  const seeNote = image ? " A REFERENCE PHOTO is attached — study it and build the prompt around what you see, keeping the real subject/product accurate." : "";
  const out = await callClaude(instr + seeNote + "\n\nThe idea: " + idea, 1000, false, image);
  const clean = (out || "").trim();
  if (!clean || clean === "Unable to generate. Please try again." || clean === "Something went wrong. Please try again.") {
    throw new Error("Couldn't write a prompt. Try again.");
  }
  return clean;
}
async function generateGeminiImage(prompt, inputImages, aspectRatio, quality) {
  const token = await freshToken();
  const imgs = Array.isArray(inputImages) ? inputImages : (inputImages ? [inputImages] : []);
  async function call(q) {
    const res = await fetch("/api/image", {
      method: "POST",
      headers: { "Content-Type": "application/json", ...(token ? { Authorization: "Bearer " + token } : {}) },
      body: JSON.stringify({ prompt, inputImages: imgs, inputImage: imgs[0] || null, aspectRatio: aspectRatio || "1:1", quality: q || "standard" }),
    });
    const d = await res.json();
    if (!d.image) throw new Error(d.error || "No image");
    return d; // { image, balance }
  }
  try {
    return await call(quality);
  } catch (e) {
    // The photo model can reject the 2K/4K tiers on some requests — fall back to standard so the member still gets their image instead of an error.
    if (quality && quality !== "standard") { return await call("standard"); }
    throw e;
  }
}

// Uploads a base64 data-URL image to the public "sites" storage bucket and
// returns its public URL. Path must start with the user's id (e.g. "<uid>/hero-1.png").
async function uploadSiteImage(dataUrl, path) {
  try {
    const m = (dataUrl || "").match(/^data:([^;]+);base64,(.*)$/);
    if (!m) return null;
    const mime = m[1];
    const bin = atob(m[2]);
    const arr = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
    const blob = new Blob([arr], { type: mime });
    const token = await freshToken();
    if (!token) return null;
    const res = await fetch(SUPABASE_URL + "/storage/v1/object/sites/" + path, {
      method: "POST",
      headers: { apikey: SUPABASE_KEY, Authorization: "Bearer " + token, "x-upsert": "true", "Content-Type": mime },
      body: blob
    });
    if (!res.ok) return null;
    return SUPABASE_URL + "/storage/v1/object/public/sites/" + path;
  } catch (e) { return null; }
}

