      const secs=(wmExisting.data.sections||[]).map(sec=>{ if(sec&&sec.type==="offerings"&&Array.isArray(sec.items)){ return {...sec, items: sec.items.filter((_,j)=>j!==idx)}; } return sec; });
      const data={...wmExisting.data, sections:secs};
