  // ─── Photo manager: see every photo on the site + replace / regenerate / delete ───
  function sitePhotoSlots(){
    const secs=(wmExisting&&wmExisting.data&&wmExisting.data.sections)||[]; const out=[];
    const hero=secs.find(x=>x&&x.type==="hero"); if(hero) out.push({key:"hero",label:"Hero image",sub:"Top of your site",url:(hero.image&&hero.image.url)||"",prompt:(hero.image&&hero.image.prompt)||"",ar:"16:9"});
    const about=secs.find(x=>x&&x.type==="about"); if(about) out.push({key:"about",label:"About photo",sub:"Your story section",url:(about.image&&about.image.url)||"",prompt:(about.image&&about.image.prompt)||"",ar:"4:5"});
    const ed=secs.find(x=>x&&x.type==="editorial"); if(ed) out.push({key:"editorial",label:"Feature image",sub:"Editorial banner",url:(ed.image&&ed.image.url)||"",prompt:(ed.image&&ed.image.prompt)||"",ar:"16:9"});
    const off=secs.find(x=>x&&x.type==="offerings"); if(off&&Array.isArray(off.items)) off.items.forEach((it,i)=>out.push({key:"offering-"+i,label:(it.name?it.name:("Item "+(i+1))),sub:"Product / service photo",url:(it.image&&it.image.url)||"",prompt:(it.image&&it.image.prompt)||"",ar:"1:1"}));
    return out;
  }
  function defaultPhotoPrompt(slot){
    const name=(wmExisting&&wmExisting.data&&wmExisting.data.brand&&wmExisting.data.brand.name)||"this business";
    if(slot.key==="hero") return "A striking luxury editorial hero image for "+name;
    if(slot.key==="about") return "An atmospheric scene representing the world of "+name+" — workspace, materials and environment";
    if(slot.key==="editorial") return "An atmospheric brand scene for "+name;
    return "A clean, elegant photograph of "+slot.label;
  }
  async function placeSitePhoto(key, url, prompt){
    const d=JSON.parse(JSON.stringify(wmExisting.data||{})); const secs=d.sections||[];
    const setImg=(obj)=>{ obj.image = (prompt!==undefined) ? {url, prompt} : {...(obj.image||{}), url}; };
    const clrImg=(obj)=>{ delete obj.image; };
    const act = (url===null) ? clrImg : setImg;
    if(key==="hero"){ const s=secs.find(x=>x.type==="hero"); if(s) act(s); }
    else if(key==="about"){ const s=secs.find(x=>x.type==="about"); if(s) act(s); }
    else if(key==="editorial"){ const s=secs.find(x=>x.type==="editorial"); if(s) act(s); }
    else if(key.indexOf("offering-")===0){ const oi=parseInt(key.split("-")[1],10); const off=secs.find(x=>x.type==="offerings"); if(off&&off.items&&off.items[oi]) act(off.items[oi]); }
    return await saveData(d);
  }
  function replaceSitePhoto(key, file){
    if(!file||!wmExisting) return; setEdMgrBusy(key); setWmErr("");
    wmRead(file, async(dataUrl)=>{
      try{ const u=await uploadSiteImage(dataUrl, user.id+"/site-"+Date.now()+"-"+Math.random().toString(36).slice(2,5)+".png"); if(u){ await placeSitePhoto(key,u); setWmPreview(p=>p+1); } else setWmErr("Couldn't upload that image — please try again."); }
      catch(e){ setWmErr("Couldn't upload that image — please try again."); }
      setEdMgrBusy(null);
    });
  }
  async function regenSitePhoto(slot){
    if(!wmExisting||edMgrBusy) return; setEdMgrBusy(slot.key); setWmErr("");
    try{
      const themeStyle=THEME_IMG_STYLE[(wmExisting.data&&wmExisting.data.theme)]||THEME_IMG_STYLE["editorial-porcelain"];
      const dna=((wmExisting.data&&wmExisting.data.styleDNA)?String(wmExisting.data.styleDNA)+" ":"")+themeStyle;
      const basePrompt=(slot.prompt&&slot.prompt.trim())||defaultPhotoPrompt(slot);
      const prompt=basePrompt+" "+dna+" No text, no words, no logos.";
      const r=await generateGeminiImage(prompt, null, slot.ar||"1:1", "standard");
      if(r&&r.image){ if(typeof r.balance==="number") onBalance(r.balance); const u=await uploadSiteImage(r.image, user.id+"/site-"+Date.now()+"-"+Math.random().toString(36).slice(2,5)+".png"); if(u){ await placeSitePhoto(slot.key,u,basePrompt); setWmPreview(p=>p+1); } else setWmErr("Couldn't save the new image — please try again."); }
      else setWmErr("Couldn't generate that image — please try again.");
    }catch(e){ setWmErr("Couldn't generate that image — please try again."); }
    setEdMgrBusy(null);
  }
  async function regenAllPhotos(){
    if(!wmExisting||regenAllBusy||edMgrBusy) return;
    const slots=sitePhotoSlots(); if(!slots.length) return;
    setRegenAllBusy(true); setWmErr(""); setRegenAllProg("");
    try{
      const d=JSON.parse(JSON.stringify(wmExisting.data||{})); const secs=d.sections||[];
      const themeStyle=THEME_IMG_STYLE[d.theme]||THEME_IMG_STYLE["editorial-porcelain"];
      const style=wmPhotoStyle.trim();
      if(style){ d.styleDNA=style; } // bake the requested look in so future photos stay cohesive too
      const dna=((d.styleDNA?String(d.styleDNA)+" ":"")+themeStyle);
      const put=(key,url,prompt)=>{ const set=(o)=>{ o.image={url,prompt}; };
        if(key==="hero"){ const s=secs.find(x=>x.type==="hero"); if(s)set(s); }
        else if(key==="about"){ const s=secs.find(x=>x.type==="about"); if(s)set(s); }
        else if(key==="editorial"){ const s=secs.find(x=>x.type==="editorial"); if(s)set(s); }
        else if(key.indexOf("offering-")===0){ const oi=parseInt(key.split("-")[1],10); const off=secs.find(x=>x.type==="offerings"); if(off&&off.items&&off.items[oi])set(off.items[oi]); }
      };
      let ok=0;
      for(let i=0;i<slots.length;i++){
        const slot=slots[i]; setRegenAllProg("Reshooting "+(i+1)+" of "+slots.length+"…");
        try{
          const basePrompt=(slot.prompt&&slot.prompt.trim())||defaultPhotoPrompt(slot);
          const prompt=basePrompt+" "+dna+" No text, no words, no logos.";
          const r=await generateGeminiImage(prompt, null, slot.ar||"1:1", "standard");
          if(r&&r.image){ if(typeof r.balance==="number") onBalance(r.balance); const u=await uploadSiteImage(r.image, user.id+"/site-"+Date.now()+"-"+Math.random().toString(36).slice(2,5)+".png"); if(u){ put(slot.key,u,basePrompt); ok++; } }
        }catch(e){}
      }
      d.sections=secs;
      await saveData(d);
      setWmPreview(p=>p+1);
      if(!ok) setWmErr("Couldn't regenerate the photos — please try again.");
    }catch(e){ setWmErr("Couldn't regenerate the photos — please try again."); }
    setRegenAllBusy(false); setRegenAllProg("");
  }
  async function deleteSitePhoto(key){
    if(!wmExisting||edMgrBusy) return; setEdMgrBusy(key); setWmErr("");
    try{ await placeSitePhoto(key,null); setWmPreview(p=>p+1); }
    catch(e){ setWmErr("Couldn't remove that photo — please try again."); }
    setEdMgrBusy(null);
  }
  const [secBusy,setSecBusy]=useState(false);
  function curSections(){ return (wmExisting&&wmExisting.data&&Array.isArray(wmExisting.data.sections))?wmExisting.data.sections:[]; }
  async function saveSections(newSecs){
    if(!wmExisting) return; setSecBusy(true); setWmErr("");
    try{ const d=JSON.parse(JSON.stringify(wmExisting.data||{})); d.sections=newSecs; await saveData(d); setWmPreview(p=>p+1); }
    catch(e){ setWmErr("Couldn't save your layout — please try again."); }
    setSecBusy(false);
  }
  async function addSection(type){ const secs=curSections().slice(); const contactAt=secs.findIndex(s=>s&&s.type==="contact"); const item=defaultSection(type); if(contactAt>=0){ secs.splice(contactAt,0,item); } else { secs.push(item); } await saveSections(secs); }
  async function removeSection(idx){ const secs=curSections().slice(); if(idx<0||idx>=secs.length) return; secs.splice(idx,1); await saveSections(secs); }
  async function moveSection(idx,dir){ const secs=curSections().slice(); const j=idx+dir; if(j<0||j>=secs.length) return; const t=secs[idx]; secs[idx]=secs[j]; secs[j]=t; await saveSections(secs); }
  useEffect(()=>{
    if(tool!=="website"||!user||!user.id) return;
    let cancel=false;
    (async()=>{
      try{
        const tok=await freshToken(); if(!tok) return;
        const res=await fetch(SUPABASE_URL+"/rest/v1/websites?select=id,slug,data,theme,custom_domain&user_id=eq."+user.id+"&order=updated_at.desc.nullslast",{ headers:{ apikey:SUPABASE_KEY, Authorization:"Bearer "+tok } });
        const rows=await res.json();
        if(!cancel&&Array.isArray(rows)&&rows.length){ const mapped=rows.map(r=>{ const data=(r.data&&typeof r.data==="object")?r.data:{}; if(!data.theme&&r.theme) data.theme=r.theme; return { id:r.id, slug:r.slug, data, domain:r.custom_domain||null }; }); setWmSites(mapped); setWmExisting(mapped[0]); }
      }catch(e){}
    })();
    return ()=>{ cancel=true; };
  },[tool,user]);
  async function applyEdit(){
    if(!wmEdit.trim()||!wmExisting) return;
    setWmEditLoad(true); setWmErr("");
    try{
      setWmEditNote("");
      const cur = JSON.stringify(wmExisting.data);
      const prompt = "You are the content editor for a published luxury website stored as JSON. You may change ONLY text and structure: headlines, paragraphs, the About text, offerings (names, notes, prices), the testimonial, contact details, navigation labels — and you may add, remove, or reorder sections. You CANNOT change colours, fonts, the theme, layout/spacing, or images; those are handled by separate controls in this editor. If the owner asks for a colour/font/theme change, do NOT modify the site — instead tell them to use the \"Theme\" controls. If they ask to change or add a photo, tell them to use \"Add or replace a photo\". CRITICAL: preserve every existing \"image\":{\"url\":\"...\"} value EXACTLY. Keep the upscale, restrained editorial voice.\n\nOWNER'S REQUEST: "+wmEdit.trim()+"\n\nCURRENT WEBSITE JSON:\n"+cur+"\n\nRespond with ONLY this JSON object (no markdown): {\"site\": <the complete website JSON, edited if you could apply the request, otherwise unchanged>, \"note\": <one short friendly sentence: what you changed, or if you couldn't, which control to use>}";
      const raw = await callClaude(prompt, 12000);
      let t=(raw||"").trim().replace(/^```json/i,"").replace(/^```/,"").replace(/```$/,"").trim();
      const a=t.indexOf("{"), b=t.lastIndexOf("}"); if(a>=0&&b>a) t=t.slice(a,b+1);
      let parsed; try{ parsed=JSON.parse(t); }catch(pe){ throw new Error("That didn't come back cleanly — try rephrasing it."); }
      const updated = parsed && parsed.site; const note = (parsed && parsed.note ? String(parsed.note) : "").trim();
      if(!updated||!Array.isArray(updated.sections)||!updated.brand) throw new Error("That didn't come back cleanly — try rephrasing it.");
      updated.theme = (wmExisting.data&&wmExisting.data.theme) || updated.theme || "editorial-porcelain";
      if(wmExisting.data&&wmExisting.data.custom) updated.custom = wmExisting.data.custom;
      const changed = JSON.stringify(updated) !== JSON.stringify(wmExisting.data);
      if(!changed){
        setWmEditNote(note || "I didn't change anything for that. Colours, fonts and theme are under \"Theme\" above; photos are under \"Add or replace a photo\" below.");
        setWmEditLoad(false); return;
      }
      const tok=await freshToken(); if(!tok) throw new Error("Your session expired — please log in again.");
      const up=await fetch(SUPABASE_URL+"/rest/v1/websites?id=eq."+wmExisting.id,{ method:"PATCH", headers:{ apikey:SUPABASE_KEY, Authorization:"Bearer "+tok, "Content-Type":"application/json", Prefer:"return=minimal" }, body:JSON.stringify({ data:updated, updated_at:new Date().toISOString() }) });
      if(!up.ok) throw new Error("Couldn't save the change: "+(await up.text()));
      setWmExisting(x=>({ ...x, data:updated }));
      setWmEditLog(l=>[wmEdit.trim(), ...l].slice(0,8));
      setWmEdit("");
      setWmEditNote(note || "Done — your change is in the preview.");
      setWmPreview(p=>p+1);
    }catch(e){ setWmErr(e&&e.message?e.message:"Something went wrong — please try again."); }
    setWmEditLoad(false);
  }
  function wmRead(file,cb){ if(!file) return; const r=new FileReader(); r.onload=()=>cb(r.result); r.readAsDataURL(file); }
  function wmNext(){ if(wmStep===1&&(!wmName.trim()||!wmDesc.trim())){ setWmErr("Please add your business name and what you do."); return; } setWmErr(""); setWmStep(s=>Math.min(5,s+1)); }
