  function onUploadVid(e){const files=Array.from((e.target&&e.target.files)||[]);files.forEach(f=>{const r=new FileReader();r.onload=()=>setVVidPhotos(p=>p.length>=3?p:[...p,r.result]);r.readAsDataURL(f);});if(e.target)e.target.value="";}
  function onUploadRefVideo(e){
    const f=(e.target&&e.target.files&&e.target.files[0])||null;
    if(e.target)e.target.value="";
    if(!f)return;
    setVRefVidLoad(true);
    try{
      const url=URL.createObjectURL(f);
      const vid=document.createElement("video");
      vid.preload="auto";vid.muted=true;vid.playsInline=true;vid.src=url;
      const cleanup=()=>{try{URL.revokeObjectURL(url);}catch(err){}setVRefVidLoad(false);};
      const grab=()=>{
        try{
          const c=document.createElement("canvas");
          c.width=vid.videoWidth||720;c.height=vid.videoHeight||1280;
          c.getContext("2d").drawImage(vid,0,0,c.width,c.height);
          const data=c.toDataURL("image/jpeg",0.85);
          setVVidPhotos(p=>p.length>=3?p:[...p,data]);
        }catch(err){}
        cleanup();
      };
      vid.onloadeddata=()=>{
        const seekTo=Math.min(1,(vid.duration||2)/2);
        const onSeek=()=>{vid.removeEventListener("seeked",onSeek);grab();};
        vid.addEventListener("seeked",onSeek);
        try{vid.currentTime=seekTo;}catch(err){grab();}
      };
      vid.onerror=cleanup;
    }catch(err){setVRefVidLoad(false);}
  }
  function durOptionsFor(q){if(q==="omni")return [10];if(q==="veo")return [4,6,8];if(q==="kling4k"||q.indexOf("seedance")===0||q==="1080p")return [5,10,15];return [5,10];}
  function vidCost(){const d=Number(vDuration);if(vQuality==="omni")return CREDIT_COSTS.omniClip;if(vQuality==="veo")return (vAudio?CREDIT_COSTS.veoSec:CREDIT_COSTS.veoSecSilent)*d;if(vQuality==="kling4k")return CREDIT_COSTS.klingSec*d;if(vQuality.indexOf("seedance")===0)return seedanceRate(vQuality)*d;const base=vQuality==="1080p"?CREDIT_COSTS.video1080:vQuality==="720p"?CREDIT_COSTS.videoHD:CREDIT_COSTS.video;return Math.round(base*d/5);}
