// ─── CREDIT SHOP ─────────────────────────────────────────────────────────────
function CreditShop({ onClose, currentCredits, onPurchase, onBalance }) {
  const [purchasingId, setPurchasingId] = useState(null);
  const [success, setSuccess] = useState(false);
  const [buyErr, setBuyErr] = useState("");

  // Web pack id -> Apple product id (note: Agency uses the "agency2" id on Apple).
  const APPLE_PACK_IDS = {
    starter: "com.chelgy.app.credits.starter",
    creator: "com.chelgy.app.credits.creator",
    pro:     "com.chelgy.app.credits.pro",
    studio:  "com.chelgy.app.credits.studio",
    agency:  "com.chelgy.app.credits.agency2",
  };

  // Native (iOS/Mac): buy the pack through Apple. Credits are granted server-side
  // by the RevenueCat webhook, so afterwards we poll the server for the real balance.
  async function buyPackApple(pack) {
    setBuyErr("");
    setPurchasingId(pack.id);
    try {
      const wantId = APPLE_PACK_IDS[pack.id];
      const pkgs = await IAP.getPackages();
      const match = pkgs.find(p => p.productId === wantId);
      if (!match) { setBuyErr("This pack isn't available right now. Please try again shortly."); setPurchasingId(null); return; }
      const res = await IAP.purchase(match.pkg);
      if (res.cancelled) { setPurchasingId(null); return; }
      if (!res.success) { setBuyErr("That purchase didn't go through. Please try again."); setPurchasingId(null); return; }
      setSuccess(true);
      const reconcile = () => { try { const ss = loadSession(); if (ss && ss.access_token && ss.id) getMyMember(ss.access_token, ss.id).then(m => { if (m && (typeof m.credits === "number" || typeof m.credits_purchased === "number") && typeof onBalance === "function") { onBalance((m.credits || 0) + (m.credits_purchased || 0)); } }); } catch (e) {} };
      setTimeout(reconcile, 3000); setTimeout(reconcile, 8000); // webhook may take a moment
      setPurchasingId(null);
    } catch (e) {
      setBuyErr("Could not complete the purchase. Please try again.");
      setPurchasingId(null);
    }
  }

  async function buyPack(pack) {
    if (IS_NATIVE) { return buyPackApple(pack); }
    setBuyErr("");
    setPurchasingId(pack.id);
    try {
      const token = await freshToken();
      if (!token) { setBuyErr("Please log in before purchasing."); setPurchasingId(null); return; }
      const res = await fetch("/api/create-checkout", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ pack_id: pack.id, access_token: token })
      });
      const d = await res.json();
      if (d && d.url) { window.location.href = d.url; return; } // off to Stripe
      setBuyErr((d && d.error) || "Could not start checkout. Please try again.");
      setPurchasingId(null);
    } catch {
      setBuyErr("Could not reach checkout. Please try again.");
      setPurchasingId(null);
    }
  }

  return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.75)",zIndex:9998,display:"flex",alignItems:"flex-start",justifyContent:"center",padding:"max(24px,env(safe-area-inset-top,24px)) 20px 24px",overflowY:"auto"}}>
      <div style={{background:"#fff",width:"100%",maxWidth:520,padding:"32px 28px",position:"relative",maxHeight:"90vh",overflowY:"auto",margin:"auto"}}>
        <button onClick={onClose} style={{position:"absolute",top:14,right:14,background:"none",border:"none",cursor:"pointer",color:"#6B6B6B"}}><Icons.X /></button>

        <div style={{width:24,height:1,background:B.gold,marginBottom:16}} />
        <h2 style={{fontFamily:"Georgia,serif",fontSize:22,fontWeight:400,margin:"0 0 4px"}}>Credit Top-Up</h2>
        <p style={{fontFamily:"sans-serif",fontSize:12,color:B.mid,margin:"0 0 8px",letterSpacing:"0.01em"}}>Purchase credits to generate more images, videos, and voiceovers.</p>

        {/* Current balance */}
        <div style={{background:B.offwhite,border:"1px solid "+B.stone,padding:"14px 16px",marginBottom:20,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
          <span style={{fontFamily:"sans-serif",fontSize:12,color:B.mid,letterSpacing:"0.04em"}}>Current Balance</span>
          <span style={{fontFamily:"Georgia,serif",fontSize:20,color:B.gold}}>{currentCredits.toLocaleString()} credits</span>
        </div>

        {/* Credit costs reference */}
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:1,background:B.stone,marginBottom:20}}>
          {[{label:"Image",cost:"120–750 cr"},{label:"Video",cost:"from 500 cr"},{label:"Voiceover",cost:"150 cr"}].map((item,i)=>(
            <div key={i} style={{background:B.white,padding:"10px 12px",textAlign:"center"}}>
              <div style={{fontFamily:"sans-serif",fontSize:11,fontWeight:700,marginBottom:3}}>{item.label}</div>
              <div style={{fontFamily:"sans-serif",fontSize:10,color:B.gold}}>{item.cost}</div>
            </div>
          ))}
        </div>

        {success&&<div style={{background:"#E8F5EE",border:"1px solid #4CAF82",padding:"11px 14px",fontFamily:"sans-serif",fontSize:12,color:"#2E7D32",marginBottom:14,letterSpacing:"0.04em"}}>Credits added successfully!</div>}

        {/* Credit packs */}
        <div style={{display:"flex",flexDirection:"column",gap:1,background:B.stone}}>
          {CREDIT_PACKS.map(pack=>(
            <div key={pack.id} style={{background:pack.popular?B.goldLight:B.white,padding:"18px 20px",position:"relative"}}>
              {pack.popular&&<div style={{position:"absolute",top:-1,right:16,background:B.gold,color:"#fff",fontSize:8,letterSpacing:"0.14em",fontWeight:700,padding:"3px 10px",fontFamily:"sans-serif"}}>MOST POPULAR</div>}
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:8}}>
                <div>
                  <div style={{fontFamily:"sans-serif",fontSize:14,fontWeight:700,marginBottom:2}}>{pack.name}</div>
                  <div style={{fontFamily:"Georgia,serif",fontSize:18,color:B.gold}}>{pack.credits.toLocaleString()} credits</div>
                </div>
                <div style={{textAlign:"right"}}>
                  <div style={{fontFamily:"Georgia,serif",fontSize:22,fontWeight:400}}>${pack.price}</div>
                  <div style={{fontFamily:"sans-serif",fontSize:9,color:B.mid,letterSpacing:"0.04em"}}>one time</div>
                </div>
              </div>
              <div style={{fontFamily:"sans-serif",fontSize:11,color:B.mid,marginBottom:12,lineHeight:1.5}}>{pack.description}</div>
              <button onClick={()=>buyPack(pack)} disabled={!!purchasingId} style={{background:pack.popular?B.charcoal:B.white,color:pack.popular?"#fff":B.charcoal,border:"1px solid "+B.charcoal,padding:"9px 20px",fontSize:9,letterSpacing:"0.14em",fontFamily:"sans-serif",fontWeight:700,cursor:purchasingId?"not-allowed":"pointer"}}>
                {purchasingId===pack.id?"PROCESSING...":"BUY NOW"}
              </button>
            </div>
          ))}
        </div>

        {buyErr&&<p style={{fontFamily:"sans-serif",fontSize:12,color:B.red,textAlign:"center",marginTop:14,letterSpacing:"0.02em"}}>{buyErr}</p>}
        <p style={{fontFamily:"sans-serif",fontSize:10,color:B.mid,textAlign:"center",marginTop:14,letterSpacing:"0.04em"}}>{IS_NATIVE?"Credits never expire. Purchases are handled securely by the App Store.":"Credits never expire. Secured by Stripe."}</p>
      </div>
    </div>
  );
}

