function WinningProductFinder(){
  const [q,setQ]=useState("");
  const [loading,setLoading]=useState(false);
  const [items,setItems]=useState([]);
  const [err,setErr]=useState("");
  const run=async()=>{
    if(!q.trim()||loading) return;
    setLoading(true); setErr(""); setItems([]);
    try{
      const prompt="You are a sharp e-commerce product researcher for dropshippers. For the niche or interest below, suggest 6 WINNING dropshipping products that trend and sell well right now. Be specific and realistic — real products, not categories.\n\nNICHE/INTEREST: "+q.trim()+"\n\nReturn ONLY a JSON array (no markdown) of 6 objects, each: {\"name\": string (a specific product), \"why\": string (one sentence on why it wins — the demand, wow-factor, or problem it solves), \"audience\": string (who buys it), \"price\": string (realistic retail range like \"$25-$35\"), \"margin\": string (rough profit potential like \"3-5x\" or \"~$18/sale\"), \"hook\": string (a punchy, scroll-stopping ad hook to sell it — make it catchy)}.";
      const raw=await callClaude(prompt, 2000);
      let t=(raw||"").trim().replace(/^```json/i,"").replace(/^```/,"").replace(/```$/,"").trim();
      const a=t.indexOf("["), b=t.lastIndexOf("]"); if(a>=0&&b>a) t=t.slice(a,b+1);
      const arr=JSON.parse(t);
      setItems(Array.isArray(arr)?arr:[]);
      if(!Array.isArray(arr)||!arr.length) setErr("Couldn't get product ideas — please try again.");
    }catch(e){ setErr("Couldn't get product ideas — please try again."); }
    setLoading(false);
  };
  return (
    <div style={{border:"1px solid "+B.stone,background:B.white,borderRadius:4,padding:18,marginBottom:22}}>
      <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:6}}>
        <div style={{fontFamily:"Georgia,serif",fontSize:18,color:B.charcoal}}>Find winning products</div>
        <span style={{fontFamily:"sans-serif",fontSize:8.5,fontWeight:700,letterSpacing:"0.1em",textTransform:"uppercase",color:"#fff",background:"#B8955A",padding:"3px 7px",borderRadius:20}}>AI</span>
      </div>
      <p style={{fontFamily:"sans-serif",fontSize:12,color:B.mid,lineHeight:1.5,margin:"0 0 12px"}}>Tell Claude a niche or interest and get trending products that sell — with the audience, pricing, and a ready-to-use ad hook for each.</p>
      <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
        <input value={q} onChange={e=>setQ(e.target.value)} onKeyDown={e=>{if(e.key==="Enter")run();}} placeholder="e.g. home fitness, cozy home decor, dog owners" style={{flex:1,minWidth:200,padding:"11px 13px",border:"1px solid "+B.stone,fontFamily:"sans-serif",fontSize:13,outline:"none",boxSizing:"border-box"}} />
        <button onClick={run} disabled={loading||!q.trim()} style={{background:B.charcoal,color:"#fff",border:"none",padding:"11px 20px",fontFamily:"sans-serif",fontSize:12,fontWeight:700,letterSpacing:"0.04em",cursor:(loading||!q.trim())?"default":"pointer",opacity:(loading||!q.trim())?0.5:1,whiteSpace:"nowrap"}}>{loading?"Researching…":"✨ Find products"}</button>
      </div>
      {err&&<div style={{fontFamily:"sans-serif",fontSize:12,color:B.red,marginTop:8}}>{err}</div>}
      {items.length>0&&<div style={{marginTop:14,display:"grid",gap:10}}>
        {items.map((it,i)=>(
          <div key={i} style={{border:"1px solid "+B.stone,background:B.offwhite,borderRadius:4,padding:"13px 15px"}}>
            <div style={{display:"flex",justifyContent:"space-between",gap:10,flexWrap:"wrap",alignItems:"baseline"}}>
              <div style={{fontFamily:"sans-serif",fontSize:14,fontWeight:700,color:B.charcoal}}>{it.name}</div>
              <div style={{fontFamily:"sans-serif",fontSize:12,color:B.charcoal}}>{it.price}{it.margin?(" · "+it.margin):""}</div>
            </div>
            {it.why&&<div style={{fontFamily:"sans-serif",fontSize:12,color:B.mid,lineHeight:1.5,marginTop:5}}>{it.why}</div>}
            {it.audience&&<div style={{fontFamily:"sans-serif",fontSize:11,color:B.mid,marginTop:5}}><strong style={{color:B.charcoal}}>Who buys it:</strong> {it.audience}</div>}
            {it.hook&&<div style={{fontFamily:"sans-serif",fontSize:12,color:B.charcoal,lineHeight:1.5,marginTop:8,background:"#FBF7F0",border:"1px solid #E7DDCB",borderLeft:"3px solid #B8955A",padding:"8px 11px",borderRadius:2}}><strong style={{fontSize:8.5,letterSpacing:"0.1em",textTransform:"uppercase",color:"#B8955A",display:"block",marginBottom:3}}>Ad hook</strong>{it.hook}</div>}
            <a href={"https://www.aliexpress.com/wholesale?SearchText="+encodeURIComponent(it.name||"")} target="_blank" rel="noreferrer" style={{display:"inline-block",marginTop:10,fontFamily:"sans-serif",fontSize:11,fontWeight:700,letterSpacing:"0.04em",color:B.goldDark,textDecoration:"none",borderBottom:"1px solid "+B.gold,paddingBottom:2}}>Find a supplier →</a>
          </div>
        ))}
      </div>}
    </div>
  );
}
function BlogWriter({ site, onSave, user, onBalance }) {
  const posts = (site && site.data && site.data.blog) || [];
  const [mode, setMode] = useState("ai"); // ai | own
  const [topic, setTopic] = useState("");
  const [tone, setTone] = useState("Warm & personal");
  const [busy, setBusy] = useState(false);
  const [draft, setDraft] = useState(null); // {title,excerpt,body} — editable
  const [img, setImg] = useState("");
  const [imgBusy, setImgBusy] = useState(false);
  const [err, setErr] = useState("");
  const [saving, setSaving] = useState(false);
  const MIN = 250;
  const TONES = ["Warm & personal","Expert & authoritative","Conversational","Bold & opinionated","Friendly & practical"];

  function reset(){ setDraft(null); setImg(""); setErr(""); setTopic(""); }
  function startOwn(){ setDraft({ title:"", excerpt:"", body:"" }); setImg(""); setErr(""); setMode("own"); }
  function startAi(){ setDraft(null); setImg(""); setErr(""); setMode("ai"); }

  async function write() {
    if (topic.trim().length < MIN) { setErr("Add at least " + MIN + " characters so your post is specific and original."); return; }
    setBusy(true); setErr(""); setDraft(null); setImg("");
    const prompt = "You are writing an original blog post for a real small business's own website.\n\nThe owner's description of what they want the post to be about (use this as the specific, original basis — do not drift generic):\n\"\"\"" + topic.trim() + "\"\"\"\n\nTone: " + tone + "\n\nWrite a genuinely human, original blog post. It must NOT read like AI writing. Rules:\n- Vary sentence length a lot: mix short punchy sentences with longer flowing ones, and the odd fragment.\n- Write with a specific point of view and real personality. Take a stance; sound like a person, not a brand bot.\n- Use concrete, specific details and small examples instead of vague generalities.\n- Use contractions and a natural spoken rhythm. Rhetorical questions are fine.\n- Do NOT use any of these AI-tell phrases: 'in today's fast-paced world', 'whether you're', 'in conclusion', 'let's dive in', 'it's important to note', 'when it comes to', 'game-changer', 'elevate', 'unlock', 'seamless', 'delve', 'moreover', 'furthermore', 'look no further', 'navigate the world of', 'that being said'.\n- No generic opening or summary paragraph. Open on something specific. End on a real thought, not a neat wrap-up.\n- Avoid perfectly balanced lists of three and overly symmetrical structure.\n- 500-800 words.\n\nReturn ONLY valid JSON (no markdown, no code fences) exactly like:\n{\"title\":\"a specific, non-clickbait title\",\"excerpt\":\"one-sentence teaser under 160 characters\",\"body\":\"full post as plain text, paragraphs separated by \\\\n\\\\n; put any short subheading on its own line\"}";
    try {
      const rawT = await callClaude(prompt, 2200, false, null);
      let txt = (rawT || "").trim().replace(/^```json/i, "").replace(/^```/, "").replace(/```$/, "").trim();
      const a = txt.indexOf("{"); const b = txt.lastIndexOf("}");
      if (a >= 0 && b > a) txt = txt.slice(a, b + 1);
      const obj = JSON.parse(txt);
      if (!obj.title || !obj.body) throw new Error("bad");
      setDraft({ title: obj.title, excerpt: obj.excerpt || "", body: obj.body });
      setBusy(false);
      genImage(obj.title); // auto-make a header image to match
    } catch (e) { setErr("Couldn't write the post — please try again."); setBusy(false); }
  }

  async function genImage(titleStr) {
    if (!user || !user.id) { setErr("Please finish setting up your site before adding images."); return; }
    setImgBusy(true); setErr("");
    try {
      const styleDNA = (site && site.data && site.data.styleDNA) || "";
      const t = titleStr || (draft && draft.title) || topic || "blog post";
      const prompt = "A refined editorial header photograph for a blog post titled \"" + t + "\". " + (styleDNA ? ("Match this art direction so it fits the brand: " + styleDNA + ". ") : "") + "Photographic, tasteful, premium, magazine-quality. Absolutely no text, no words, no letters, no captions, no logos anywhere in the image.";
      const r = await generateGeminiImage(prompt, null, "16:9", "standard");
      if (r && r.image) {
        if (typeof r.balance === "number" && onBalance) onBalance(r.balance);
        const url = await uploadSiteImage(r.image, user.id + "/blog-" + Date.now() + "-" + Math.random().toString(36).slice(2, 5) + ".png");
        if (url) setImg(url); else setErr("Couldn't save the image — try again or upload your own.");
      } else setErr("Couldn't make the image — try again or upload your own.");
    } catch (e) { setErr("Couldn't make the image — try again or upload your own."); }
    setImgBusy(false);
  }

  function onUpload(e) {
    const file = e.target.files && e.target.files[0];
    e.target.value = "";
    if (!file || !user || !user.id) return;
    setImgBusy(true); setErr("");
    const reader = new FileReader();
    reader.onload = async () => {
      try { const url = await uploadSiteImage(String(reader.result), user.id + "/blog-" + Date.now() + "-" + Math.random().toString(36).slice(2, 5) + ".png"); if (url) setImg(url); else setErr("Couldn't upload that image."); }
      catch (e2) { setErr("Couldn't upload that image."); }
      setImgBusy(false);
    };
    reader.onerror = () => { setErr("Couldn't read that file."); setImgBusy(false); };
    reader.readAsDataURL(file);
  }

  async function publish() {
    if (!draft || !(draft.title || "").trim() || !(draft.body || "").trim()) { setErr("Add a title and some body text before publishing."); return; }
    setSaving(true); setErr("");
    const d = JSON.parse(JSON.stringify((site && site.data) || {}));
    d.blog = Array.isArray(d.blog) ? d.blog : [];
    const ex = new Set((d.blog || []).map(x => x && x.slug).filter(Boolean));
    const base = cgSlugify(draft.title); let sl = base, n = 2; while (ex.has(sl)) { sl = base + "-" + n; n++; }
    d.blog.unshift({ id: "p" + Date.now(), slug: sl, title: draft.title.trim(), excerpt: (draft.excerpt || "").trim(), body: draft.body.trim(), image: img || undefined, date: new Date().toISOString(), tone: mode === "ai" ? tone : undefined });
    d.sections = Array.isArray(d.sections) ? d.sections : [];
    if (!d.sections.some(s => s && s.type === "blog")) {
      const ci = d.sections.findIndex(s => s && s.type === "contact");
      const blogSec = { type: "blog", eyebrow: "Journal", heading: "From the blog" };
      if (ci >= 0) d.sections.splice(ci, 0, blogSec); else d.sections.push(blogSec);
    }
    const ok = await onSave(d);
    setSaving(false);
    if (ok) { reset(); setMode("ai"); } else setErr("Couldn't publish — please try again.");
  }

  async function del(id) {
    const d = JSON.parse(JSON.stringify((site && site.data) || {}));
    d.blog = (d.blog || []).filter(p => p.id !== id);
    await onSave(d);
  }

  const left = MIN - topic.trim().length;
  const fld = { width:"100%", boxSizing:"border-box", padding:"10px 12px", border:"1px solid "+B.stone, fontFamily:"sans-serif", fontSize:13, color:B.charcoal, background:"#fff", marginBottom:10 };
  const lbl = { fontFamily:"sans-serif", fontSize:10, fontWeight:700, letterSpacing:"0.08em", textTransform:"uppercase", color:"#B8955A", marginBottom:6 };
  const btnGhost = { background:"none", color:B.charcoal, border:"1px solid "+B.stone, padding:"9px 14px", fontFamily:"sans-serif", fontSize:10, letterSpacing:"0.06em", fontWeight:700, textTransform:"uppercase", cursor:"pointer" };

  return (
    <div>
      <div style={{fontFamily:"Georgia,serif",fontSize:22,color:B.charcoal,marginBottom:4}}>Blog</div>
      <p style={{fontFamily:"sans-serif",fontSize:12.5,color:B.mid,lineHeight:1.6,margin:"0 0 16px",maxWidth:560}}>Write a post with AI from your own brief, or write your own from scratch. Every post gets a matching header image you can regenerate or replace — then it publishes straight to your site.</p>

      <div style={{display:"flex",gap:6,marginBottom:18}}>
        <button onClick={startAi} style={{...btnGhost,background:mode==="ai"?B.charcoal:"none",color:mode==="ai"?"#fff":B.charcoal,borderColor:mode==="ai"?B.charcoal:B.stone}}>Write with AI</button>
        <button onClick={startOwn} style={{...btnGhost,background:mode==="own"?B.charcoal:"none",color:mode==="own"?"#fff":B.charcoal,borderColor:mode==="own"?B.charcoal:B.stone}}>Write my own</button>
      </div>

      {mode==="ai" && !draft && (
        <div>
          <div style={lbl}>What should it be about?</div>
          <textarea value={topic} onChange={e=>setTopic(e.target.value)} rows={5} placeholder="e.g. Why we switched our whole cafe to oat milk by default, what regulars said, and the two drinks it quietly made better. Mention our house chai and the mess we made testing it…" style={{...fld,lineHeight:1.5,resize:"vertical",marginBottom:6}} />
          <div style={{fontFamily:"sans-serif",fontSize:11,color:left>0?B.mid:B.green,marginBottom:14}}>{left>0?left+" more characters needed":"✓ Ready — nicely specific"}</div>
          <div style={{display:"flex",gap:10,alignItems:"center",flexWrap:"wrap"}}>
            <label style={{fontFamily:"sans-serif",fontSize:11,color:B.charcoal,display:"flex",alignItems:"center",gap:8}}>Tone
              <select value={tone} onChange={e=>setTone(e.target.value)} style={{padding:"8px 10px",border:"1px solid "+B.stone,fontFamily:"sans-serif",fontSize:12,background:"#fff",color:B.charcoal}}>
                {TONES.map(t=><option key={t} value={t}>{t}</option>)}
              </select>
            </label>
            <button disabled={busy||topic.trim().length<MIN} onClick={write} style={{background:(busy||topic.trim().length<MIN)?B.stone:B.charcoal,color:(busy||topic.trim().length<MIN)?B.mid:"#fff",border:"none",padding:"11px 20px",fontFamily:"sans-serif",fontSize:10,letterSpacing:"0.1em",fontWeight:700,textTransform:"uppercase",cursor:(busy||topic.trim().length<MIN)?"default":"pointer"}}>{busy?"Writing…":"✨ Write my post"}</button>
          </div>
        </div>
      )}

      {draft && (
        <div style={{border:"1px solid "+B.stone,background:B.offwhite,padding:"18px 20px",marginBottom:20}}>
          <div style={{fontFamily:"sans-serif",fontSize:11,color:B.mid,marginBottom:12}}>{mode==="ai"?"Edit anything below, then publish.":"Write your post below, then publish."}</div>

          <div style={lbl}>Header image</div>
          {img ? (
            <div style={{marginBottom:14}}>
              <img src={img} alt="" style={{width:"100%",maxHeight:220,objectFit:"cover",display:"block",border:"1px solid "+B.stone}} />
              <div style={{display:"flex",gap:8,marginTop:8,flexWrap:"wrap"}}>
                <button onClick={()=>genImage()} disabled={imgBusy} style={btnGhost}>{imgBusy?"Working…":"Regenerate"}</button>
                <label style={{...btnGhost,display:"inline-block"}}>Upload<input type="file" accept="image/*" onChange={onUpload} style={{display:"none"}} /></label>
                <button onClick={()=>setImg("")} disabled={imgBusy} style={{...btnGhost,color:B.red,borderColor:B.stone}}>Remove</button>
              </div>
            </div>
          ) : (
            <div style={{border:"1px dashed "+B.stone,padding:"16px",textAlign:"center",marginBottom:14,background:"#fff"}}>
              {imgBusy ? <div style={{fontFamily:"sans-serif",fontSize:12,color:B.mid}}>Creating a matching image…</div> : (
                <div style={{display:"flex",gap:8,justifyContent:"center",flexWrap:"wrap"}}>
                  <button onClick={()=>genImage()} style={{background:B.charcoal,color:"#fff",border:"none",padding:"9px 16px",fontFamily:"sans-serif",fontSize:10,letterSpacing:"0.06em",fontWeight:700,textTransform:"uppercase",cursor:"pointer"}}>✨ Generate with AI</button>
                  <label style={{...btnGhost,display:"inline-block"}}>Upload your own<input type="file" accept="image/*" onChange={onUpload} style={{display:"none"}} /></label>
                </div>
              )}
            </div>
          )}

          <div style={lbl}>Title</div>
          <input value={draft.title} onChange={e=>setDraft(d=>({...d,title:e.target.value}))} placeholder="Post title" style={{...fld,fontFamily:"Georgia,serif",fontSize:17}} />
          <div style={lbl}>Teaser <span style={{textTransform:"none",fontWeight:400,color:B.mid}}>(shown in the blog list)</span></div>
          <input value={draft.excerpt} onChange={e=>setDraft(d=>({...d,excerpt:e.target.value}))} placeholder="One-sentence teaser" style={fld} />
          <div style={lbl}>Body</div>
          <textarea value={draft.body} onChange={e=>setDraft(d=>({...d,body:e.target.value}))} rows={12} placeholder="Write your post. Leave a blank line between paragraphs." style={{...fld,fontFamily:"Georgia,serif",fontSize:14,lineHeight:1.7,resize:"vertical"}} />

          <div style={{display:"flex",gap:10,marginTop:6,flexWrap:"wrap"}}>
            <button disabled={saving} onClick={publish} style={{background:B.green,color:"#fff",border:"none",padding:"10px 18px",fontFamily:"sans-serif",fontSize:10,letterSpacing:"0.08em",fontWeight:700,textTransform:"uppercase",cursor:saving?"default":"pointer"}}>{saving?"Publishing…":"Publish to my site"}</button>
            {mode==="ai"&&<button disabled={saving||busy} onClick={write} style={btnGhost}>Rewrite</button>}
            <button disabled={saving} onClick={()=>{ setDraft(null); setImg(""); if(mode==="own") setMode("ai"); }} style={{background:"none",color:B.mid,border:"none",padding:"10px 8px",fontFamily:"sans-serif",fontSize:11,cursor:"pointer"}}>Discard</button>
          </div>
        </div>
      )}

      {err&&<div style={{fontFamily:"sans-serif",fontSize:12,color:B.red,marginBottom:12}}>{err}</div>}

      {posts.length>0&&(
        <div>
          <div style={{fontFamily:"sans-serif",fontSize:10,fontWeight:700,letterSpacing:"0.08em",textTransform:"uppercase",color:B.mid,margin:"6px 0 10px"}}>Published posts ({posts.length})</div>
          {posts.map(p=>(
            <div key={p.id} style={{display:"flex",justifyContent:"space-between",alignItems:"center",gap:12,borderBottom:"1px solid "+B.stone,padding:"10px 0"}}>
              <div style={{display:"flex",alignItems:"center",gap:12,minWidth:0}}>
                {p.image&&<img src={p.image} alt="" style={{width:52,height:40,objectFit:"cover",border:"1px solid "+B.stone,flexShrink:0}} />}
                <div style={{minWidth:0}}>
                  <div style={{fontFamily:"sans-serif",fontSize:13,fontWeight:700,color:B.charcoal,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{p.title}</div>
                  <div style={{fontFamily:"sans-serif",fontSize:11,color:B.mid}}>{p.date?new Date(p.date).toLocaleDateString():""}</div>
                </div>
              </div>
              <button onClick={()=>del(p.id)} style={{background:"none",border:"none",color:B.red,fontFamily:"sans-serif",fontSize:11,cursor:"pointer",flexShrink:0}}>Delete</button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

function CJConnect({ user }) {
  const [state, setState] = useState("loading"); // loading | connected | disconnected
  const [apiKey, setApiKey] = useState("");
  const [busy, setBusy] = useState(false);
  const [err, setErr] = useState("");

  useEffect(() => {
    let alive = true;
    (async () => {
      try {
        const t = await freshToken();
        const r = await fetch("/api/cj-status", { headers: { Authorization: "Bearer " + t } });
        const j = await r.json();
        if (alive) setState(j && j.connected ? "connected" : "disconnected");
      } catch (e) { if (alive) setState("disconnected"); }
    })();
    return () => { alive = false; };
  }, []);

  async function connect() {
    setErr("");
    if (!apiKey.trim()) { setErr("Paste your CJ API key first."); return; }
    setBusy(true);
    try {
      const t = await freshToken();
      const r = await fetch("/api/cj-connect", {
        method: "POST",
        headers: { "Content-Type": "application/json", Authorization: "Bearer " + t },
        body: JSON.stringify({ apiKey: apiKey.trim() }),
      });
      const j = await r.json();
      if (r.ok && j.connected) { setState("connected"); setApiKey(""); }
      else setErr(j.error || "Could not connect. Check your API key.");
    } catch (e) { setErr("Something went wrong. Try again."); }
    setBusy(false);
  }

  if (state === "loading") {
    return <div style={{ fontFamily: "sans-serif", fontSize: 12, color: B.mid }}>Checking CJ connection…</div>;
  }
  if (state === "connected") {
    return (
      <div style={{ display: "flex", alignItems: "center", gap: 8, fontFamily: "sans-serif", fontSize: 13, color: B.green, fontWeight: 700 }}>
        <span style={{ fontSize: 15 }}>✓</span> Your CJ account is connected.
      </div>
    );
  }
  return (
    <div>
      <input value={apiKey} onChange={(e) => setApiKey(e.target.value)} placeholder="Paste your CJ API key" style={{ width: "100%", boxSizing: "border-box", padding: "11px 12px", border: "1px solid " + B.stone, borderRadius: 2, fontFamily: "sans-serif", fontSize: 13, marginBottom: 10, color: B.charcoal }} />
      {err && <div style={{ fontFamily: "sans-serif", fontSize: 12, color: B.red, marginBottom: 10 }}>{err}</div>}
      <button onClick={connect} disabled={busy} style={{ padding: "11px 20px", background: busy ? B.stone : B.charcoal, color: busy ? B.mid : "#fff", border: "none", borderRadius: 2, fontFamily: "sans-serif", fontSize: 13, fontWeight: 700, cursor: busy ? "default" : "pointer" }}>
        {busy ? "Connecting…" : "Connect CJ account"}
      </button>
    </div>
  );
}

function CJProductBrowser({ user, onImport }) {
  const [open, setOpen] = useState(false);
  const [q, setQ] = useState("");
  const [results, setResults] = useState([]);
  const [loading, setLoading] = useState(false);
  const [err, setErr] = useState("");
  const [connected, setConnected] = useState(null);
  const [openPid, setOpenPid] = useState("");
  const [detail, setDetail] = useState(null);
  const [detailLoading, setDetailLoading] = useState(false);

  useEffect(() => {
    if (!open || connected !== null) return;
    (async () => {
      try {
        const t = await freshToken();
        const r = await fetch("/api/cj-status", { headers: { Authorization: "Bearer " + t } });
        const j = await r.json();
        setConnected(!!(j && j.connected));
      } catch (e) { setConnected(false); }
    })();
  }, [open]);

  async function search(page) {
    if (!q.trim()) { setErr("Type what you want to sell, e.g. 'phone stand'."); return; }
    setLoading(true); setErr(""); setOpenPid(""); setDetail(null);
    try {
      const t = await freshToken();
      const r = await fetch("/api/cj-search?keyword=" + encodeURIComponent(q.trim()) + "&page=" + (page || 1), { headers: { Authorization: "Bearer " + t } });
      const j = await r.json();
      if (r.ok && Array.isArray(j.products)) setResults(j.products);
      else { setErr(j.error || "Search failed."); setResults([]); }
    } catch (e) { setErr("Something went wrong. Try again."); }
    setLoading(false);
  }

  async function loadDetail(pid) {
    if (openPid === pid) { setOpenPid(""); setDetail(null); return; }
    setOpenPid(pid); setDetail(null); setDetailLoading(true); setErr("");
    try {
      const t = await freshToken();
      const r = await fetch("/api/cj-product?pid=" + encodeURIComponent(pid), { headers: { Authorization: "Bearer " + t } });
      const j = await r.json();
      if (r.ok) setDetail(j); else setErr(j.error || "Couldn't load that product.");
    } catch (e) { setErr("Couldn't load that product."); }
    setDetailLoading(false);
  }

  function addVariant(prod, v) {
    const cost = v.cost != null ? Number(v.cost) : null;
    const sug = cost != null ? (Math.round(cost * 2.5 * 100) / 100).toFixed(2) : "";
    const name = prod.name + (v.key ? " – " + v.key : "");
    onImport({ name, price: sug, note: "", image: { url: v.image || prod.image }, buyUrl: "", cj: { pid: prod.pid, vid: v.vid, sku: v.sku || "", cost: cost } });
  }

  if (!open) {
    return (
      <button onClick={() => setOpen(true)} style={{ background: "none", border: "1px solid " + B.charcoal, color: B.charcoal, padding: "10px 16px", fontFamily: "sans-serif", fontSize: 11, letterSpacing: "0.06em", fontWeight: 700, cursor: "pointer", marginBottom: 16 }}>
        🔍 Source products from CJ
      </button>
    );
  }

  return (
    <div style={{ border: "1px solid " + B.stone, background: B.offwhite, padding: 16, marginBottom: 16 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
        <div style={{ fontFamily: "Georgia,serif", fontSize: 16, color: B.charcoal }}>Source products from CJ</div>
        <button onClick={() => setOpen(false)} style={{ background: "none", border: "none", color: B.mid, fontFamily: "sans-serif", fontSize: 12, cursor: "pointer" }}>Close</button>
      </div>
      {connected === false && (
        <div style={{ fontFamily: "sans-serif", fontSize: 12.5, color: B.mid, lineHeight: 1.6 }}>
          Connect your CJ account first (in the Auto-dropshipping box above) to search and import products.
        </div>
      )}
      {connected !== false && (
        <div>
          <div style={{ display: "flex", gap: 8, marginBottom: 12 }}>
            <input value={q} onChange={e => setQ(e.target.value)} onKeyDown={e => { if (e.key === "Enter") search(1); }} placeholder="Search CJ, e.g. phone stand, hoodie…" style={{ flex: 1, padding: "10px 12px", border: "1px solid " + B.stone, outline: "none", fontSize: 13, fontFamily: "sans-serif", background: "#fff", color: B.charcoal }} />
            <button onClick={() => search(1)} disabled={loading} style={{ background: B.charcoal, color: "#fff", border: "none", padding: "10px 18px", fontFamily: "sans-serif", fontSize: 12, fontWeight: 700, cursor: loading ? "default" : "pointer" }}>{loading ? "Searching…" : "Search"}</button>
          </div>
          {err && <div style={{ fontFamily: "sans-serif", fontSize: 12, color: B.red, marginBottom: 10 }}>{err}</div>}
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(150px,1fr))", gap: 10 }}>
            {results.map(p => (
              <div key={p.pid} style={{ border: "1px solid " + (openPid === p.pid ? B.charcoal : B.stone), background: "#fff", padding: 10 }}>
                {p.image && <div style={{ width: "100%", aspectRatio: "1 / 1", backgroundImage: "url(" + p.image + ")", backgroundSize: "cover", backgroundPosition: "center", marginBottom: 8 }} />}
                <div style={{ fontFamily: "sans-serif", fontSize: 12, fontWeight: 700, color: B.charcoal, lineHeight: 1.3, marginBottom: 4 }}>{p.name}</div>
                <div style={{ fontFamily: "sans-serif", fontSize: 11, color: B.green, fontWeight: 700, marginBottom: 8 }}>{p.cost != null ? "Cost $" + p.cost : ""}</div>
                <button onClick={() => loadDetail(p.pid)} style={{ width: "100%", background: openPid === p.pid ? B.charcoal : "none", color: openPid === p.pid ? "#fff" : B.charcoal, border: "1px solid " + B.charcoal, padding: "7px", fontFamily: "sans-serif", fontSize: 10, fontWeight: 700, letterSpacing: "0.06em", cursor: "pointer", textTransform: "uppercase" }}>{openPid === p.pid ? "Hide options" : "Choose & add"}</button>
                {openPid === p.pid && (
                  <div style={{ marginTop: 8 }}>
                    {detailLoading && <div style={{ fontFamily: "sans-serif", fontSize: 11, color: B.mid }}>Loading options…</div>}
                    {detail && detail.variants && detail.variants.map(v => (
                      <div key={v.vid} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", gap: 6, borderTop: "1px solid " + B.stone, padding: "6px 0" }}>
                        <div style={{ fontFamily: "sans-serif", fontSize: 10.5, color: B.charcoal, lineHeight: 1.3 }}>{v.key || v.name}{v.cost != null ? " · $" + v.cost : ""}</div>
                        <button onClick={() => addVariant(p, v)} style={{ background: B.gold, color: "#fff", border: "none", padding: "5px 10px", fontFamily: "sans-serif", fontSize: 9, fontWeight: 700, letterSpacing: "0.06em", cursor: "pointer", textTransform: "uppercase", flexShrink: 0 }}>Add</button>
                      </div>
                    ))}
                    {detail && detail.variants && detail.variants.length === 0 && <div style={{ fontFamily: "sans-serif", fontSize: 11, color: B.mid }}>No variants available.</div>}
                  </div>
                )}
              </div>
            ))}
          </div>
          <div style={{ fontFamily: "sans-serif", fontSize: 10.5, color: B.mid, lineHeight: 1.6, marginTop: 12 }}>
            Prices import at a suggested 2.5&times; the CJ cost — edit any price after adding. Added items are linked to CJ so they can be fulfilled automatically once you save.
          </div>
        </div>
      )}
    </div>
  );
}

function ProductPhotoSet({ onBalance }) {
  const [ref, setRef] = useState(null);
  const [desc, setDesc] = useState("");
  const [busy, setBusy] = useState(false);
  const [prog, setProg] = useState("");
  const [shots, setShots] = useState([]);
  const [err, setErr] = useState("");

  const ANGLES = [
    ["Front", "a clean straight-on FRONT view of the product"],
    ["Back", "a straight-on BACK view of the same product"],
    ["Side", "a 3/4 SIDE-angle view of the same product"],
    ["Close-up", "a tight CLOSE-UP detail shot showing the material and texture of the same product"],
  ];

  function pickFile(f) {
    if (!f) return;
    const rdr = new FileReader();
    rdr.onload = () => { setRef(rdr.result); setShots([]); setErr(""); };
    rdr.readAsDataURL(f);
  }

  async function generate() {
    if (!ref) { setErr("Upload a reference photo first."); return; }
    setBusy(true); setErr(""); setShots([]);
    const out = [];
    for (let i = 0; i < ANGLES.length; i++) {
      setProg("Creating " + ANGLES[i][0] + " (" + (i + 1) + "/4)…");
      const p = "Using the uploaded product image as the reference, generate " + ANGLES[i][1] + ". Keep the exact same product, colours and design. Professional e-commerce product photography, clean seamless studio background, soft even lighting, sharp detail." + (desc.trim() ? " The product is: " + desc.trim() + "." : "");
      try {
        const r = await generateGeminiImage(p, ref, "1:1", "standard");
        if (r && r.image) { out.push({ label: ANGLES[i][0], url: r.image }); setShots([...out]); if (typeof r.balance === "number" && onBalance) onBalance(r.balance); }
      } catch (e) { /* continue */ }
    }
    if (!out.length) setErr("Couldn't generate photos. Please try again.");
    setProg(""); setBusy(false);
  }

  return (
    <div style={{ marginTop: 24, paddingTop: 22, borderTop: "1px solid " + B.stone }}>
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", gap: 8, flexWrap: "wrap", marginBottom: 6 }}>
        <div style={{ fontFamily: "Georgia,serif", fontSize: 19, color: B.charcoal }}>Product photo set</div>
        <CreditTag n={4 * CREDIT_COSTS.image} />
      </div>
      <p style={{ fontFamily: "sans-serif", fontSize: 12, color: B.mid, lineHeight: 1.6, margin: "0 0 12px" }}>Upload one reference photo and Chelgy generates four matching product shots — front, back, side, and a close-up.</p>
      {!ref
        ? <label style={{ display: "inline-flex", alignItems: "center", justifyContent: "center", padding: "11px 16px", border: "1px dashed " + B.stone, background: B.white, cursor: "pointer", fontFamily: "sans-serif", fontSize: 11, color: B.goldDark }}>+ Upload a reference photo<input type="file" accept="image/*" onChange={e => pickFile((e.target.files || [])[0])} style={{ display: "none" }} /></label>
        : <div>
            <div style={{ display: "flex", gap: 10, alignItems: "flex-start", border: "1px solid " + B.stone, background: "#fff", padding: 8, marginBottom: 10 }}>
              <img src={ref} alt="" style={{ width: 70, height: 70, objectFit: "cover", flexShrink: 0 }} />
              <div style={{ flex: 1, minWidth: 0 }}>
                <input value={desc} onChange={e => setDesc(e.target.value)} placeholder="What is it? e.g. ceramic coffee mug" style={{ width: "100%", padding: "7px 9px", border: "1px solid " + B.stone, outline: "none", fontSize: 12, fontFamily: "sans-serif", boxSizing: "border-box" }} />
              </div>
              <button onClick={() => { setRef(null); setShots([]); }} style={{ background: "none", border: "none", color: B.mid, cursor: "pointer", fontSize: 11, fontFamily: "sans-serif", textDecoration: "underline" }}>Remove</button>
            </div>
            <button disabled={busy} onClick={generate} style={{ background: B.charcoal, color: "#fff", border: "none", padding: "10px 18px", fontFamily: "sans-serif", fontSize: 10, letterSpacing: "0.1em", fontWeight: 700, cursor: busy ? "default" : "pointer", textTransform: "uppercase", opacity: busy ? 0.6 : 1 }}>{busy ? (prog || "Working…") : "✨ Generate 4 product photos"}</button>
          </div>}
      {err && <div style={{ fontFamily: "sans-serif", fontSize: 11, color: B.red, marginTop: 8 }}>{err}</div>}
      {shots.length > 0 && (
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(130px,1fr))", gap: 10, marginTop: 14 }}>
          {shots.map((sh, i) => (
            <div key={i} style={{ border: "1px solid " + B.stone, background: "#fff", padding: 8 }}>
              <div style={{ width: "100%", aspectRatio: "1 / 1", backgroundImage: "url(" + sh.url + ")", backgroundSize: "cover", backgroundPosition: "center", marginBottom: 6 }} />
              <div style={{ fontFamily: "sans-serif", fontSize: 10, fontWeight: 700, letterSpacing: "0.06em", textTransform: "uppercase", color: B.mid, marginBottom: 6 }}>{sh.label}</div>
              <a href={sh.url} download={"product-" + sh.label.toLowerCase().replace(/[^a-z]/g, "") + ".png"} style={{ display: "block", textAlign: "center", background: "none", border: "1px solid " + B.charcoal, color: B.charcoal, padding: "6px", fontFamily: "sans-serif", fontSize: 9, fontWeight: 700, letterSpacing: "0.06em", textTransform: "uppercase", textDecoration: "none", cursor: "pointer" }}>Download</a>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

function FocalPicker({ url, value, onChange, height }) {
  const ref = useRef(null);
  const parse = (v) => { const m = /(\d+(?:\.\d+)?)%\s+(\d+(?:\.\d+)?)%/.exec(v || ""); return m ? { x: +m[1], y: +m[2] } : { x: 50, y: 50 }; };
  const pt = parse(value);
  const setFrom = (clientX, clientY) => {
    const el = ref.current; if (!el) return; const r = el.getBoundingClientRect();
    let x = ((clientX - r.left) / r.width) * 100, y = ((clientY - r.top) / r.height) * 100;
    x = Math.max(0, Math.min(100, x)); y = Math.max(0, Math.min(100, y));
    onChange(Math.round(x) + "% " + Math.round(y) + "%");
  };
  const onDown = (e) => {
    const move = (ev) => { const c = ev.touches ? ev.touches[0] : ev; if (ev.cancelable) ev.preventDefault(); setFrom(c.clientX, c.clientY); };
    move(e.nativeEvent);
    const up = () => { window.removeEventListener("mousemove", move); window.removeEventListener("mouseup", up); window.removeEventListener("touchmove", move); window.removeEventListener("touchend", up); };
    window.addEventListener("mousemove", move); window.addEventListener("mouseup", up);
    window.addEventListener("touchmove", move, { passive: false }); window.addEventListener("touchend", up);
  };
  return (
    <div style={{ marginBottom: 12 }}>
      <div ref={ref} onMouseDown={onDown} onTouchStart={onDown} style={{ position: "relative", width: "100%", height: height || 180, cursor: "crosshair", userSelect: "none", overflow: "hidden", border: "1px solid #E5E0D8", background: "#f4f2ee" }}>
        <img src={url} alt="" draggable={false} style={{ width: "100%", height: "100%", objectFit: "cover", objectPosition: pt.x + "% " + pt.y + "%", display: "block", pointerEvents: "none" }} onError={e => { e.target.style.display = "none"; }} />
        <div style={{ position: "absolute", left: pt.x + "%", top: pt.y + "%", width: 24, height: 24, marginLeft: -12, marginTop: -12, borderRadius: "50%", border: "2px solid #fff", boxShadow: "0 0 0 2px rgba(0,0,0,0.45)", background: "rgba(255,255,255,0.2)", pointerEvents: "none" }} />
      </div>
      <div style={{ fontFamily: "sans-serif", fontSize: 10, color: "#8A8175", marginTop: 5 }}>Drag the dot to choose which part of this photo stays centered in thumbnails.</div>
    </div>
  );
}

function PhotoCatalog({ onBalance }) {
  const [prompt, setPrompt] = useState("");
  const [count, setCount] = useState(6);
  const [busy, setBusy] = useState(false);
  const [prog, setProg] = useState("");
  const [imgs, setImgs] = useState([]);
  const [err, setErr] = useState("");
  const [style, setStyle] = useState("editorial-porcelain");
  const [orient, setOrient] = useState("1:1");
  const [quality, setQuality] = useState("standard");
  const STYLE_OPTIONS = [["editorial-porcelain","Editorial porcelain"],["warm-minimal","Warm minimal"],["gallery","Gallery / stone"],["atelier","Atelier / emerald"],["noir","Dark & moody"],["bordeaux","Bordeaux"],["","Just my description"]];

  async function generate() {
    if (!prompt.trim()) { setErr("Describe the photos you want."); return; }
    const n = Math.max(1, Math.min(20, parseInt(count, 10) || 1));
    setBusy(true); setErr(""); setImgs([]);
    const out = [];
    let failures = 0;
    for (let i = 0; i < n; i++) {
      setProg("Creating image " + (i + 1) + " of " + n + "…");
      const lux = " Shot as high-end, editorial magazine-quality photography: premium tasteful styling, soft professional lighting, refined composition, elevated luxury brand aesthetic, crisp and clean, no text or logos.";
      const paletteDir = THEME_IMG_STYLE[style] ? (" Mood and palette: " + THEME_IMG_STYLE[style] + ".") : "";
      const p = prompt.trim() + lux + paletteDir + " Part of a cohesive set with a consistent style, lighting and colour palette across every image. This is image " + (i + 1) + " of " + n + " — a distinct composition within the same series.";
      let ok = false;
      for (let attempt = 0; attempt < 2 && !ok; attempt++) {
        try {
          const r = await generateGeminiImage(p, null, orient, quality);
          if (r && r.image) { out.push(r.image); setImgs([...out]); if (typeof r.balance === "number" && onBalance) onBalance(r.balance); ok = true; }
        } catch (e) { /* retry once */ }
      }
      if (!ok) failures++;
    }
    if (!out.length) setErr("Couldn't generate images. Please try again.");
    else if (failures) setErr(out.length + " of " + n + " images came through — tap Generate again to fill in the rest.");
    setProg(""); setBusy(false);
  }

  function downloadAll() {
    downloadAllImages(imgs, "catalog", "chelgy-photo-set");
  }

  const n = Math.max(1, Math.min(20, parseInt(count, 10) || 1));
  return (
    <div style={{ border: "1px solid " + B.stone, background: B.offwhite, padding: "16px 18px", marginBottom: 18 }}>
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", gap: 8, flexWrap: "wrap", marginBottom: 4 }}>
        <div style={{ fontFamily: "Georgia,serif", fontSize: 17, color: B.charcoal }}>Matching photo set</div>
        <CreditTag n={n * (quality === "4K" ? CREDIT_COSTS.image4K : quality === "2K" ? CREDIT_COSTS.imageHD : CREDIT_COSTS.image)} />
      </div>
      <p style={{ fontFamily: "sans-serif", fontSize: 11.5, color: B.mid, lineHeight: 1.6, margin: "0 0 12px" }}>Describe a look and generate up to 20 images that share one consistent style — perfect for a content batch or product line. Download them individually or all at once.</p>
      <textarea value={prompt} onChange={e => setPrompt(e.target.value)} placeholder="e.g. minimalist skincare bottles on warm beige backgrounds, soft daylight, matching shadows" rows={3} style={{ width: "100%", boxSizing: "border-box", padding: "10px 12px", border: "1px solid " + B.stone, fontFamily: "sans-serif", fontSize: 12.5, resize: "vertical", marginBottom: 10, color: B.charcoal }} />
      <div style={{ display: "flex", gap: 10, alignItems: "center", flexWrap: "wrap", marginBottom: 4 }}>
        <label style={{ fontFamily: "sans-serif", fontSize: 11, color: B.charcoal, display: "flex", alignItems: "center", gap: 8 }}>
          How many
          <select value={count} onChange={e => setCount(e.target.value)} style={{ padding: "8px 10px", border: "1px solid " + B.stone, fontFamily: "sans-serif", fontSize: 12, background: "#fff", color: B.charcoal }}>
            {[3, 5, 6, 8, 10, 12, 15, 20].map(v => <option key={v} value={v}>{v} images</option>)}
          </select>
        </label>
        <label style={{ fontFamily: "sans-serif", fontSize: 11, color: B.charcoal, display: "flex", alignItems: "center", gap: 8 }}>
          Aesthetic
          <select value={style} onChange={e => setStyle(e.target.value)} style={{ padding: "8px 10px", border: "1px solid " + B.stone, fontFamily: "sans-serif", fontSize: 12, background: "#fff", color: B.charcoal }}>
            {STYLE_OPTIONS.map(([v,l]) => <option key={v||"none"} value={v}>{l}</option>)}
          </select>
        </label>
        <label style={{ fontFamily: "sans-serif", fontSize: 11, color: B.charcoal, display: "flex", alignItems: "center", gap: 8 }}>
          Orientation
          <select value={orient} onChange={e => setOrient(e.target.value)} style={{ padding: "8px 10px", border: "1px solid " + B.stone, fontFamily: "sans-serif", fontSize: 12, background: "#fff", color: B.charcoal }}>
            {[["1:1","Square (1:1)"],["4:5","Portrait (4:5)"],["3:4","Portrait (3:4)"],["2:3","Portrait (2:3)"],["9:16","Tall / Story (9:16)"],["16:9","Landscape (16:9)"],["3:2","Landscape (3:2)"],["4:3","Standard (4:3)"]].map(([v,l]) => <option key={v} value={v}>{l}</option>)}
          </select>
        </label>
        <label style={{ fontFamily: "sans-serif", fontSize: 11, color: B.charcoal, display: "flex", alignItems: "center", gap: 8 }}>
          Quality
          <select value={quality} onChange={e => setQuality(e.target.value)} style={{ padding: "8px 10px", border: "1px solid " + B.stone, fontFamily: "sans-serif", fontSize: 12, background: "#fff", color: B.charcoal }}>
            {[["standard","Standard"],["2K","HD 2K"],["4K","Ultra 4K"]].map(([v,l]) => <option key={v} value={v}>{l}</option>)}
          </select>
        </label>
        <button disabled={busy} onClick={generate} style={{ background: B.charcoal, color: "#fff", border: "none", padding: "10px 18px", fontFamily: "sans-serif", fontSize: 10, letterSpacing: "0.1em", fontWeight: 700, cursor: busy ? "default" : "pointer", textTransform: "uppercase", opacity: busy ? 0.6 : 1 }}>{busy ? (prog || "Working…") : "✨ Generate catalog"}</button>
      </div>
      {err && <div style={{ fontFamily: "sans-serif", fontSize: 11, color: B.red, marginTop: 8 }}>{err}</div>}
      {imgs.length > 0 && (
        <div style={{ marginTop: 14 }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
            <div style={{ fontFamily: "sans-serif", fontSize: 11, color: B.mid }}>{imgs.length} image{imgs.length > 1 ? "s" : ""}{busy ? " so far…" : ""}</div>
            {!busy && <button onClick={downloadAll} style={{ background: B.gold, color: "#fff", border: "none", padding: "7px 14px", fontFamily: "sans-serif", fontSize: 10, fontWeight: 700, letterSpacing: "0.06em", textTransform: "uppercase", cursor: "pointer" }}>Download all</button>}
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(120px,1fr))", gap: 10 }}>
            {imgs.map((u, i) => (
              <div key={i} style={{ border: "1px solid " + B.stone, background: "#fff", padding: 6 }}>
                <div style={{ width: "100%", aspectRatio: "1 / 1", backgroundImage: "url(" + u + ")", backgroundSize: "cover", backgroundPosition: "center", marginBottom: 6 }} />
                <a href={u} download={"catalog-" + (i + 1) + ".png"} style={{ display: "block", textAlign: "center", border: "1px solid " + B.charcoal, color: B.charcoal, padding: "5px", fontFamily: "sans-serif", fontSize: 9, fontWeight: 700, letterSpacing: "0.06em", textTransform: "uppercase", textDecoration: "none", cursor: "pointer" }}>Download</a>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

function UGCCharacter({ onBalance, onUseInVideo }) {
  const [desc, setDesc] = useState("");
  const [product, setProduct] = useState("");
  const [uploads, setUploads] = useState([]);
  const [count, setCount] = useState(6);
  const [busy, setBusy] = useState(false);
  const [prog, setProg] = useState("");
  const [imgs, setImgs] = useState([]);
  const [err, setErr] = useState("");
  const POSES = [
    "a friendly selfie looking straight into the front camera with a warm natural smile",
    "talking to the camera mid-sentence, expressive and engaged, one hand gesturing",
    "holding the product up next to their face and pointing at it, excited expression",
    "a close-up reaction shot, delighted and pleasantly surprised expression",
    "a three-quarter angle, casually presenting the product toward the camera",
    "laughing candidly while glancing slightly off camera",
    "holding the product and reading the label with a curious, interested look",
    "a relaxed at-home shot, cozy and authentic, product resting in their hands",
    "a confident piece-to-camera pose giving a thumbs up",
    "an unboxing moment, looking down at the product with a happy expression",
    "a mirror-style full-outfit shot holding the product",
    "a calm, trustworthy expression looking directly at the camera, product visible",
  ];

  function onUpload(e){ const fs=e.target.files; if(!fs||!fs.length) return; const arr=Array.from(fs).slice(0,3); arr.forEach(f=>{ const r=new FileReader(); r.onload=()=>setUploads(p=>p.length>=3?p:[...p,r.result]); r.readAsDataURL(f); }); e.target.value=""; }

  async function generate(){
    if(!desc.trim() && !uploads.length){ setErr("Describe your creator, or upload a reference photo."); return; }
    const n = Math.max(1, Math.min(12, parseInt(count,10)||1));
    setBusy(true); setErr(""); setImgs([]);
    const who = desc.trim() || "the exact person shown in the uploaded reference photo(s)";
    const prod = product.trim() ? (" They are showcasing this product: "+product.trim()+".") : "";
    const REAL = " Photorealistic, authentic user-generated content (UGC): looks like a real everyday content creator filming themselves on a smartphone front camera — natural indoor lighting, real skin texture, slightly candid framing, relatable and genuine, NOT a glossy studio ad or stock photo. An adult creator, tasteful and fully clothed in a casual everyday outfit. Keep the SAME person — same face, hair and outfit — perfectly consistent across every image.";
    const out = [];
    let styleRef = null;
    for(let i=0;i<n;i++){
      setProg("Creating shot "+(i+1)+" of "+n+"…");
      const pose = POSES[i % POSES.length];
      const p = "A UGC content-creator photo of "+who+". Pose and shot: "+pose+"."+prod+REAL+" This is image "+(i+1)+" of "+n+" — a distinct shot of the exact same creator.";
      const refs = styleRef ? [styleRef] : (uploads.length ? uploads : null);
      try {
        const r = await generateGeminiImage(p, refs, "4:5", "standard");
        if(r && r.image){ out.push(r.image); setImgs([...out]); if(!styleRef) styleRef=r.image; if(typeof r.balance==="number"&&onBalance) onBalance(r.balance); }
      } catch(e) { /* continue */ }
    }
    if(!out.length) setErr("Couldn't generate. Please try again.");
    setProg(""); setBusy(false);
  }

  function downloadAll(){ downloadAllImages(imgs, "ugc-creator", "chelgy-ugc-creators"); }

  const n = Math.max(1, Math.min(12, parseInt(count,10)||1));
  const inpS = { width:"100%", boxSizing:"border-box", padding:"10px 12px", border:"1px solid "+B.stone, fontFamily:"sans-serif", fontSize:12.5, color:B.charcoal, background:"#fff" };
  return (
    <div style={{ border:"1px solid "+B.stone, background:B.offwhite, padding:"16px 18px", marginBottom:18 }}>
      <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", gap:8, flexWrap:"wrap", marginBottom:4 }}>
        <div style={{ fontFamily:"Georgia,serif", fontSize:17, color:B.charcoal }}>UGC character</div>
        <CreditTag n={n * CREDIT_COSTS.image} />
      </div>
      <p style={{ fontFamily:"sans-serif", fontSize:11.5, color:B.mid, lineHeight:1.6, margin:"0 0 12px" }}>Describe a content creator (or upload reference photos of one) and generate a set of realistic, consistent shots of the same person — a character sheet you can download and use to build UGC videos.</p>

      <div style={{ fontFamily:"sans-serif", fontSize:9, fontWeight:700, letterSpacing:"0.14em", color:B.mid, marginBottom:6, textTransform:"uppercase" }}>Describe your creator</div>
      <textarea value={desc} onChange={e=>setDesc(e.target.value)} placeholder="e.g. a friendly woman in her late 20s, natural curly hair, minimal makeup, cozy neutral sweater, filming at home" rows={3} style={{ ...inpS, resize:"vertical", marginBottom:12 }} />

      <div style={{ fontFamily:"sans-serif", fontSize:9, fontWeight:700, letterSpacing:"0.14em", color:B.mid, marginBottom:6, textTransform:"uppercase" }}>Product they're showing (optional)</div>
      <input value={product} onChange={e=>setProduct(e.target.value)} placeholder="e.g. a matte green skincare serum bottle" style={{ ...inpS, marginBottom:12 }} />

      <div style={{ fontFamily:"sans-serif", fontSize:9, fontWeight:700, letterSpacing:"0.14em", color:B.mid, marginBottom:6, textTransform:"uppercase" }}>Reference photos of the creator (optional · up to 3)</div>
      {uploads.length>0 && <div style={{ display:"flex", flexWrap:"wrap", gap:8, marginBottom:10 }}>
        {uploads.map((u,idx)=>(
          <div key={idx} style={{ position:"relative", width:64, height:64 }}>
            <img src={u} alt={"Reference "+(idx+1)} style={{ width:64, height:64, objectFit:"cover", border:"1px solid "+B.stone, display:"block" }} />
            <button onClick={()=>setUploads(prev=>prev.filter((_,i)=>i!==idx))} style={{ position:"absolute", top:-7, right:-7, width:20, height:20, borderRadius:"50%", background:B.charcoal, color:"#fff", border:"none", cursor:"pointer", fontSize:12, lineHeight:1, display:"flex", alignItems:"center", justifyContent:"center" }}>×</button>
          </div>
        ))}
      </div>}
      {uploads.length<3 && <label style={{ display:"block", border:"1px dashed "+B.stone, background:"#fff", padding:"14px", textAlign:"center", cursor:"pointer", fontFamily:"sans-serif", fontSize:12, color:B.goldDark, marginBottom:6 }}>{uploads.length?"Add another reference photo":"Tap to upload photo(s) of the creator to match their look"}<input type="file" accept="image/*" multiple onChange={onUpload} style={{ display:"none" }} /></label>}
      <p style={{ fontFamily:"sans-serif", fontSize:10.5, color:B.mid, lineHeight:1.5, margin:"0 0 14px", fontStyle:"italic" }}>Only upload photos of yourself or people who've given you permission to use their likeness.</p>

      <div style={{ display:"flex", gap:10, alignItems:"center", flexWrap:"wrap", marginBottom:4 }}>
        <label style={{ fontFamily:"sans-serif", fontSize:11, color:B.charcoal, display:"flex", alignItems:"center", gap:8 }}>
          How many shots
          <select value={count} onChange={e=>setCount(e.target.value)} style={{ padding:"8px 10px", border:"1px solid "+B.stone, fontFamily:"sans-serif", fontSize:12, background:"#fff", color:B.charcoal }}>
            {[3,4,6,8,10,12].map(v=><option key={v} value={v}>{v} shots</option>)}
          </select>
        </label>
        <button disabled={busy} onClick={generate} style={{ background:B.charcoal, color:"#fff", border:"none", padding:"10px 18px", fontFamily:"sans-serif", fontSize:10, letterSpacing:"0.1em", fontWeight:700, cursor:busy?"default":"pointer", textTransform:"uppercase", opacity:busy?0.6:1 }}>{busy?(prog||"Working…"):"✨ Generate creator"}</button>
      </div>
      {err && <div style={{ fontFamily:"sans-serif", fontSize:11, color:B.red, marginTop:8 }}>{err}</div>}
      {imgs.length>0 && (
        <div style={{ marginTop:14 }}>
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:10 }}>
            <div style={{ fontFamily:"sans-serif", fontSize:11, color:B.mid }}>{imgs.length} shot{imgs.length>1?"s":""}{busy?" so far…":""}</div>
            {!busy && <button onClick={downloadAll} style={{ background:B.gold, color:"#fff", border:"none", padding:"7px 14px", fontFamily:"sans-serif", fontSize:10, fontWeight:700, letterSpacing:"0.06em", textTransform:"uppercase", cursor:"pointer" }}>Download all</button>}
          </div>
          <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(120px,1fr))", gap:10 }}>
            {imgs.map((u,i)=>(
              <div key={i} style={{ border:"1px solid "+B.stone, background:"#fff", padding:6 }}>
                <div style={{ width:"100%", aspectRatio:"4 / 5", backgroundImage:"url("+u+")", backgroundSize:"cover", backgroundPosition:"center", marginBottom:6 }} />
                <a href={u} download={"ugc-creator-"+(i+1)+".png"} style={{ display:"block", textAlign:"center", border:"1px solid "+B.charcoal, color:B.charcoal, padding:"5px", fontFamily:"sans-serif", fontSize:9, fontWeight:700, letterSpacing:"0.06em", textTransform:"uppercase", textDecoration:"none", cursor:"pointer" }}>Download</a>
                {onUseInVideo && <button onClick={()=>onUseInVideo(u)} style={{ display:"block", width:"100%", boxSizing:"border-box", marginTop:4, background:B.gold, color:"#fff", border:"none", padding:"6px", fontFamily:"sans-serif", fontSize:9, fontWeight:700, letterSpacing:"0.06em", textTransform:"uppercase", cursor:"pointer" }}>Use in video →</button>}
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

// ─── UGC STUDIO: self-contained tool. Character maker + Seedance-2.0-only video ───
// ─── PRODUCT STUDIO (Phase 1: on-brand product stills via Nano Banana) ──────
// ─── ENHANCE PHOTO / PROFESSIONAL HEADSHOTS ──────
// ─── BUSINESS MANAGER (CRM · Invoices · Proposals · Contracts) ──────────────
function bmMdToHtml(md) {
  const esc = s => String(s || "").replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
  return String(md || "").split("\n").map(line => {
    let l = esc(line).replace(/\*\*(.+?)\*\*/g, "<strong>$1</strong>").replace(/\*(.+?)\*/g, "<em>$1</em>");
    if (/^#{1,6}\s/.test(line)) { const lvl = Math.min(line.match(/^#+/)[0].length + 1, 4); return "<h" + lvl + ">" + l.replace(/^#{1,6}\s/, "") + "</h" + lvl + ">"; }
    if (/^\s*[-*]\s/.test(line)) return "<li>" + l.replace(/^\s*[-*]\s/, "") + "</li>";
    if (!line.trim()) return "<br/>";
    return "<p>" + l + "</p>";
  }).join("");
}
function bmPrint(title, innerHtml) {
  const w = window.open("", "_blank");
  if (!w) { alert("Please allow pop-ups to download the PDF."); return; }
  w.document.write('<html><head><title>' + title + '</title><meta name="viewport" content="width=device-width,initial-scale=1"><style>body{font-family:Georgia,serif;color:#111;max-width:720px;margin:40px auto;padding:0 28px;line-height:1.65}h1{font-weight:400;font-size:26px;margin:0 0 4px}h2,h3,h4{font-weight:600}.muted{color:#666;font-family:Arial,sans-serif;font-size:13px}table{width:100%;border-collapse:collapse;margin:20px 0;font-family:Arial,sans-serif;font-size:14px}td,th{text-align:left;padding:9px 6px;border-bottom:1px solid #e5e5e5}.r{text-align:right}.tot{font-weight:700;font-size:16px}.sign{margin-top:48px;font-family:Arial,sans-serif}.line{border-top:1px solid #111;width:260px;margin-top:34px;padding-top:6px;font-size:13px;color:#555}</style></head><body>' + innerHtml + '</body></html>');
  w.document.close(); w.focus(); setTimeout(() => { try { w.print(); } catch (e) {} }, 350);
}

function BusinessManager({ user, bizCtx, locked, onUpgrade }) {
  const TABS = [["clients", "Clients"], ["invoices", "Invoices"], ["payments", "Payments"], ["proposals", "Proposals"], ["contracts", "Contracts"]];
  const [tab, setTab] = useState("clients");
  const [clients, setClients] = useState([]);
  const [invoices, setInvoices] = useState([]);
  const [proposals, setProposals] = useState([]);
  const [contracts, setContracts] = useState([]);
  const [err, setErr] = useState("");
  const [busy, setBusy] = useState(false);
  const [edit, setEdit] = useState(null); // { kind, row }
  const [drafting, setDrafting] = useState(false);
  const [payMsg, setPayMsg] = useState({});

  async function api(path, opts) {
    const tok = await freshToken();
    if (!tok) throw new Error("Please sign in again.");
    const res = await fetch(SUPABASE_URL + "/rest/v1/" + path, { ...(opts || {}), headers: { apikey: SUPABASE_KEY, Authorization: "Bearer " + tok, "Content-Type": "application/json", Prefer: "return=representation", ...((opts && opts.headers) || {}) } });
    const txt = await res.text();
    if (!res.ok) throw new Error(txt || ("error " + res.status));
    return txt ? JSON.parse(txt) : [];
  }
  async function loadAll() {
    try {
      const [c, i, p, k] = await Promise.all([
        api("bm_clients?order=created_at.desc"),
        api("bm_invoices?order=created_at.desc"),
        api("bm_proposals?order=created_at.desc"),
        api("bm_contracts?order=created_at.desc"),
      ]);
      setClients(c || []); setInvoices(i || []); setProposals(p || []); setContracts(k || []);
    } catch (e) { setErr("Couldn't load your data. Refresh and try again."); }
  }
  useEffect(() => { if (!locked && user) loadAll(); }, [locked, user]);

  const setters = { bm_clients: [clients, setClients], bm_invoices: [invoices, setInvoices], bm_proposals: [proposals, setProposals], bm_contracts: [contracts, setContracts] };
  async function save(table, id, body) {
    setBusy(true); setErr("");
    const [list, setter] = setters[table];
    try {
      let out;
      if (id) out = await api(table + "?id=eq." + id, { method: "PATCH", body: JSON.stringify(body) });
      else out = await api(table, { method: "POST", body: JSON.stringify({ ...body, user_id: user.id }) });
      const saved = (out && out[0]) || { id, ...body };
      setter(id ? list.map(x => x.id === id ? saved : x) : [saved, ...list]);
      setEdit(null); setBusy(false); return saved;
    } catch (e) { setErr("Couldn't save. Please try again."); setBusy(false); return null; }
  }
  async function remove(table, id) {
    if (!window.confirm("Delete this permanently?")) return;
    const [list, setter] = setters[table];
    try { await api(table + "?id=eq." + id, { method: "DELETE" }); setter(list.filter(x => x.id !== id)); }
    catch (e) { setErr("Couldn't delete. Please try again."); }
  }

  async function draftDoc(kind, title, clientName, extra) {
    setDrafting(true);
    const ctx = bizCtx ? ("Business context (the sender): " + bizCtx + "\n\n") : "";
    let p;
    if (kind === "proposal") p = ctx + "Write a professional, persuasive business proposal" + (clientName ? (" for the client " + clientName) : "") + (title ? (' titled "' + title + '"') : "") + ". " + (extra ? ("Details: " + extra + ". ") : "") + "Include a warm intro, the client's goal, the proposed solution and scope, deliverables, timeline, a pricing section (use placeholders like [amount] where unknown), and a friendly close with next steps. Clean markdown with clear headings, concise and premium in tone.";
    else p = ctx + "Draft a clear, professional service contract" + (clientName ? (" between the business and the client " + clientName) : "") + (title ? (' titled "' + title + '"') : "") + ". " + (extra ? ("Details: " + extra + ". ") : "") + "Include standard sections: parties, scope of work, payment terms, timeline, revisions, cancellation, ownership/IP, confidentiality, liability, and signature lines. Use placeholders like [amount], [date], [term] where unknown. Clean markdown. At the very top add this exact italic line: *This is a starting template, not legal advice — have a lawyer review before use.*";
    const out = await callClaude(p, 3000);
    setDrafting(false);
    return out || "";
  }

  // ── invoice math ──
  function invSubtotal(inv) { return (inv.items || []).reduce((s, it) => s + (Number(it.qty) || 0) * (Number(it.price) || 0), 0); }
  function invTotal(inv) { const st = invSubtotal(inv); return st + st * ((Number(inv.tax) || 0) / 100); }
  function money(n, cur) { const c = (cur || "USD").toUpperCase(); const sym = { USD: "$", EUR: "€", GBP: "£", CAD: "$", AUD: "$" }[c] || ""; return sym + (Number(n) || 0).toFixed(2) + (sym ? "" : " " + c); }

  async function payLink(inv) {
    setPayMsg(m => ({ ...m, [inv.id]: "Creating link…" }));
    try {
      const tok = await freshToken();
      const base = window.location.href.split("?")[0];
      const r = await fetch("/api/invoice-checkout", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ access_token: tok, invoice_id: inv.id, amount_cents: Math.round(invTotal(inv) * 100), currency: (inv.currency || "usd").toLowerCase(), description: "Invoice " + (inv.number || "") + (inv.client_name ? (" · " + inv.client_name) : ""), success_url: base + "?inv_paid=" + inv.id, cancel_url: base }) });
      const d = await r.json().catch(() => ({}));
      if (!r.ok || !d.url) { setPayMsg(m => ({ ...m, [inv.id]: (d.error || "Online payments aren't switched on yet — the payment endpoint is the last step. Use “Mark as paid” for now.") })); return; }
      try { await navigator.clipboard.writeText(d.url); } catch (e) {}
      window.open(d.url, "_blank");
      setPayMsg(m => ({ ...m, [inv.id]: "✓ Payment link opened & copied — send it to your client." }));
    } catch (e) { setPayMsg(m => ({ ...m, [inv.id]: "Couldn't create a payment link right now." })); }
  }

  // ── print / PDF ──
  function printInvoice(inv) {
    const rows = (inv.items || []).map(it => "<tr><td>" + (it.desc || "") + "</td><td class='r'>" + (Number(it.qty) || 0) + "</td><td class='r'>" + money(it.price, inv.currency) + "</td><td class='r'>" + money((Number(it.qty) || 0) * (Number(it.price) || 0), inv.currency) + "</td></tr>").join("");
    const html = "<h1>Invoice " + (inv.number || "") + "</h1><div class='muted'>" + (inv.client_name ? "Bill to: " + inv.client_name + " · " : "") + (inv.due_date ? "Due " + inv.due_date : "") + "</div>" +
      "<table><tr><th>Description</th><th class='r'>Qty</th><th class='r'>Price</th><th class='r'>Amount</th></tr>" + rows +
      "<tr><td colspan='3' class='r'>Subtotal</td><td class='r'>" + money(invSubtotal(inv), inv.currency) + "</td></tr>" +
      (Number(inv.tax) ? "<tr><td colspan='3' class='r'>Tax (" + inv.tax + "%)</td><td class='r'>" + money(invSubtotal(inv) * (Number(inv.tax) / 100), inv.currency) + "</td></tr>" : "") +
      "<tr><td colspan='3' class='r tot'>Total</td><td class='r tot'>" + money(invTotal(inv), inv.currency) + "</td></tr></table>" +
      (inv.notes ? "<p class='muted'>" + inv.notes + "</p>" : "");
    bmPrint("Invoice " + (inv.number || ""), html);
  }
  function printReceipt(inv) {
    const rows = (inv.items || []).map(it => "<tr><td>" + (it.desc || "") + "</td><td class='r'>" + (Number(it.qty) || 0) + "</td><td class='r'>" + money(it.price, inv.currency) + "</td><td class='r'>" + money((Number(it.qty) || 0) * (Number(it.price) || 0), inv.currency) + "</td></tr>").join("");
    const paidOn = inv.paid_at ? new Date(inv.paid_at).toLocaleDateString() : new Date().toLocaleDateString();
    const html = "<h1>Receipt</h1><div class='muted'>For Invoice " + (inv.number || "") + (inv.client_name ? " · " + inv.client_name : "") + "</div><div class='muted'>Paid on " + paidOn + "</div>" +
      "<table><tr><th>Description</th><th class='r'>Qty</th><th class='r'>Price</th><th class='r'>Amount</th></tr>" + rows +
      "<tr><td colspan='3' class='r'>Subtotal</td><td class='r'>" + money(invSubtotal(inv), inv.currency) + "</td></tr>" +
      (Number(inv.tax) ? "<tr><td colspan='3' class='r'>Tax (" + inv.tax + "%)</td><td class='r'>" + money(invSubtotal(inv) * (Number(inv.tax) / 100), inv.currency) + "</td></tr>" : "") +
      "<tr><td colspan='3' class='r tot'>Total Paid</td><td class='r tot'>" + money(invTotal(inv), inv.currency) + "</td></tr></table>" +
      "<p class='muted'>Payment received in full — thank you!</p>";
    bmPrint("Receipt " + (inv.number || ""), html);
  }
  function printDoc(kind, d) {
    const html = "<h1>" + (d.title || (kind === "proposal" ? "Proposal" : "Contract")) + "</h1>" + (d.client_name ? "<div class='muted'>Prepared for " + d.client_name + "</div>" : "") + bmMdToHtml(d.body) + (kind === "contract" && d.signed_name ? "<div class='sign'><div class='line'>Signed: " + d.signed_name + (d.signed_at ? " · " + new Date(d.signed_at).toLocaleDateString() : "") + "</div></div>" : (kind === "contract" ? "<div class='sign'><div class='line'>Client signature</div><div class='line'>Date</div></div>" : ""));
    bmPrint(d.title || kind, html);
  }

  // ── styles ──
  const Label = ({ children }) => <div style={{ fontFamily: "sans-serif", fontSize: 9, fontWeight: 700, letterSpacing: "0.14em", color: B.mid, margin: "0 0 6px", textTransform: "uppercase" }}>{children}</div>;
  const inp = { width: "100%", padding: "10px 12px", border: "1px solid " + B.stone, outline: "none", fontSize: 13, fontFamily: "sans-serif", background: "#fff", color: "#111", marginBottom: 12, boxSizing: "border-box" };
  const sel = { ...inp, cursor: "pointer" };
  const badge = (s) => { const map = { paid: "#2E7D32", signed: "#2E7D32", accepted: "#2E7D32", sent: B.goldDark, draft: B.mid, declined: B.red, lead: B.goldDark, active: "#2E7D32", past: B.mid }; return { display: "inline-block", fontFamily: "sans-serif", fontSize: 9, fontWeight: 700, letterSpacing: "0.1em", textTransform: "uppercase", color: map[s] || B.mid, border: "1px solid " + (map[s] || B.stone), padding: "3px 8px", borderRadius: 2 }; };
  const secBtn = (extra) => ({ background: "#fff", border: "1px solid " + B.stone, color: B.charcoal, padding: "7px 12px", fontFamily: "sans-serif", fontSize: 10, letterSpacing: "0.08em", fontWeight: 700, cursor: "pointer", textTransform: "uppercase", marginRight: 6, marginTop: 6, ...(extra || {}) });

  if (locked) {
    return (
      <div>
        <h2 style={{ fontSize: 20, fontWeight: 400, fontFamily: "Georgia,serif", margin: "0 0 8px" }}>Business Manager</h2>
        <div style={{ background: B.offwhite, border: "1px solid " + B.stone, padding: "22px", fontFamily: "sans-serif", fontSize: 13, color: B.charcoal, lineHeight: 1.6 }}>
          Your CRM, invoices, proposals and contracts — all in one place. This is a members' tool.
          <div style={{ marginTop: 14 }}><Btn dark onClick={onUpgrade}>UPGRADE TO UNLOCK</Btn></div>
        </div>
      </div>
    );
  }

  const clientOptions = clients.map(c => <option key={c.id} value={c.name || ""}>{c.name || "(unnamed)"}</option>);

  return (
    <div>
      <h2 style={{ fontSize: 20, fontWeight: 400, fontFamily: "Georgia,serif", margin: "0 0 4px" }}>Business Manager</h2>
      <p style={{ fontFamily: "sans-serif", color: B.mid, fontSize: 12, margin: "0 0 16px", letterSpacing: "0.02em" }}>Your clients, invoices, proposals and contracts — all in one place.</p>

      {/* Overview strip */}
      <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginBottom: 16 }}>
        {[["Clients", clients.length], ["Open invoices", invoices.filter(i => i.status !== "paid").length], ["Outstanding", money(invoices.filter(i => i.status !== "paid").reduce((s, i) => s + invTotal(i), 0), (invoices[0] || {}).currency)]].map(([k, v], i) => (
          <div key={i} style={{ flex: "1 1 30%", minWidth: 90, background: B.offwhite, border: "1px solid " + B.stone, padding: "11px 13px" }}>
            <div style={{ fontFamily: "sans-serif", fontSize: 9, letterSpacing: "0.12em", color: B.mid, textTransform: "uppercase" }}>{k}</div>
            <div style={{ fontFamily: "Georgia,serif", fontSize: 18, color: B.charcoal, marginTop: 3 }}>{v}</div>
          </div>
        ))}
      </div>

      {/* Tabs */}
      <div style={{ display: "flex", flexWrap: "wrap", marginBottom: 18, borderBottom: "1px solid " + B.stone }}>
        {TABS.map(([id, label]) => (
          <button key={id} onClick={() => { setTab(id); setEdit(null); setErr(""); }} style={{ background: "none", border: "none", borderBottom: "2px solid " + (tab === id ? B.charcoal : "transparent"), color: tab === id ? B.charcoal : B.mid, padding: "10px 14px", fontFamily: "sans-serif", fontSize: 12, fontWeight: tab === id ? 700 : 500, letterSpacing: "0.02em", cursor: "pointer", marginBottom: -1 }}>{label}</button>
        ))}
      </div>

      {err && <div style={{ background: "#FEF2F2", border: "1px solid #FECACA", padding: "10px 14px", fontFamily: "sans-serif", fontSize: 12, color: B.red, marginBottom: 12 }}>{err}</div>}

      {/* ══ CLIENTS ══ */}
      {tab === "clients" && (
        <div>
          <Btn dark small onClick={() => setEdit({ kind: "client", row: { status: "lead" } })}>+ NEW CLIENT</Btn>
          {edit && edit.kind === "client" && (
            <Card style={{ padding: 20, margin: "14px 0" }}>
              <Label>Name</Label><input style={inp} value={edit.row.name || ""} onChange={e => setEdit({ ...edit, row: { ...edit.row, name: e.target.value } })} placeholder="Client or company name" />
              <Label>Email</Label><input style={inp} value={edit.row.email || ""} onChange={e => setEdit({ ...edit, row: { ...edit.row, email: e.target.value } })} />
              <Label>Phone</Label><input style={inp} value={edit.row.phone || ""} onChange={e => setEdit({ ...edit, row: { ...edit.row, phone: e.target.value } })} />
              <Label>Company</Label><input style={inp} value={edit.row.company || ""} onChange={e => setEdit({ ...edit, row: { ...edit.row, company: e.target.value } })} />
              <Label>Status</Label>
              <select style={sel} value={edit.row.status || "lead"} onChange={e => setEdit({ ...edit, row: { ...edit.row, status: e.target.value } })}>{["lead", "active", "past"].map(o => <option key={o} value={o}>{o[0].toUpperCase() + o.slice(1)}</option>)}</select>
              <Label>Deal value</Label><input style={inp} type="number" value={edit.row.deal_value || ""} onChange={e => setEdit({ ...edit, row: { ...edit.row, deal_value: e.target.value } })} placeholder="0" />
              <Label>Notes</Label><textarea style={{ ...inp, resize: "vertical", lineHeight: 1.6 }} rows={2} value={edit.row.notes || ""} onChange={e => setEdit({ ...edit, row: { ...edit.row, notes: e.target.value } })} />
              <Btn dark disabled={busy} onClick={() => save("bm_clients", edit.row.id, { name: edit.row.name || null, email: edit.row.email || null, phone: edit.row.phone || null, company: edit.row.company || null, status: edit.row.status || "lead", deal_value: edit.row.deal_value ? Number(edit.row.deal_value) : null, notes: edit.row.notes || null })}>{busy ? "SAVING..." : "SAVE CLIENT"}</Btn>
              <button style={secBtn({ marginLeft: 8 })} onClick={() => setEdit(null)}>CANCEL</button>
            </Card>
          )}
          <div style={{ marginTop: 14, display: "flex", flexDirection: "column", gap: 10 }}>
            {clients.map(c => (
              <div key={c.id} style={{ background: B.offwhite, border: "1px solid " + B.stone, padding: "14px 16px" }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", gap: 8 }}>
                  <div style={{ fontFamily: "Georgia,serif", fontSize: 16, color: B.charcoal }}>{c.name || "(unnamed)"}</div>
                  <span style={badge(c.status)}>{c.status}</span>
                </div>
                <div style={{ fontFamily: "sans-serif", fontSize: 11.5, color: B.mid, marginTop: 4, lineHeight: 1.5 }}>{[c.company, c.email, c.phone].filter(Boolean).join(" · ")}{c.deal_value ? " · " + money(c.deal_value, "USD") : ""}</div>
                {c.notes && <div style={{ fontFamily: "sans-serif", fontSize: 11.5, color: B.charcoal, marginTop: 6, lineHeight: 1.5 }}>{c.notes}</div>}
                <div><button style={secBtn()} onClick={() => setEdit({ kind: "client", row: c })}>Edit</button><button style={secBtn()} onClick={() => remove("bm_clients", c.id)}>Delete</button></div>
              </div>
            ))}
            {!clients.length && <div style={{ fontFamily: "sans-serif", fontSize: 12, color: B.mid, padding: "8px 0" }}>No clients yet — add your first one above.</div>}
          </div>
        </div>
      )}

      {/* ══ INVOICES ══ */}
      {tab === "invoices" && (
        <div>
          <div style={{ marginBottom: 14 }}>
            <StripeConnect user={user} />
            <div style={{ fontFamily: "sans-serif", fontSize: 11, color: B.mid, lineHeight: 1.5, marginTop: -8 }}>Connect Stripe once (you may have already for your store) to send clients a “Pay now” link. Payments go straight to your Stripe.</div>
          </div>
          <Btn dark small onClick={() => setEdit({ kind: "invoice", row: { items: [{ desc: "", qty: 1, price: 0 }], currency: "USD", status: "draft", number: "INV-" + String(invoices.length + 1).padStart(3, "0") } })}>+ NEW INVOICE</Btn>
          {edit && edit.kind === "invoice" && (
            <Card style={{ padding: 20, margin: "14px 0" }}>
              <Label>Invoice #</Label><input style={inp} value={edit.row.number || ""} onChange={e => setEdit({ ...edit, row: { ...edit.row, number: e.target.value } })} />
              <Label>Client</Label>
              <input style={inp} list="bm-clients-dl" value={edit.row.client_name || ""} onChange={e => setEdit({ ...edit, row: { ...edit.row, client_name: e.target.value } })} placeholder="Pick or type a client" />
              <datalist id="bm-clients-dl">{clientOptions}</datalist>
              <Label>Line items</Label>
              {(edit.row.items || []).map((it, idx) => (
                <div key={idx} style={{ display: "flex", gap: 6, marginBottom: 8, alignItems: "center" }}>
                  <input style={{ ...inp, marginBottom: 0, flex: 2 }} placeholder="Description" value={it.desc} onChange={e => { const items = [...edit.row.items]; items[idx] = { ...it, desc: e.target.value }; setEdit({ ...edit, row: { ...edit.row, items } }); }} />
                  <input style={{ ...inp, marginBottom: 0, width: 52 }} type="number" placeholder="Qty" value={it.qty} onChange={e => { const items = [...edit.row.items]; items[idx] = { ...it, qty: e.target.value }; setEdit({ ...edit, row: { ...edit.row, items } }); }} />
                  <input style={{ ...inp, marginBottom: 0, width: 72 }} type="number" placeholder="Price" value={it.price} onChange={e => { const items = [...edit.row.items]; items[idx] = { ...it, price: e.target.value }; setEdit({ ...edit, row: { ...edit.row, items } }); }} />
                  <button style={{ border: "none", background: "none", color: B.mid, cursor: "pointer", fontSize: 18, padding: "0 4px" }} onClick={() => { const items = edit.row.items.filter((_, j) => j !== idx); setEdit({ ...edit, row: { ...edit.row, items } }); }}>×</button>
                </div>
              ))}
              <button style={secBtn({ marginBottom: 12 })} onClick={() => setEdit({ ...edit, row: { ...edit.row, items: [...(edit.row.items || []), { desc: "", qty: 1, price: 0 }] } })}>+ Add line</button>
              <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
                <div style={{ flex: "1 1 40%" }}><Label>Currency</Label><select style={sel} value={edit.row.currency || "USD"} onChange={e => setEdit({ ...edit, row: { ...edit.row, currency: e.target.value } })}>{["USD", "EUR", "GBP", "CAD", "AUD"].map(o => <option key={o}>{o}</option>)}</select></div>
                <div style={{ flex: "1 1 40%" }}><Label>Tax %</Label><input style={inp} type="number" value={edit.row.tax || ""} onChange={e => setEdit({ ...edit, row: { ...edit.row, tax: e.target.value } })} placeholder="0" /></div>
              </div>
              <Label>Due date</Label><input style={inp} type="date" value={edit.row.due_date || ""} onChange={e => setEdit({ ...edit, row: { ...edit.row, due_date: e.target.value } })} />
              <Label>Notes</Label><textarea style={{ ...inp, resize: "vertical", lineHeight: 1.6 }} rows={2} value={edit.row.notes || ""} onChange={e => setEdit({ ...edit, row: { ...edit.row, notes: e.target.value } })} placeholder="Payment terms, thank-you note, etc." />
              <div style={{ fontFamily: "sans-serif", fontSize: 13, color: B.charcoal, fontWeight: 700, margin: "4px 0 12px" }}>Total: {money(invTotal(edit.row), edit.row.currency)}</div>
              <Btn dark disabled={busy} onClick={() => save("bm_invoices", edit.row.id, { client_name: edit.row.client_name || null, number: edit.row.number || null, items: edit.row.items || [], tax: edit.row.tax ? Number(edit.row.tax) : 0, currency: edit.row.currency || "USD", due_date: edit.row.due_date || null, status: edit.row.status || "draft", notes: edit.row.notes || null })}>{busy ? "SAVING..." : "SAVE INVOICE"}</Btn>
              <button style={secBtn({ marginLeft: 8 })} onClick={() => setEdit(null)}>CANCEL</button>
            </Card>
          )}
          <div style={{ marginTop: 14, display: "flex", flexDirection: "column", gap: 10 }}>
            {invoices.map(inv => (
              <div key={inv.id} style={{ background: B.offwhite, border: "1px solid " + B.stone, padding: "14px 16px" }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", gap: 8 }}>
                  <div style={{ fontFamily: "Georgia,serif", fontSize: 16, color: B.charcoal }}>{inv.number || "Invoice"} · {money(invTotal(inv), inv.currency)}</div>
                  <span style={badge(inv.status)}>{inv.status}</span>
                </div>
                <div style={{ fontFamily: "sans-serif", fontSize: 11.5, color: B.mid, marginTop: 4 }}>{[inv.client_name, inv.due_date ? "Due " + inv.due_date : ""].filter(Boolean).join(" · ")}</div>
                <div>
                  <button style={secBtn()} onClick={() => setEdit({ kind: "invoice", row: { ...inv, items: inv.items || [] } })}>Edit</button>
                  <button style={secBtn()} onClick={() => printInvoice(inv)}>PDF</button>
                  <button style={secBtn()} onClick={() => payLink(inv)}>💳 Payment link</button>
                  {inv.status !== "paid" ? <button style={secBtn()} onClick={() => save("bm_invoices", inv.id, { status: "paid", paid_at: new Date().toISOString() })}>Mark paid</button> : <button style={secBtn()} onClick={() => save("bm_invoices", inv.id, { status: "sent", paid_at: null })}>Unmark paid</button>}
                  <button style={secBtn()} onClick={() => remove("bm_invoices", inv.id)}>Delete</button>
                </div>
                {payMsg[inv.id] && <div style={{ fontFamily: "sans-serif", fontSize: 11, color: String(payMsg[inv.id]).charAt(0) === "✓" ? "#2E7D32" : B.mid, marginTop: 8, lineHeight: 1.5 }}>{payMsg[inv.id]}</div>}
              </div>
            ))}
            {!invoices.length && <div style={{ fontFamily: "sans-serif", fontSize: 12, color: B.mid, padding: "8px 0" }}>No invoices yet — create your first one above.</div>}
          </div>
        </div>
      )}

      {tab === "payments" && (() => {
        const paid = invoices.filter(i => i.status === "paid").slice().sort((a, b) => new Date(b.paid_at || b.created_at) - new Date(a.paid_at || a.created_at));
        const cur = (paid[0] || invoices[0] || {}).currency;
        const now = new Date();
        const sum = (arr) => arr.reduce((s2, i) => s2 + invTotal(i), 0);
        const monthPaid = paid.filter(i => { const d = new Date(i.paid_at || i.created_at); return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear(); });
        return (
          <div>
            <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginBottom: 16 }}>
              {[["Received this month", money(sum(monthPaid), cur)], ["Received all time", money(sum(paid), cur)], ["Payments", paid.length]].map(([k, v], i) => (
                <div key={i} style={{ flex: "1 1 30%", minWidth: 90, background: B.offwhite, border: "1px solid " + B.stone, padding: "11px 13px" }}>
                  <div style={{ fontFamily: "sans-serif", fontSize: 9, letterSpacing: "0.12em", color: B.mid, textTransform: "uppercase" }}>{k}</div>
                  <div style={{ fontFamily: "Georgia,serif", fontSize: 18, color: B.charcoal, marginTop: 3 }}>{v}</div>
                </div>
              ))}
            </div>
            <p style={{ fontFamily: "sans-serif", fontSize: 11.5, color: B.mid, lineHeight: 1.6, margin: "0 0 14px" }}>Every invoice you mark paid — or that a client pays online — shows up here as a payment. Tap <strong>Receipt</strong> to print or save a PDF receipt to send your client.</p>
            <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
              {paid.map(inv => (
                <div key={inv.id} style={{ background: B.white, border: "1px solid " + B.stone, padding: "14px 16px", display: "flex", alignItems: "center", justifyContent: "space-between", gap: 12, flexWrap: "wrap" }}>
                  <div>
                    <div style={{ fontFamily: "sans-serif", fontSize: 13, fontWeight: 700, color: B.charcoal }}>{money(invTotal(inv), inv.currency)} <span style={{ fontWeight: 400, color: B.mid }}>· {inv.client_name || "Client"}</span></div>
                    <div style={{ fontFamily: "sans-serif", fontSize: 10.5, color: B.mid, marginTop: 3 }}>Invoice {inv.number || "—"} · Paid {inv.paid_at ? new Date(inv.paid_at).toLocaleDateString() : "—"}</div>
                  </div>
                  <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
                    <span style={{ fontFamily: "sans-serif", fontSize: 9, letterSpacing: "0.1em", textTransform: "uppercase", fontWeight: 700, padding: "3px 9px", background: B.charcoal, color: "#fff" }}>Paid</span>
                    <button style={secBtn()} onClick={() => printReceipt(inv)}>Receipt</button>
                  </div>
                </div>
              ))}
              {!paid.length && <div style={{ fontFamily: "sans-serif", fontSize: 12, color: B.mid, padding: "8px 0" }}>No payments yet. When you mark an invoice paid, it will appear here with a printable receipt.</div>}
            </div>
          </div>
        );
      })()}

      {/* ══ PROPOSALS & CONTRACTS (shared) ══ */}
      {(tab === "proposals" || tab === "contracts") && (() => {
        const kind = tab === "proposals" ? "proposal" : "contract";
        const table = tab === "proposals" ? "bm_proposals" : "bm_contracts";
        const list = tab === "proposals" ? proposals : contracts;
        return (
          <div>
            <Btn dark small onClick={() => setEdit({ kind, row: { status: "draft" } })}>+ NEW {kind.toUpperCase()}</Btn>
            {edit && edit.kind === kind && (
              <Card style={{ padding: 20, margin: "14px 0" }}>
                <Label>Title</Label><input style={inp} value={edit.row.title || ""} onChange={e => setEdit({ ...edit, row: { ...edit.row, title: e.target.value } })} placeholder={kind === "proposal" ? "e.g. Social Media Management Proposal" : "e.g. Service Agreement"} />
                <Label>Client</Label>
                <input style={inp} list="bm-clients-dl2" value={edit.row.client_name || ""} onChange={e => setEdit({ ...edit, row: { ...edit.row, client_name: e.target.value } })} placeholder="Pick or type a client" />
                <datalist id="bm-clients-dl2">{clientOptions}</datalist>
                <button style={secBtn({ marginBottom: 12 })} disabled={drafting} onClick={async () => { const body = await draftDoc(kind, edit.row.title, edit.row.client_name, edit.row.extra); setEdit(e => ({ ...e, row: { ...e.row, body } })); }}>{drafting ? "✍️ Drafting…" : "✨ Draft with AI"}</button>
                <Label>{kind === "proposal" ? "Proposal" : "Contract"} text</Label>
                <textarea style={{ ...inp, resize: "vertical", lineHeight: 1.6, fontFamily: "Georgia,serif", fontSize: 13 }} rows={12} value={edit.row.body || ""} onChange={e => setEdit({ ...edit, row: { ...edit.row, body: e.target.value } })} placeholder="Write it yourself or tap Draft with AI." />
                <Label>Status</Label>
                <select style={sel} value={edit.row.status || "draft"} onChange={e => setEdit({ ...edit, row: { ...edit.row, status: e.target.value } })}>{(kind === "proposal" ? ["draft", "sent", "accepted", "declined"] : ["draft", "sent", "signed"]).map(o => <option key={o} value={o}>{o[0].toUpperCase() + o.slice(1)}</option>)}</select>
                <Btn dark disabled={busy} onClick={() => save(table, edit.row.id, { title: edit.row.title || null, client_name: edit.row.client_name || null, body: edit.row.body || null, status: edit.row.status || "draft" })}>{busy ? "SAVING..." : "SAVE"}</Btn>
                <button style={secBtn({ marginLeft: 8 })} onClick={() => setEdit(null)}>CANCEL</button>
              </Card>
            )}
            <div style={{ marginTop: 14, display: "flex", flexDirection: "column", gap: 10 }}>
              {list.map(d => (
                <div key={d.id} style={{ background: B.offwhite, border: "1px solid " + B.stone, padding: "14px 16px" }}>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", gap: 8 }}>
                    <div style={{ fontFamily: "Georgia,serif", fontSize: 16, color: B.charcoal }}>{d.title || "(untitled)"}</div>
                    <span style={badge(d.status)}>{d.status}</span>
                  </div>
                  {d.client_name && <div style={{ fontFamily: "sans-serif", fontSize: 11.5, color: B.mid, marginTop: 4 }}>{d.client_name}</div>}
                  <div>
                    <button style={secBtn()} onClick={() => setEdit({ kind, row: d })}>Edit</button>
                    <button style={secBtn()} onClick={() => printDoc(kind, d)}>PDF</button>
                    {kind === "contract" && d.status !== "signed" && <button style={secBtn()} onClick={() => { const name = window.prompt("Type the client's full name to mark as signed:"); if (name && name.trim()) save(table, d.id, { status: "signed", signed_name: name.trim(), signed_at: new Date().toISOString() }); }}>Mark signed</button>}
                    <button style={secBtn()} onClick={() => remove(table, d.id)}>Delete</button>
                  </div>
                </div>
              ))}
              {!list.length && <div style={{ fontFamily: "sans-serif", fontSize: 12, color: B.mid, padding: "8px 0" }}>Nothing here yet — create your first one above.</div>}
            </div>
          </div>
        );
      })()}
    </div>
  );
}

function ProductStudio({ onBalance, useCredits, onToolUse, user, credits }) {
  // Studio scene presets — Kive-style "virtual photo sets". Each appends a scene
  // description to the prompt while the uploaded product stays accurate.
  const STUDIOS = [
    { id:"ecom",     label:"Clean E-Commerce", desc:"Place the product on a seamless pure-white studio background, evenly and softly lit with gentle contact shadows — a crisp catalogue-ready packshot." },
    { id:"marble",   label:"Marble Luxe",      desc:"Set the product on a polished white marble surface in soft natural window light, with subtle elegant reflections and a refined luxury feel." },
    { id:"editorial",label:"Warm Editorial",   desc:"Style the product in a warm editorial scene — soft golden light, cream and beige tones, a few tasteful props, magazine-quality art direction." },
    { id:"gradient", label:"Studio Gradient",  desc:"Photograph the product against a smooth modern studio gradient backdrop with dramatic directional lighting and one bold tasteful accent colour." },
    { id:"outdoor",  label:"Natural Light",    desc:"Shoot the product outdoors in soft natural daylight on an organic surface such as stone, wood or greenery — fresh, airy and premium." },
    { id:"flatlay",  label:"Lifestyle Flatlay",desc:"Compose an overhead flat-lay on a textured surface with complementary props arranged tastefully around the product — balanced and stylish." },
    { id:"model",    label:"On a Model",       desc:"Show the product being held or worn naturally by a realistic, stylish human model in a flattering lifestyle setting. Keep the product clearly visible and perfectly accurate; the person looks natural, premium and aspirational." },
    { id:"custom",   label:"Custom Scene",     desc:"" },
  ];

  // Image-to-video model options (reuse the app's existing /api/video pipeline).
  const VIDEO_MODELS = [
    { id:"480p",       label:"Standard — fast & economical" },
    { id:"720p",       label:"HD 720p — sharper" },
    { id:"1080p",      label:"Premium 1080p — cinematic" },
    { id:"kling4k",    label:"4K Ultra · Kling 3.0" },
    { id:"seedance480",  label:"Seedance 2.0 · 480p — fast & economical" },
    { id:"seedance720",  label:"Seedance 2.0 · 720p — HD" },
    { id:"seedance1080", label:"Seedance 2.0 · 1080p — Full HD" },
    { id:"seedance4k",   label:"Seedance 2.0 · 4K — best product fidelity" },
  ];
  const DEFAULT_MOTION = "Bring this product photo to life with a smooth, subtle cinematic camera move — a slow push-in or gentle rotation — soft studio lighting and a premium commercial feel. Keep the product perfectly accurate and in sharp focus. No text or captions.";

  const [products, setProducts] = useState([]); // reference photo data URLs (up to 4)
  const [productName, setProductName] = useState("");
  const [studio, setStudio] = useState("ecom");
  const [extra, setExtra] = useState("");
  const [model, setModel] = useState("");
  const [outfit, setOutfit] = useState("");
  const [environment, setEnvironment] = useState("");
  const [aspect, setAspect] = useState("4:5");
  const [quality, setQuality] = useState("standard");
  const [loading, setLoading] = useState(false);
  const [err, setErr] = useState("");
  const [shots, setShots] = useState([]); // { id, url, label, aspect }
  const [prog, setProg] = useState("");
  const [saveMsg, setSaveMsg] = useState({});
  const [videos, setVideos] = useState({}); // { [shotId]: { open, prompt, quality, duration, orient, loading, status, url, err, saveMsg } }

  function costFor(q){ return q === "4K" ? CREDIT_COSTS.image4K : q === "2K" ? CREDIT_COSTS.imageHD : CREDIT_COSTS.image; }
  const cost = costFor(quality);
  function aspectToOrient(a){ return a === "16:9" || a === "4:3" ? "landscape" : a === "1:1" ? "square" : "portrait"; }
  function vidCostFor(q, d){
    d = Number(d) || 5;
    if (q === "kling4k") return CREDIT_COSTS.klingSec * d;
    if (q.indexOf("seedance")===0) return seedanceRate(q) * d;
    const base = q === "1080p" ? CREDIT_COSTS.video1080 : q === "720p" ? CREDIT_COSTS.videoHD : CREDIT_COSTS.video;
    return Math.round(base * d / 5);
  }
  function setVid(id, patch){ setVideos(prev => ({ ...prev, [id]: { ...(prev[id] || {}), ...patch } })); }

  function onUpload(e) {
    const files = e.target.files;
    if (!files || !files.length) return;
    Array.from(files).slice(0, 4).forEach(f => {
      const r = new FileReader();
      r.onload = () => setProducts(prev => prev.length >= 4 ? prev : [...prev, r.result]);
      r.readAsDataURL(f);
    });
    e.target.value = "";
  }

  function buildPrompt() {
    const s = STUDIOS.find(x => x.id === studio) || STUDIOS[0];
    let p = "Create a premium, high-end commercial product photograph of the product shown in the uploaded reference photo" + (products.length > 1 ? "s" : "") + ". ";
    p += "CRITICAL: keep the product itself perfectly accurate to the reference — identical shape, colour, materials, proportions, and any label text, logo or branding must stay correct, sharp and legible. Do not redesign or alter the product. ";
    if (productName.trim()) p += "The product is: " + productName.trim() + ". ";
    if (model.trim()) p += "Include a realistic, attractive human model: " + model.trim() + ". The model naturally holds, wears or uses the product so it stays the clear hero of the shot, looking premium and aspirational. ";
    if (outfit.trim()) p += "Style the model in: " + outfit.trim() + ". ";
    if (environment.trim()) p += "Place the scene in this environment: " + environment.trim() + ". ";
    if (s.desc) p += s.desc + " ";
    if (extra.trim()) p += extra.trim() + " ";
    p += "Studio-quality professional lighting, realistic reflections and natural shadows, sharp focus, tasteful editorial composition, clean and uncluttered, an expensive premium brand feel. ";
    p += "No watermark, no signature, and no AI or tool attribution text anywhere in the image.";
    return p;
  }

  async function generate() {
    if (!products.length) { setErr("Add at least one photo of your product first."); return; }
    if (loading) return;
    if (!useCredits(cost)) return; // gate + insufficient-credit UX handled upstream
    setErr(""); setLoading(true);
    try {
      const inputImages = products
        .map(u => { const m = /^data:(.*?);base64,(.*)$/.exec(u || ""); return m ? { mimeType: m[1], data: m[2] } : null; })
        .filter(Boolean);
      const r = await generateGeminiImage(buildPrompt(), inputImages, aspect, quality);
      if (!r || !r.image) throw new Error("No image came back. Please try again.");
      if (typeof r.balance === "number") onBalance(r.balance);
      const label = (STUDIOS.find(x => x.id === studio) || {}).label || "Shot";
      setShots(prev => [{ id: Date.now() + "-" + Math.random().toString(36).slice(2, 6), url: r.image, label, aspect }, ...prev]);
      try { onToolUse("product_studio", cost); } catch (e) {}
    } catch (e) {
      setErr("Sorry — we couldn't create that shot right now. Please try again in a little while.");
    }
    setLoading(false);
  }

  const ANGLES = [
    ["Front", "a clean straight-on FRONT view of the product"],
    ["Back", "a straight-on BACK view of the same product"],
    ["Side", "a 3/4 SIDE-angle view of the same product"],
    ["Close-up", "a tight CLOSE-UP detail shot showing the material and texture of the same product"],
  ];
  function productInputs() {
    return products
      .map(u => { const m = /^data:(.*?);base64,(.*)$/.exec(u || ""); return m ? { mimeType: m[1], data: m[2] } : null; })
      .filter(Boolean);
  }
  async function enhance() {
    if (!products.length) { setErr("Add at least one photo of your product first."); return; }
    if (loading) return;
    if (!useCredits(cost)) return;
    setErr(""); setLoading(true); setProg("Enhancing your product photo... (4–8 seconds)");
    try {
      let p = "Enhance the product shown in the uploaded photo" + (products.length > 1 ? "s" : "") + " into a clean, professional, high-end product photograph. ";
      p += "CRITICAL: keep the product itself perfectly accurate — identical shape, colour, materials, proportions, and any label text, logo or branding must stay correct, sharp and legible. Do not redesign the product. ";
      p += "Just make it look professional: remove background clutter and distractions, place it on a clean tasteful studio backdrop, add soft realistic studio lighting with natural shadows and reflections, fix any blur or poor lighting, and make it crisp, bright and premium. ";
      if (productName.trim()) p += "The product is: " + productName.trim() + ". ";
      if (extra.trim()) p += extra.trim() + " ";
      p += "No watermark, no text, no AI attribution.";
      const r = await generateGeminiImage(p, productInputs(), aspect, quality);
      if (!r || !r.image) throw new Error("no image");
      if (typeof r.balance === "number") onBalance(r.balance);
      setShots(prev => [{ id: Date.now() + "-" + Math.random().toString(36).slice(2, 6), url: r.image, label: "Enhanced", aspect }, ...prev]);
      try { onToolUse("product_studio_enhance", cost); } catch (e) {}
    } catch (e) {
      setErr("Sorry — we couldn't enhance that photo right now. Please try again in a little while.");
    }
    setProg(""); setLoading(false);
  }
  async function generateAngles() {
    if (!products.length) { setErr("Add at least one photo of your product first."); return; }
    if (loading) return;
    if (!useCredits(cost * ANGLES.length)) return;
    setErr(""); setLoading(true);
    const existing = shots;
    const made = [];
    let failures = 0;
    for (let i = 0; i < ANGLES.length; i++) {
      setProg("Creating " + ANGLES[i][0] + " view (" + (i + 1) + " of 4)…");
      let p = "Using the uploaded reference photo" + (products.length > 1 ? "s" : "") + " of the product, generate " + ANGLES[i][1] + ". ";
      p += "CRITICAL: keep the exact same product — identical shape, colour, materials, proportions and any label text, logo or branding, sharp and legible. Do not redesign it. ";
      p += "Professional e-commerce product photography, clean seamless studio background, soft even lighting, sharp detail, premium feel. ";
      if (productName.trim()) p += "The product is: " + productName.trim() + ". ";
      if (extra.trim()) p += extra.trim() + " ";
      p += "No watermark, no text.";
      let ok = false;
      for (let attempt = 0; attempt < 2 && !ok; attempt++) {
        try {
          const r = await generateGeminiImage(p, productInputs(), aspect, quality);
          if (r && r.image) { if (typeof r.balance === "number") onBalance(r.balance); made.push({ id: Date.now() + "-" + i + "-" + Math.random().toString(36).slice(2, 5), url: r.image, label: ANGLES[i][0], aspect }); setShots([...made, ...existing]); ok = true; }
        } catch (e) { /* retry once */ }
      }
      if (!ok) failures++;
    }
    setProg("");
    try { onToolUse("product_studio_angles", cost * (ANGLES.length - failures)); } catch (e) {}
    if (!made.length) setErr("Sorry — we couldn't create the angle set right now. Please try again in a little while.");
    else if (failures) setErr(made.length + " of 4 angles came through — tap 4 Angles again to fill in the rest.");
    setLoading(false);
  }

  async function saveShot(shot) {
    setSaveMsg(m => ({ ...m, [shot.id]: "Saving…" }));
    try {
      const uid = (user && user.id) || "anon";
      const url = await uploadSiteImage(shot.url, uid + "/product-" + Date.now() + "-" + Math.random().toString(36).slice(2, 5) + ".png");
      if (!url) throw new Error("save failed");
      await saveToLibrary(user, "product", (productName.trim() || "Product Studio") + " — " + shot.label, url);
      setSaveMsg(m => ({ ...m, [shot.id]: "✓ Saved to Library" }));
    } catch (e) {
      setSaveMsg(m => ({ ...m, [shot.id]: "Couldn't save — try again" }));
    }
  }

  // ── Phase 2: animate a still into a short product video (reuses /api/video) ──
  async function animate(shot) {
    const v = videos[shot.id] || {};
    if (v.loading) return;
    const q = v.quality || "480p";
    const dur = Number(v.duration || 5);
    const orient = v.orient || aspectToOrient(shot.aspect);
    const vc = vidCostFor(q, dur);
    if (!useCredits(vc)) return;
    setVid(shot.id, { loading: true, err: "", url: "", status: "Starting the video engine..." });
    try {
      const prompt = (v.prompt && v.prompt.trim()) || DEFAULT_MOTION;
      const started = await generateVideo(prompt, shot.url, { orientation: orient, quality: q, duration: dur, audio: false, tool:"product_studio" });
      if (!started || !started.id) {
        setVid(shot.id, { loading: false, status: "", err: "Sorry — we couldn't start that video right now. Please try again in a little while." });
        return;
      }
      if (typeof started.balance === "number") onBalance(started.balance);
      setVid(shot.id, { status: "Creating your video — usually 1 to 3 minutes (the 4K models can take up to 10). Keep this tab open." });
      try { onToolUse("product_studio_video", vc); } catch (e) {}
      const url = await pollVideo(started.id);
      if (!url) {
        setVid(shot.id, { loading: false, status: "", err: "The video didn't finish in time. Your credits were refunded." });
        if (typeof started.balance === "number") onBalance(started.balance + vc);
        return;
      }
      setVid(shot.id, { loading: false, status: "", url });
    } catch (e) {
      setVid(shot.id, { loading: false, status: "", err: "Something went wrong generating the video. Please try again." });
    }
  }

  async function saveVideo(shot, url) {
    setVid(shot.id, { saveMsg: "Saving…" });
    try {
      await saveToLibrary(user, "video", (productName.trim() || "Product Studio") + " — " + shot.label + " video", url);
      setVid(shot.id, { saveMsg: "✓ Saved to Library" });
    } catch (e) {
      setVid(shot.id, { saveMsg: "Couldn't save — try again" });
    }
  }

  // ── small local UI helpers (match the app's field styling) ──
  const Label = ({ children }) => (
    <div style={{ fontFamily: "sans-serif", fontSize: 9, fontWeight: 700, letterSpacing: "0.14em", color: B.mid, marginBottom: 7, textTransform: "uppercase" }}>{children}</div>
  );
  const CostNote = ({ cost }) => {
    const have = typeof credits === "number" ? credits : null;
    const insufficient = have !== null && cost > have;
    const heavy = have !== null && !insufficient && cost >= have * 0.4; // uses 40%+ of remaining balance
    const color = insufficient ? B.red : heavy ? "#B7791F" : B.mid;
    return (
      <div style={{ fontFamily: "sans-serif", fontSize: 11.5, color, marginTop: 9, lineHeight: 1.5 }}>
        {insufficient
          ? "⚠ Not enough credits — this needs " + cost.toLocaleString() + " and you have " + have.toLocaleString() + ". Top up in Profile → Buy credits."
          : "Uses " + cost.toLocaleString() + " credits" + (have !== null ? " · you have " + have.toLocaleString() : "") + (heavy ? " — heads up, that's a big chunk of your balance." : "")}
      </div>
    );
  };
  const selStyle = { width: "100%", padding: "10px 12px", border: "1px solid " + B.stone, outline: "none", fontSize: 13, fontFamily: "sans-serif", background: "#fff", color: "#111", cursor: "pointer", marginBottom: 14, boxSizing: "border-box" };
  const inpStyle = { width: "100%", padding: "10px 12px", border: "1px solid " + B.stone, outline: "none", fontSize: 13, fontFamily: "sans-serif", background: "#fff", color: "#111", marginBottom: 14, boxSizing: "border-box" };

  return (
    <div>
      <h2 style={{ fontSize: 20, fontWeight: 400, fontFamily: "Georgia,serif", margin: "0 0 4px" }}>Product Studio</h2>
      <p style={{ fontFamily: "sans-serif", color: B.mid, fontSize: 12, margin: "0 0 6px", letterSpacing: "0.02em" }}>Powered by Nano Banana 2 (Google Gemini)</p>
      <p style={{ fontFamily: "sans-serif", color: B.mid, fontSize: 12, margin: "0 0 6px", letterSpacing: "0.02em" }}>Make studio photos of your product — then turn any shot into a video with the 🎬 Make a Video button.</p>
      <div style={{ background: B.white, border: "1px solid " + B.stone, padding: "8px 14px", marginBottom: 18, fontFamily: "sans-serif", fontSize: 11, color: B.goldDark, letterSpacing: "0.02em" }}>Upload your product once, then drop it into premium, on-brand photo studios — clean packshots, marble, editorial, lifestyle, or on a model. Then bring any shot to life as a short video.</div>

      <Card style={{ padding: "22px", marginBottom: 14 }}>
        {/* Upload product */}
        <Label>Your product photo(s) · up to 4</Label>
        {products.length > 0 && (
          <div style={{ display: "flex", flexWrap: "wrap", gap: 8, marginBottom: 10 }}>
            {products.map((u, idx) => (
              <div key={idx} style={{ position: "relative", width: 72, height: 72 }}>
                <img src={u} alt={"Product " + (idx + 1)} style={{ width: 72, height: 72, objectFit: "cover", border: "1px solid " + B.stone, display: "block" }} />
                <button onClick={() => setProducts(prev => prev.filter((_, i) => i !== idx))} style={{ position: "absolute", top: -7, right: -7, width: 20, height: 20, borderRadius: "50%", background: B.charcoal, color: "#fff", border: "none", cursor: "pointer", fontSize: 12, lineHeight: 1, display: "flex", alignItems: "center", justifyContent: "center" }}>×</button>
              </div>
            ))}
          </div>
        )}
        {products.length < 4 && (
          <label style={{ display: "block", border: "1px dashed " + B.stone, background: B.white, padding: "16px", textAlign: "center", cursor: "pointer", fontFamily: "sans-serif", fontSize: 12, color: B.goldDark, letterSpacing: "0.02em", marginBottom: 16 }}>
            {products.length ? "Add another angle" : "Tap to upload your product — a clean, sharp photo works best. Add a few angles for the most accurate results."}
            <input type="file" accept="image/*" multiple onChange={onUpload} style={{ display: "none" }} />
          </label>
        )}

        <Label>Product name · optional</Label>
        <input value={productName} onChange={e => setProductName(e.target.value)} placeholder="e.g. Rose Body Oil, Weekender Bag" style={inpStyle} />

        <Label>Model · optional</Label>
        <input value={model} onChange={e => setModel(e.target.value)} placeholder="e.g. a stylish woman in her late 20s, warm skin, natural curls" style={inpStyle} />
        <Label>Outfit · optional</Label>
        <input value={outfit} onChange={e => setOutfit(e.target.value)} placeholder="e.g. cream linen suit, minimal gold jewellery" style={inpStyle} />
        <Label>Environment · optional</Label>
        <input value={environment} onChange={e => setEnvironment(e.target.value)} placeholder="e.g. sunlit minimalist loft, soft neutral tones" style={inpStyle} />
        <div style={{ fontFamily: "sans-serif", fontSize: 11, color: B.mid, margin: "-4px 0 16px", lineHeight: 1.5 }}>Add a model, outfit and environment to build a full scene around your product — or leave blank for a classic product-only shot.</div>

        {/* Studio picker */}
        <Label>Choose a studio</Label>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8, marginBottom: 16 }}>
          {STUDIOS.map(s => (
            <button key={s.id} onClick={() => setStudio(s.id)} style={{ textAlign: "left", padding: "12px 13px", border: "1px solid " + (studio === s.id ? B.charcoal : B.stone), background: studio === s.id ? B.charcoal : "#fff", color: studio === s.id ? "#fff" : B.charcoal, cursor: "pointer", fontFamily: "sans-serif", fontSize: 12.5, fontWeight: 600, letterSpacing: "0.01em", lineHeight: 1.3 }}>{s.label}</button>
          ))}
        </div>

        <Label>{studio === "custom" ? "Describe your scene" : "Extra direction · optional"}</Label>
        <textarea value={extra} onChange={e => setExtra(e.target.value)} rows={studio === "custom" ? 3 : 2} placeholder={studio === "custom" ? "Describe the exact scene, surface, props, mood and lighting you want." : "Anything to add — e.g. 'held in a hand', 'with fresh flowers', 'on a linen backdrop'."} style={{ ...inpStyle, resize: "vertical", lineHeight: 1.6 }} />

        <Label>Orientation</Label>
        <select value={aspect} onChange={e => setAspect(e.target.value)} style={selStyle}>
          <option value="1:1">Square (1:1)</option>
          <option value="4:5">Portrait (4:5)</option>
          <option value="9:16">Tall / Story (9:16)</option>
          <option value="16:9">Landscape (16:9)</option>
          <option value="4:3">Standard (4:3)</option>
        </select>

        <Label>Quality</Label>
        <select value={quality} onChange={e => setQuality(e.target.value)} style={selStyle}>
          <option value="standard">Standard — fast &amp; economical ({CREDIT_COSTS.image} cr)</option>
          <option value="2K">HD 2K — sharper, better label text ({CREDIT_COSTS.imageHD} cr)</option>
          <option value="4K">Ultra 4K — maximum detail ({CREDIT_COSTS.image4K} cr)</option>
        </select>

        <Btn dark disabled={loading || !products.length} onClick={generate}>
          {loading ? "CREATING SHOT..." : ("GENERATE SHOT (" + cost.toLocaleString() + " credits)")}
        </Btn>
        {products.length > 0 && <CostNote cost={cost} />}
        {products.length > 0 && (
          <div style={{ marginTop: 12 }}>
            <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
              <button disabled={loading || !products.length} onClick={enhance} style={{ flex: "1 1 46%", background: "#fff", border: "1px solid " + B.charcoal, color: B.charcoal, padding: "12px", fontFamily: "sans-serif", fontSize: 11, letterSpacing: "0.05em", fontWeight: 700, cursor: (loading || !products.length) ? "default" : "pointer", textTransform: "uppercase", opacity: (loading || !products.length) ? 0.5 : 1 }}>✨ Enhance photo ({cost.toLocaleString()} cr)</button>
              <button disabled={loading || !products.length} onClick={generateAngles} style={{ flex: "1 1 46%", background: "#fff", border: "1px solid " + B.charcoal, color: B.charcoal, padding: "12px", fontFamily: "sans-serif", fontSize: 11, letterSpacing: "0.05em", fontWeight: 700, cursor: (loading || !products.length) ? "default" : "pointer", textTransform: "uppercase", opacity: (loading || !products.length) ? 0.5 : 1 }}>📐 4 Angles ({(cost * 4).toLocaleString()} cr)</button>
            </div>
            <div style={{ fontFamily: "sans-serif", fontSize: 11, color: B.mid, marginTop: 8, lineHeight: 1.5 }}><strong>Enhance</strong> = a clean, professional version of your photo. <strong>4 Angles</strong> = front, back, side &amp; close-up of the same product.</div>
          </div>
        )}
        {!products.length && <div style={{ fontFamily: "sans-serif", fontSize: 11, color: B.mid, marginTop: 10 }}>Upload a product photo to begin.</div>}
      </Card>

      {loading && <div style={{ background: B.offwhite, border: "1px solid " + B.stone, padding: "36px", textAlign: "center", fontFamily: "sans-serif", fontSize: 12, color: B.mid, letterSpacing: "0.04em" }}>{prog || "Styling your product shot... (4–8 seconds)"}</div>}
      {err && <div style={{ background: "#FEF2F2", border: "1px solid #FECACA", padding: "12px 16px", fontFamily: "sans-serif", fontSize: 12, color: B.red, marginTop: 4 }}>{err}</div>}

      {/* Results gallery — keep generating to build a set, animate any shot */}
      {shots.length > 0 && (
        <div style={{ marginTop: 16 }}>
          <div style={{ fontSize: 9, color: B.gold, fontFamily: "sans-serif", fontWeight: 700, letterSpacing: "0.18em", marginBottom: 12, textTransform: "uppercase" }}>Your product set · {shots.length}</div>
          <div style={{ fontFamily: "sans-serif", fontSize: 11, color: B.mid, marginTop: -6, marginBottom: 12 }}>Tap 🎬 Make a Video on any shot to turn it into a product clip.</div>
          <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
            {shots.map(shot => {
              const v = videos[shot.id] || {};
              return (
              <div key={shot.id} style={{ background: B.offwhite, border: "1px solid " + B.stone, padding: "20px" }}>
                <div style={{ fontFamily: "sans-serif", fontSize: 10, color: B.mid, letterSpacing: "0.1em", textTransform: "uppercase", marginBottom: 10 }}>{shot.label}</div>
                <img src={shot.url} alt={shot.label} style={{ maxWidth: "100%", display: "block", marginBottom: 12 }} />
                <Btn dark small onClick={()=>downloadPic(shot.url,"chelgy-product.jpg")}>DOWNLOAD</Btn>
                <button onClick={() => saveShot(shot)} style={{ marginLeft: 8, background: "#fff", border: "1px solid " + B.stone, color: B.charcoal, padding: "9px 14px", fontFamily: "sans-serif", fontSize: 10, letterSpacing: "0.1em", fontWeight: 700, cursor: "pointer", textTransform: "uppercase" }}>♥ Save to Library</button>
                <button onClick={() => setVid(shot.id, { open: !v.open })} style={{ marginLeft: 8, background: v.open ? B.charcoal : "#fff", border: "1px solid " + (v.open ? B.charcoal : B.stone), color: v.open ? "#fff" : B.charcoal, padding: "9px 14px", fontFamily: "sans-serif", fontSize: 10, letterSpacing: "0.1em", fontWeight: 700, cursor: "pointer", textTransform: "uppercase" }}>🎬 Make a Video</button>
                {saveMsg[shot.id] && <div style={{ fontFamily: "sans-serif", fontSize: 11, color: String(saveMsg[shot.id]).charAt(0) === "✓" ? "#2E7D32" : B.mid, marginTop: 10 }}>{saveMsg[shot.id]}</div>}
                <div style={{ marginTop: 14 }}><ShareBar file={shot.url} filename="chelgy-product.png" title="Made with Chelgy" text="" /></div>

                {/* Animate panel */}
                {v.open && (
                  <div style={{ marginTop: 16, borderTop: "1px solid " + B.stone, paddingTop: 16 }}>
                    <Label>Motion &amp; direction</Label>
                    <textarea value={v.prompt !== undefined ? v.prompt : DEFAULT_MOTION} onChange={e => setVid(shot.id, { prompt: e.target.value })} rows={3} style={{ ...inpStyle, resize: "vertical", lineHeight: 1.6 }} />
                    <Label>Model &amp; quality</Label>
                    <select value={v.quality || "480p"} onChange={e => setVid(shot.id, { quality: e.target.value })} style={selStyle}>
                      {VIDEO_MODELS.map(m => <option key={m.id} value={m.id}>{m.label}</option>)}
                    </select>
                    <Label>Length</Label>
                    <select value={String(v.duration || 5)} onChange={e => setVid(shot.id, { duration: e.target.value })} style={selStyle}>
                      <option value="5">5 seconds</option>
                      <option value="10">10 seconds</option>
                    </select>
                    <Label>Orientation</Label>
                    <select value={v.orient || aspectToOrient(shot.aspect)} onChange={e => setVid(shot.id, { orient: e.target.value })} style={selStyle}>
                      <option value="portrait">Portrait (9:16)</option>
                      <option value="landscape">Landscape (16:9)</option>
                      <option value="square">Square (1:1)</option>
                    </select>
                    <Btn dark disabled={v.loading} onClick={() => animate(shot)}>
                      {v.loading ? "GENERATING VIDEO..." : ("GENERATE VIDEO (" + vidCostFor(v.quality || "480p", v.duration || 5).toLocaleString() + " credits)")}
                    </Btn>
                    <CostNote cost={vidCostFor(v.quality || "480p", v.duration || 5)} />
                    {v.loading && v.status && <div style={{ background: B.white, border: "1px solid " + B.stone, padding: "16px", textAlign: "center", fontFamily: "sans-serif", fontSize: 12, color: B.mid, letterSpacing: "0.02em", lineHeight: 1.6, marginTop: 12 }}>{v.status}</div>}
                    {v.err && !v.loading && <div style={{ background: "#FEF2F2", border: "1px solid #FECACA", padding: "12px 16px", fontFamily: "sans-serif", fontSize: 12, color: B.red, marginTop: 12 }}>{v.err}</div>}
                    {v.url && !v.loading && (
                      <div style={{ background: B.white, border: "1px solid " + B.stone, padding: "16px", marginTop: 12 }}>
                        <video src={v.url} controls playsInline style={{ maxWidth: "100%", display: "block", marginBottom: 12, background: "#000" }} />
                        <Btn dark small onClick={()=>downloadVideo(v.url,"chelgy-product-video.mp4")}>DOWNLOAD VIDEO</Btn>
                        <button onClick={() => saveVideo(shot, v.url)} style={{ marginLeft: 8, background: "#fff", border: "1px solid " + B.stone, color: B.charcoal, padding: "9px 14px", fontFamily: "sans-serif", fontSize: 10, letterSpacing: "0.1em", fontWeight: 700, cursor: "pointer", textTransform: "uppercase" }}>♥ Save to Library</button>
                        {v.saveMsg && <div style={{ fontFamily: "sans-serif", fontSize: 11, color: String(v.saveMsg).charAt(0) === "✓" ? "#2E7D32" : B.mid, marginTop: 10 }}>{v.saveMsg}</div>}
                        <div style={{ marginTop: 14 }}><ShareBar url={v.url} file={v.url} filename="chelgy-product-video.mp4" title="Made with Chelgy" text="" /></div>
                      </div>
                    )}
                  </div>
                )}
              </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}

// ─── BACKLINK & AUTHORITY BUILDER (white-hat opportunity finder + outreach) ──────
function AuthorityBuilder({ onToolUse, locked, onUpgrade, bizCtx, user }) {
  const ctxPre = bizCtx ? ("[Context about the business owner you're helping — use this to personalize your answer, but always follow their specific request below:]\n" + bizCtx + "\n\n") : "";
  const WHITE_HAT = " ONLY recommend legitimate, white-hat opportunities (local directories, chambers of commerce, industry & trade associations, local news/blogs, 'best of' roundups, relevant resource pages, niche directories, community sites, podcasts, guest-post and partnership targets). NEVER recommend buying links, link farms, PBNs, paid link schemes, or anything that violates Google's link-spam policy — those can get a site penalized. Favor relevance over raw authority, and remind them to vary anchor text naturally.";

  const MODES = [
    { id: "find",       label: "Find opportunities" },
    { id: "outreach",   label: "Write outreach" },
    { id: "assets",     label: "Linkable assets" },
    { id: "article",    label: "Write the article" },
    { id: "competitor", label: "Competitor check" },
  ];
  const [mode, setMode] = useState("find");

  const [biz, setBiz] = useState("");
  const [city, setCity] = useState("");
  const [niche, setNiche] = useState("");
  const [site, setSite] = useState("");
  const [targetName, setTargetName] = useState("");
  const [outreachType, setOutreachType] = useState("Guest post pitch");
  const [offer, setOffer] = useState("");
  const [tone, setTone] = useState("Warm & professional");
  const [competitor, setCompetitor] = useState("");
  const [artTopic, setArtTopic] = useState("");
  const [artLen, setArtLen] = useState("1200");

  const [result, setResult] = useState("");
  const [loading, setLoading] = useState(false);
  const [err, setErr] = useState("");

  function guard(fn) { if (locked) { try { onUpgrade(); } catch (e) {} return; } fn(); }

  async function run(prompt, searchOn) {
    setErr(""); setLoading(true); setResult("");
    try {
      try { onToolUse("authority_builder", 0); } catch (e) {}
      const out = await callClaude(ctxPre + prompt, 5000, !!searchOn);
      setResult(out || "");
    } catch (e) {
      setErr("Something went wrong. Please try again.");
    }
    setLoading(false);
  }

  function genFind() {
    if (!biz.trim()) return;
    const p = "You are an expert white-hat SEO and local link-building strategist. Use web search to find REAL, currently-existing places where this business could earn a legitimate backlink or citation — links Google rewards that also build the brand and audience." + WHITE_HAT +
      "\n\nBusiness: " + biz +
      "\nLocation: " + (city.trim() || "not specified — note that adding a city gives far better local results") +
      "\nIndustry / niche: " + (niche.trim() || "not specified") +
      (site.trim() ? ("\nWebsite: " + site.trim()) : "") +
      "\n\nReturn a prioritized markdown list of 8–12 specific, real opportunities. For EACH: the name (and URL if known), the type (directory / chamber / local press / association / resource page / partnership / guest post / podcast), one line on why it fits, and a one-line 'how to get listed or pitch' action. Group them under: ## Quick wins, ## Local authority, and ## Editorial & PR. End with a short note on focusing on relevance and real editorial placements and avoiding bought links.";
    run(p, true);
  }
  function genOutreach() {
    if (!targetName.trim() || !biz.trim()) return;
    const p = "You are an expert outreach copywriter. Write a concise, personable, high-converting outreach message to earn a legitimate backlink or feature. Warm and specific, never spammy; lead with value; make the ask easy and low-pressure." +
      "\n\nType of outreach: " + outreachType +
      "\nTarget site / person: " + targetName +
      "\nMy business: " + biz +
      "\nWhat I can offer them / my angle: " + (offer.trim() || "(none given — infer a genuine value angle)") +
      "\nTone: " + tone +
      "\n\nReturn a subject line (if it's an email) and the message body, ready to paste and lightly personalize. Keep it short and human. Then add 2 quick follow-up tips.";
    run(p, false);
  }
  function genArticle() {
    if (!artTopic.trim() || !biz.trim()) return;
    const p = "You are a skilled ghostwriter writing a GUEST ARTICLE that will be published on someone else's website. " +
      "This is the article itself \u2014 not a pitch. It must be good enough that the host site is glad they ran it.\n\n" +
      "RULES:\n" +
      "- Genuinely useful and specific. Real advice, real examples, real numbers where you can.\n" +
      "- Write for THEIR audience, not yours. Do not make it an advert for my business.\n" +
      "- Self-promotion belongs in ONE place only: a short author bio at the very end, with a single natural link back to my site.\n" +
      "- No fluff intros ('In today's fast-paced world...'). Start with something worth reading.\n" +
      "- Use clear H2 subheadings. Include a title and a 1-sentence summary at the top.\n" +
      "- Target roughly " + artLen + " words.\n\n" +
      "PUBLICATION / BLOG: " + (targetName.trim() || "(a relevant industry blog)") +
      "\nARTICLE TOPIC: " + artTopic +
      "\nMY BUSINESS (for the author bio only): " + biz +
      (site.trim() ? ("\nMY SITE (for the one bio link): " + site) : "") +
      (niche.trim() ? ("\nMY NICHE: " + niche) : "") +
      "\n\nWrite the full article, then the author bio." +
      "\n\nAfter the article, add a short section titled 'BEFORE YOU SEND' with 3 quick reminders (e.g. match their house style, check their guest-post guidelines, don't over-link).";
    run(p, false);
  }
  function genAssets() {
    if (!biz.trim()) return;
    const p = "You are a content strategist specializing in 'linkable assets' — content so useful that people naturally link to it, which earns white-hat backlinks and grows audience. Suggest 5 linkable-asset ideas tailored to this business. Favor local stat roundups, free templates / checklists / calculators, original mini-surveys, and 'best [thing] in [city]' guides." +
      "\n\nBusiness: " + biz +
      "\nLocation: " + (city.trim() || "not specified") +
      "\nAudience / niche: " + (niche.trim() || "not specified") +
      "\n\nFor EACH idea return: a working title, why it earns links (who would link to it and why), a quick outline, and where to promote it to get noticed. Keep it practical and specific to this business.";
    run(p, true);
  }
  function genCompetitor() {
    if (!competitor.trim()) return;
    const p = "You are an SEO researcher. Use web search to find where a competitor is mentioned, listed, or linked online, so this business can pursue the same legitimate opportunities." + WHITE_HAT +
      "\n\nCompetitor (name or URL): " + competitor +
      "\nMy business / city / niche: " + (biz.trim() || "not specified") + " / " + (city.trim() || "not specified") + " / " + (niche.trim() || "not specified") +
      "\n\nStart with a one-line note that this is a web-search snapshot, not a complete backlink index (a full audit would use a tool like Ahrefs or Semrush). Then return a markdown list of specific places the competitor is featured — with the URL if known, the type, and a one-line 'how to get featured here too'. Be honest when something can't be verified.";
    run(p, true);
  }

  const Label = ({ children }) => (
    <div style={{ fontFamily: "sans-serif", fontSize: 9, fontWeight: 700, letterSpacing: "0.14em", color: B.mid, marginBottom: 7, textTransform: "uppercase" }}>{children}</div>
  );
  const inpStyle = { width: "100%", padding: "10px 12px", border: "1px solid " + B.stone, outline: "none", fontSize: 13, fontFamily: "sans-serif", background: "#fff", color: "#111", marginBottom: 14, boxSizing: "border-box" };
  const selStyle = { ...inpStyle, cursor: "pointer" };

  const canRun = mode === "find" ? biz.trim() : mode === "outreach" ? (targetName.trim() && biz.trim()) : mode === "assets" ? biz.trim() : mode === "article" ? (artTopic.trim() && biz.trim()) : competitor.trim();
  function onGenerate() {
    guard(() => { if (mode === "find") genFind(); else if (mode === "outreach") genOutreach(); else if (mode === "assets") genAssets(); else if (mode === "article") genArticle(); else genCompetitor(); });
  }

  return (
    <div>
      <h2 style={{ fontSize: 20, fontWeight: 400, fontFamily: "Georgia,serif", margin: "0 0 4px" }}>Backlink &amp; Authority Builder</h2>
      <p style={{ fontFamily: "sans-serif", color: B.mid, fontSize: 12, margin: "0 0 6px", letterSpacing: "0.02em" }}>Find real, white-hat ways to get your business linked, listed, and featured — and get the outreach written for you.</p>
      <div style={{ background: B.white, border: "1px solid " + B.stone, padding: "8px 14px", marginBottom: 18, fontFamily: "sans-serif", fontSize: 11, color: B.goldDark, letterSpacing: "0.02em", lineHeight: 1.5 }}>Backlinks are still a top Google ranking signal — but <strong>buying them</strong> breaks Google's rules and can get your site penalized. This tool only finds legitimate, earned opportunities that build both your rankings and your brand.</div>

      {/* Mode tabs */}
      <div style={{ display: "flex", flexWrap: "wrap", gap: 0, marginBottom: 20, borderBottom: "1px solid " + B.stone }}>
        {MODES.map(m => (
          <button key={m.id} onClick={() => { setMode(m.id); setResult(""); setErr(""); }} style={{ background: "none", border: "none", borderBottom: "2px solid " + (mode === m.id ? B.charcoal : "transparent"), color: mode === m.id ? B.charcoal : B.mid, padding: "10px 14px", fontFamily: "sans-serif", fontSize: 12, fontWeight: mode === m.id ? 700 : 500, letterSpacing: "0.02em", cursor: "pointer", marginBottom: -1 }}>{m.label}</button>
        ))}
      </div>

      <Card style={{ padding: "22px", marginBottom: 14 }}>
        {mode === "find" && (
          <>
            <Label>Your business</Label>
            <input value={biz} onChange={e => setBiz(e.target.value)} placeholder="e.g. Tampa knotless braids salon, handmade candle shop" style={inpStyle} />
            <Label>City / location</Label>
            <input value={city} onChange={e => setCity(e.target.value)} placeholder="e.g. Tampa, FL" style={inpStyle} />
            <Label>Industry / niche · optional</Label>
            <input value={niche} onChange={e => setNiche(e.target.value)} placeholder="e.g. hair & beauty, home décor" style={inpStyle} />
            <Label>Website · optional</Label>
            <input value={site} onChange={e => setSite(e.target.value)} placeholder="yourbusiness.com" style={inpStyle} />
          </>
        )}
        {mode === "outreach" && (
          <>
            <Label>Outreach type</Label>
            <select value={outreachType} onChange={e => setOutreachType(e.target.value)} style={selStyle}>
              {["Guest post pitch", "Link insertion request", "Feature / 'best of' request", "Partnership / collaboration", "Journalist / HARO response", "Local press pitch"].map(o => <option key={o}>{o}</option>)}
            </select>
            <Label>Who you're reaching out to</Label>
            <input value={targetName} onChange={e => setTargetName(e.target.value)} placeholder="e.g. Tampa Bay Moms blog, editor at LocalEats" style={inpStyle} />
            <Label>Your business</Label>
            <input value={biz} onChange={e => setBiz(e.target.value)} placeholder="e.g. handmade candle shop" style={inpStyle} />
            <Label>What you can offer them / your angle · optional</Label>
            <textarea value={offer} onChange={e => setOffer(e.target.value)} rows={2} placeholder="e.g. a free sample, an exclusive local discount for their readers, an original guest article" style={{ ...inpStyle, resize: "vertical", lineHeight: 1.6 }} />
            <Label>Tone</Label>
            <select value={tone} onChange={e => setTone(e.target.value)} style={selStyle}>
              {["Warm & professional", "Friendly & casual", "Confident & direct", "Playful"].map(o => <option key={o}>{o}</option>)}
            </select>
          </>
        )}
        {mode === "assets" && (
          <>
            <Label>Your business</Label>
            <input value={biz} onChange={e => setBiz(e.target.value)} placeholder="e.g. Tampa knotless braids salon" style={inpStyle} />
            <Label>City / location · optional</Label>
            <input value={city} onChange={e => setCity(e.target.value)} placeholder="e.g. Tampa, FL" style={inpStyle} />
            <Label>Audience / niche · optional</Label>
            <input value={niche} onChange={e => setNiche(e.target.value)} placeholder="e.g. busy moms, local brides" style={inpStyle} />
          </>
        )}
        {mode === "article" && (
          <>
            <div style={{ background:B.white, border:"1px solid "+B.stone, padding:12, marginBottom:12 }}>
              <p style={{ fontFamily:"sans-serif", fontSize:11.5, color:B.mid, lineHeight:1.55, margin:0 }}>
                They said yes? Write the guest post. A good article earns the link — and the relationship. Keep the selling to your author bio.
              </p>
            </div>
            <Label>Article topic</Label>
            <input value={artTopic} onChange={e => setArtTopic(e.target.value)} placeholder="e.g. 5 ways small salons can fill slow weekdays" style={inpStyle} />
            <Label>Publishing on · optional</Label>
            <input value={targetName} onChange={e => setTargetName(e.target.value)} placeholder="e.g. Salon Today, or the blog's name" style={inpStyle} />
            <Label>Your business — for the author bio</Label>
            <input value={biz} onChange={e => setBiz(e.target.value)} placeholder="e.g. Bloom Salon, Tampa" style={inpStyle} />
            <Label>Your website · optional — the one link back</Label>
            <input value={site} onChange={e => setSite(e.target.value)} placeholder="e.g. bloomsalon.com" style={inpStyle} />
            <Label>Length</Label>
            <select value={artLen} onChange={e => setArtLen(e.target.value)} style={inpStyle}>
              <option value="800">Short — ~800 words</option>
              <option value="1200">Standard — ~1,200 words</option>
              <option value="1800">In-depth — ~1,800 words</option>
            </select>
          </>
        )}
        {mode === "competitor" && (
          <>
            <Label>Competitor name or website</Label>
            <input value={competitor} onChange={e => setCompetitor(e.target.value)} placeholder="e.g. rivalsalon.com or 'Rival Salon Tampa'" style={inpStyle} />
            <Label>Your business · optional</Label>
            <input value={biz} onChange={e => setBiz(e.target.value)} placeholder="e.g. your salon name" style={inpStyle} />
            <Label>City / niche · optional</Label>
            <input value={city} onChange={e => setCity(e.target.value)} placeholder="e.g. Tampa, FL · hair & beauty" style={inpStyle} />
          </>
        )}

        <Btn dark disabled={loading || !canRun} onClick={onGenerate}>
          {loading ? "WORKING..." : mode === "find" ? "FIND OPPORTUNITIES" : mode === "outreach" ? "WRITE MY OUTREACH" : mode === "assets" ? "GENERATE IDEAS" : "CHECK COMPETITOR"}
        </Btn>
        <div style={{ fontFamily: "sans-serif", fontSize: 11, color: B.mid, marginTop: 10 }}>Free to run · uses live web search for real, current opportunities.</div>
      </Card>

      {loading && <div style={{ background: B.offwhite, border: "1px solid " + B.stone, padding: "36px", textAlign: "center", fontFamily: "sans-serif", fontSize: 12, color: B.mid, letterSpacing: "0.04em" }}>{mode === "find" || mode === "competitor" ? "Searching the web for real opportunities... (10–20 seconds)" : "Writing... (a few seconds)"}</div>}
      {err && <div style={{ background: "#FEF2F2", border: "1px solid #FECACA", padding: "12px 16px", fontFamily: "sans-serif", fontSize: 12, color: B.red }}>{err}</div>}
      {result && !loading && (
        <div style={{ background: B.offwhite, border: "1px solid " + B.stone, padding: "22px" }}>
          <div style={{ fontSize: 9, color: B.gold, fontFamily: "sans-serif", fontWeight: 700, letterSpacing: "0.18em", marginBottom: 14, textTransform: "uppercase" }}>{mode === "outreach" ? "Your outreach message" : mode === "assets" ? "Your linkable-asset ideas" : "Your opportunities"}</div>
          <Md text={result} />
        </div>
      )}
    </div>
  );
}

function UGCStudio({ onBalance, useCredits, onToolUse, user }) {
  const [tab, setTab] = useState("character");
  const [startImg, setStartImg] = useState(null);
  return (
    <div>
      <h2 style={{fontSize:20,fontWeight:400,fontFamily:"Georgia,serif",margin:"0 0 4px"}}>UGC Studio</h2>
      <p style={{fontFamily:"sans-serif",color:B.mid,fontSize:12,margin:"0 0 18px",letterSpacing:"0.02em"}}>Build a consistent UGC creator, then bring any shot to life as a video — powered by Seedance 2.0.</p>
      <div style={{display:"flex",gap:0,marginBottom:18,borderBottom:"1px solid "+B.stone}}>
        <Tb label="Character" active={tab==="character"} onClick={()=>setTab("character")} />
        <Tb label="Video" active={tab==="video"} onClick={()=>setTab("video")} />
      </div>
      {tab==="character" && <UGCCharacter onBalance={onBalance} onUseInVideo={(img)=>{ setStartImg(img); setTab("video"); }} />}
      {tab==="video" && <UGCVideoMaker startImg={startImg} useCredits={useCredits} onBalance={onBalance} onToolUse={onToolUse} user={user} />}
    </div>
  );
}

function UGCVideoMaker({ startImg, useCredits, onBalance, onToolUse, user }) {
  const [prompt, setPrompt] = useState("");
  const [photo, setPhoto] = useState(startImg || null);
  const [orient, setOrient] = useState("portrait");
  const [dur, setDur] = useState("5");
  const [busy, setBusy] = useState(false);
  const [url, setUrl] = useState("");
  const [err, setErr] = useState("");
  const [status, setStatus] = useState("");
  const [saveMsg, setSaveMsg] = useState("");
  const [pw, setPw] = useState(false);
  const [refClip, setRefClip] = useState(null);
  const [refFrame, setRefFrame] = useState(null);
  const [refBusy, setRefBusy] = useState(false);
  useEffect(()=>{ if(startImg) setPhoto(startImg); }, [startImg]);
  const [vmodel, setVmodel] = useState("veolite");   // default to the affordable tier
  const UGC_MODELS = [
    { id:"omni",       label:"Omni Flash \u2014 near-Seedance, way cheaper", flat:CREDIT_COSTS.omniClip,   note:"Google's newest. Up to 10s, 720p." },
    { id:"veolite",    label:"Veo 3.1 Lite \u2014 fast & affordable",      per:CREDIT_COSTS.veoLiteSec,  note:"Great for volume. Most UGC looks great here." },
    { id:"seedance480",  label:"Seedance 2.0 \u2014 480p, fast & cheap",   per:CREDIT_COSTS.seedance480Sec,  note:"Cheapest Seedance. Great for volume." },
    { id:"seedance720",  label:"Seedance 2.0 \u2014 720p HD",             per:CREDIT_COSTS.seedance720Sec,  note:"HD detail at a lower cost." },
    { id:"seedance1080", label:"Seedance 2.0 \u2014 1080p Full HD",       per:CREDIT_COSTS.seedance1080Sec, note:"Full-HD product detail." },
    { id:"seedance4k",   label:"Seedance 2.0 \u2014 4K, best product detail", per:CREDIT_COSTS.seedanceSec, note:"Highest fidelity for product shots. Slowest & priciest." },
    { id:"veo",        label:"Veo 3.1 Cinematic \u2014 hero shots",         per:CREDIT_COSTS.veoSec,      note:"Top-tier realism. Use for your best clip." },
  ];
  function curModel(){ return UGC_MODELS.find(m=>m.id===vmodel) || UGC_MODELS[0]; }
  const DUR = [5, 10, 15];
  function cost(){ const m=curModel(); return m.flat ? m.flat : m.per * Number(dur); }
  function onUpload(e){ const f=e.target.files&&e.target.files[0]; if(!f) return; const r=new FileReader(); r.onload=()=>setPhoto(r.result); r.readAsDataURL(f); e.target.value=""; }
  async function gen(){
    if(!prompt.trim() && !photo){ setErr("Add a creator photo or describe the video."); return; }
    if(!useCredits(cost())) return;
    track("tool_used",{tool:"ugc_video",model:vmodel}); onToolUse("ugc_video",cost());
    setBusy(true); setUrl(""); setErr(""); setStatus("Starting the video engine…");
    try{
      const p = prompt.trim() || "Bring this UGC creator photo to life with subtle, natural movement — as if they are filming themselves talking to the camera. Realistic, handheld, authentic user-generated-content feel.";
      const started = await generateVideo(p, photo||undefined, {orientation:orient, quality:vmodel, duration:Number(dur), audio:true, tool:"ugc"});
      if(!started||!started.id){ setErr("Sorry — we couldn't start that video right now. Please try again in a little while."); setBusy(false); setStatus(""); return; }
      if(typeof started.balance==="number") onBalance(started.balance);
      setStatus("Creating your video with "+curModel().label.split(" \u2014 ")[0]+" — this can take a few minutes. Keep this tab open.");
      const out = await pollVideo(started.id);
      if(!out){ setErr("The video didn't finish in time. Your credits were refunded."); if(typeof started.balance==="number") onBalance(started.balance+cost()); setBusy(false); setStatus(""); return; }
      setUrl(out); setStatus("");
    }catch(e){ setErr("Something went wrong while generating the video. Please try again."); }
    setBusy(false);
  }
  async function save(){ if(!url) return; setSaveMsg("Saving…"); const r=await saveToLibrary(user,"video","UGC Video",url); setSaveMsg(r.ok?"✓ Saved to your Library":("Couldn't save: "+(r.error||"error"))); setTimeout(()=>setSaveMsg(""),4000); }
  function dl(){ downloadVideo(url,"ugc-video.mp4"); }
  function grabFrame(src){
    return new Promise((resolve,reject)=>{
      const v=document.createElement("video");
      v.muted=true; v.playsInline=true; v.preload="auto";
      v.onloadeddata=()=>{ try{ v.currentTime=Math.min(1,(v.duration||2)/3); }catch(e){ resolve(null); } };
      v.onseeked=()=>{ try{ const c=document.createElement("canvas"); c.width=v.videoWidth||720; c.height=v.videoHeight||1280; c.getContext("2d").drawImage(v,0,0,c.width,c.height); resolve(c.toDataURL("image/jpeg",0.85)); }catch(e){ reject(e); } };
      v.onerror=()=>reject(new Error("video")); v.src=src;
    });
  }
  function loadImg(src){ return new Promise((res,rej)=>{ const im=new Image(); im.onload=()=>res(im); im.onerror=rej; im.src=src; }); }
  async function buildVisionImage(){
    if(refFrame && photo){
      try{
        const [a,b]=await Promise.all([loadImg(photo),loadImg(refFrame)]);
        const H=512; const wa=Math.max(64,Math.round(H*(a.width/a.height))||384); const wb=Math.max(64,Math.round(H*(b.width/b.height))||384);
        const c=document.createElement("canvas"); c.width=wa+wb+12; c.height=H; const ctx=c.getContext("2d");
        ctx.fillStyle="#ffffff"; ctx.fillRect(0,0,c.width,c.height);
        ctx.drawImage(a,0,0,wa,H); ctx.drawImage(b,wa+12,0,wb,H);
        return c.toDataURL("image/jpeg",0.85);
      }catch(e){ return photo; }
    }
    return refFrame || photo || null;
  }
  function onRefUpload(e){
    const f=e.target.files&&e.target.files[0]; if(!f) return;
    const r=new FileReader();
    r.onload=async()=>{ const src=r.result; setRefClip(src); setRefFrame(null); setRefBusy(true); try{ const fr=await grabFrame(src); if(fr) setRefFrame(fr); }catch(err){} setRefBusy(false); };
    r.readAsDataURL(f); e.target.value="";
  }
  async function writePrompt(){
    if(pw) return;
    setPw(true);
    try{
      const vis = await buildVisionImage();
      const seeNote = (refFrame && photo)
        ? " Two images are attached SIDE BY SIDE: the LEFT image is the exact creator to keep (their face, hair, outfit — never change them); the RIGHT image is a frame from a reference clip showing the scene, action and vibe. Base the movement, action and camera feel on the RIGHT reference, while keeping the LEFT creator's identity intact."
        : refFrame
          ? " A frame from a reference clip is attached — study the scene, action, framing and vibe in it, and base the movement and camera feel on what you see."
          : photo
            ? " A REFERENCE PHOTO of the exact creator is attached — study it closely and keep the prompt TRUE to that same person: their face, hair, outfit and vibe. Do not restyle or change who they are; only describe natural motion and an action that fits them." : "";
      const brief = "You are a UGC (user-generated content) video director. Write ONE short video prompt for an AI video generator (Seedance) that animates a still photo of a real content creator into an authentic, handheld, talking-to-camera clip."
        + seeNote + " "
        + (prompt.trim() ? ("Base it on this idea: " + prompt.trim() + ". ") : "")
        + "Describe the creator's natural movement and expression, ONE simple action (like holding a product up or gesturing), and the camera feel (handheld phone front camera). Keep it 2-3 sentences, concrete and filmable. No hashtags, no quoted dialogue, no headings — just the visual prompt.";
      const out = await callClaude(brief, 400, false, vis);
      if(out && out.trim() && !/^(Unable to generate|Something went wrong)/.test(out)) setPrompt(out.trim());
    }catch(e){}
    setPw(false);
  }
  return (
    <div>
      <Card style={{padding:"22px",marginBottom:14}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",gap:8,flexWrap:"wrap",marginBottom:12}}>
          <span style={{display:"inline-block",background:B.charcoal,color:"#fff",fontFamily:"sans-serif",fontSize:9,fontWeight:700,letterSpacing:"0.12em",textTransform:"uppercase",padding:"5px 10px"}}>{curModel().label.split(" \u2014 ")[0]}</span>
          <CreditTag n={cost()} />
        </div>
        <div style={{fontFamily:"sans-serif",fontSize:9,fontWeight:700,letterSpacing:"0.14em",color:B.mid,marginBottom:7,textTransform:"uppercase"}}>Creator photo</div>
        {photo
          ? <div style={{position:"relative",display:"inline-block",border:"1px solid "+B.gold,padding:3,background:B.white,marginBottom:10}}>
              <img src={photo} alt="Creator" style={{width:88,height:110,objectFit:"cover",display:"block"}} />
              <button onClick={()=>setPhoto(null)} style={{position:"absolute",top:-8,right:-8,width:20,height:20,borderRadius:"50%",background:B.charcoal,color:"#fff",border:"none",cursor:"pointer",fontSize:11,lineHeight:"18px",padding:0}}>×</button>
            </div>
          : <label style={{display:"block",border:"1px dashed "+B.stone,background:B.white,padding:"16px",textAlign:"center",cursor:"pointer",fontFamily:"sans-serif",fontSize:12,color:B.goldDark,letterSpacing:"0.02em",marginBottom:10}}>Tap to upload a creator shot — or make one in the Character tab and hit “Use in video”<input type="file" accept="image/*" onChange={onUpload} style={{display:"none"}} /></label>}
        <div style={{fontFamily:"sans-serif",fontSize:9,fontWeight:700,letterSpacing:"0.14em",color:B.mid,margin:"4px 0 7px",textTransform:"uppercase"}}>Describe the video (optional)</div>
        <St value={prompt} onChange={e=>setPrompt(e.target.value)} placeholder="e.g. She smiles, waves at the camera, then holds the product up next to her face…" rows={3} />
        {refClip ? (
          <div style={{display:"flex",alignItems:"center",gap:10,margin:"8px 0 2px"}}>
            <video src={refClip} muted playsInline preload="metadata" style={{width:60,height:76,objectFit:"cover",border:"1px solid "+B.gold,background:"#000"}} />
            <div style={{flex:1}}>
              <div style={{fontFamily:"sans-serif",fontSize:10.5,color:B.charcoal,fontWeight:700}}>Reference clip added{refBusy?" — reading a frame…":(refFrame?" ✓":"")}</div>
              <div style={{fontFamily:"sans-serif",fontSize:9.5,color:B.mid,lineHeight:1.45,marginTop:2}}>Helps Claude picture the scene &amp; action for your prompt. (Matching the actual motion in the video is coming soon.)</div>
            </div>
            <button onClick={()=>{ setRefClip(null); setRefFrame(null); }} style={{background:"none",border:"1px solid "+B.stone,color:B.mid,padding:"5px 9px",fontFamily:"sans-serif",fontSize:9,fontWeight:700,cursor:"pointer",textTransform:"uppercase"}}>Remove</button>
          </div>
        ) : (
          <label style={{display:"block",border:"1px dashed "+B.stone,background:B.white,padding:"10px 12px",textAlign:"center",cursor:"pointer",fontFamily:"sans-serif",fontSize:11,color:B.goldDark,margin:"8px 0 2px"}}>+ Add a reference clip (optional) — lets Claude see the scene<input type="file" accept="video/*" onChange={onRefUpload} style={{display:"none"}} /></label>
        )}
        <div style={{display:"flex",alignItems:"center",gap:10,margin:"8px 0 2px",flexWrap:"wrap"}}>
          <button onClick={writePrompt} disabled={pw} style={{background:pw?B.stone:B.charcoal,color:"#fff",border:"none",padding:"8px 14px",fontFamily:"sans-serif",fontSize:10,letterSpacing:"0.1em",fontWeight:700,cursor:pw?"default":"pointer",textTransform:"uppercase"}}>{pw?"Writing…":"✨ Write this with Claude"}</button>
          <span style={{fontFamily:"sans-serif",fontSize:10.5,color:B.mid}}>Claude reads your creator photo &amp; reference clip (when added) and writes a prompt true to them.</span>
        </div>
        <details style={{margin:"4px 0 2px",fontFamily:"sans-serif"}}>
          <summary style={{fontSize:10.5,color:B.goldDark,cursor:"pointer",letterSpacing:"0.04em",fontWeight:700}}>How to get the best UGC result →</summary>
          <ol style={{fontSize:11,color:B.mid,lineHeight:1.65,margin:"8px 0 0",paddingLeft:18}}>
            <li>Make your creator in the <strong>Character</strong> tab first, then tap “Use in video” so the same face carries over.</li>
            <li>Tap <strong>✨ Write this with Claude</strong> — or type one plain sentence about what should happen (a wave, holding your product, a reaction).</li>
            <li>Keep it to <strong>one simple action</strong> per clip; short, calm movement looks far more real than a busy scene.</li>
            <li>Pick <strong>Portrait (9:16)</strong> for TikTok &amp; Reels, and start at <strong>5 seconds</strong>.</li>
            <li>Generate a few and keep the most natural one — that’s normal for UGC.</li>
          </ol>
        </details>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginTop:14}}>
          <Fl label="Orientation"><Ss value={orient} onChange={e=>setOrient(e.target.value)}><option value="portrait">Portrait (9:16)</option><option value="landscape">Landscape (16:9)</option><option value="square">Square (1:1)</option></Ss></Fl>
          <Fl label="Length"><Ss value={dur} onChange={e=>setDur(e.target.value)}>{DUR.map(s=><option key={s} value={String(s)}>{s} seconds</option>)}</Ss></Fl>
        </div>
        <div style={{marginTop:12}}>
          <Fl label="Video engine"><Ss value={vmodel} onChange={e=>setVmodel(e.target.value)}>{UGC_MODELS.map(m=><option key={m.id} value={m.id}>{m.label}</option>)}</Ss></Fl>
        </div>
        <p style={{fontFamily:"sans-serif",fontSize:10.5,color:B.mid,lineHeight:1.5,margin:"6px 0 14px"}}>{curModel().note} <strong>{curModel().flat ? curModel().flat.toLocaleString()+" credits (up to 10s)" : curModel().per.toLocaleString()+" credits per second"}</strong> — this clip: <strong>{cost().toLocaleString()} credits</strong>.</p>
        <Btn dark disabled={busy||(!prompt.trim()&&!photo)} onClick={gen}>{busy?"GENERATING VIDEO...":("GENERATE VIDEO ("+cost().toLocaleString()+" credits)")}</Btn>
      </Card>
      {busy&&<div style={{background:B.offwhite,border:"1px solid "+B.stone,padding:"22px",textAlign:"center"}}><div style={{fontFamily:"sans-serif",fontSize:12,color:B.mid,letterSpacing:"0.02em",lineHeight:1.6}}>{status||"Working..."}</div></div>}
      {err&&!busy&&<div style={{background:"#FBEAEA",border:"1px solid #E0B4B4",padding:"16px"}}><div style={{fontFamily:"sans-serif",fontSize:12,color:"#9B2C2C",letterSpacing:"0.02em"}}>{err}</div></div>}
      {url&&!busy&&<div style={{background:B.offwhite,border:"1px solid "+B.stone,padding:"20px"}}><div style={{fontSize:9,color:B.gold,fontFamily:"sans-serif",fontWeight:700,letterSpacing:"0.18em",marginBottom:14,textTransform:"uppercase"}}>Your UGC Video</div><video src={url} controls playsInline style={{maxWidth:"100%",display:"block",marginBottom:12,background:"#000"}} /><Btn dark small onClick={dl}>DOWNLOAD VIDEO</Btn> <button onClick={save} style={{marginLeft:8,background:"#fff",border:"1px solid "+B.stone,color:B.charcoal,padding:"9px 14px",fontFamily:"sans-serif",fontSize:10,letterSpacing:"0.1em",fontWeight:700,cursor:"pointer",textTransform:"uppercase"}}>♥ Save to Library</button>{saveMsg&&<div style={{fontFamily:"sans-serif",fontSize:11,color:saveMsg.charAt(0)==="✓"?"#2E7D32":B.mid,marginTop:10}}>{saveMsg}</div>}<div style={{marginTop:14}}><ShareBar url={url} file={url} filename="chelgy-ugc-video.mp4" title="Made with Chelgy" text="" /></div></div>}
    </div>
  );
}

function StoreBuilderTab({ user }) {
  const [niche, setNiche] = useState("");
  const [shop, setShop] = useState("");
  const [busy, setBusy] = useState(false);
  const [err, setErr] = useState("");
  const [prodList, setProdList] = useState([]);
  const [picks, setPicks] = useState({});
  const [prodLoad, setProdLoad] = useState(false);
  const [prodErr, setProdErr] = useState("");
  const [imaging, setImaging] = useState(false);
  const [imgDone, setImgDone] = useState(0);
  const [imgTotal, setImgTotal] = useState(0);
  const [result, setResult] = useState(() => {
    try { return new URLSearchParams(window.location.search).get("store") || ""; } catch (e) { return ""; }
  });
  useEffect(() => {
    if (result) {
      try {
        const u = new URL(window.location.href);
        u.searchParams.delete("store");
        window.history.replaceState({}, "", u.pathname + u.search);
      } catch (e) {}
    }
  }, []);

  const normShop = (raw) => {
    let v = String(raw || "").trim().toLowerCase().replace(/^https?:\/\//, "");
    const m = v.match(/admin\.shopify\.com\/store\/([a-z0-9-]+)/); // new admin URL form
    if (m) return m[1] + ".myshopify.com";
    v = v.replace(/\/.*$/, ""); // drop any path
    if (/^[a-z0-9][a-z0-9-]*$/.test(v)) v = v + ".myshopify.com"; // bare handle
    return v;
  };
  const cleanShop = normShop(shop);
  const normOk = /^[a-z0-9][a-z0-9-]*\.myshopify\.com$/.test(cleanShop);
  const canConnect = !!niche && normOk && !busy;

  const connect = async () => {
    setErr("");
    setBusy(true);
    try {
      const tok = await freshToken();
      if (!tok) { setErr("Please log in again."); setBusy(false); return; }
      const res = await fetch("/api/shopify-connect", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ access_token: tok, niche, shop: cleanShop, products: Object.values(picks) }),
      });
      const data = await res.json().catch(() => ({}));
      if (!res.ok || !data.url) { setErr(data.error || "Couldn't start the connection."); setBusy(false); return; }
      window.location.href = data.url;
    } catch (e) {
      setErr("Something went wrong. Try again.");
      setBusy(false);
    }
  };

  const pickNiche = (id) => { setNiche(id); setProdList([]); setPicks({}); setProdErr(""); };
  const loadProducts = async () => {
    setProdErr(""); setProdLoad(true);
    try {
      const tok = await freshToken();
      if (!tok) { setProdErr("Please log in again."); setProdLoad(false); return; }
      const res = await fetch("/api/store-products", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ access_token: tok, niche }) });
      const data = await res.json().catch(() => ({}));
      if (!res.ok || !data.products) { setProdErr(data.error || "Could not load products."); setProdLoad(false); return; }
      setProdList(data.products); setProdLoad(false);
    } catch (e) { setProdErr("Something went wrong."); setProdLoad(false); }
  };
  const togglePick = (p) => setPicks((m) => { const n = Object.assign({}, m); if (n[p.id]) { delete n[p.id]; } else { n[p.id] = p; } return n; });
  const pickCount = Object.keys(picks).length;
  const makePhotos = async () => {
    const sel = Object.values(picks);
    if (!sel.length || imaging) return;
    setImaging(true); setImgDone(0); setImgTotal(sel.length); setProdErr("");
    let updated = Object.assign({}, picks);
    for (let i = 0; i < sel.length; i++) {
      const p = sel[i];
      try {
        const promptTxt = p.img || ("clean high-end studio product photo of " + p.name + ", soft lighting, premium e-commerce look, plain neutral background");
        const d = await generateGeminiImage(promptTxt, [], "1:1", "standard");
        if (d && d.image) {
          const path = (user && user.id ? user.id : "store") + "/store-" + p.id + "-" + Date.now() + ".png";
          const url = await uploadSiteImage(d.image, path);
          if (url) { updated = Object.assign({}, updated, { [p.id]: Object.assign({}, updated[p.id], { image: url }) }); setPicks(updated); }
        }
      } catch (e) {}
      setImgDone(i + 1);
    }
    setImaging(false);
  };

  const H = ({ children }) => (
    <h2 style={{ fontSize: 24, fontWeight: 400, fontFamily: "Georgia,serif", margin: "0 0 6px", lineHeight: 1.25, color: B.charcoal }}>{children}</h2>
  );
  const Sub = ({ children }) => (
    <div style={{ fontFamily: "sans-serif", fontSize: 13, color: B.mid, lineHeight: 1.5, marginBottom: 22 }}>{children}</div>
  );
  const StepCard = ({ n, title, done, active, children }) => (
    <div style={{ background: active ? B.white : B.offwhite, border: "1px solid " + (active ? B.charcoal : B.stone), borderRadius: 4, padding: 18, marginBottom: 12, opacity: active || done ? 1 : 0.55 }}>
      <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: children ? 14 : 0 }}>
        <div style={{ width: 24, height: 24, borderRadius: "50%", flexShrink: 0, display: "flex", alignItems: "center", justifyContent: "center", background: done ? B.green : "none", border: done ? "none" : "1.5px " + (active ? "solid" : "dashed") + " " + (active ? B.charcoal : B.mid), color: "#fff", fontFamily: "sans-serif", fontSize: 12, fontWeight: 700 }}>
          {done ? "✓" : <span style={{ color: active ? B.charcoal : B.mid }}>{n}</span>}
        </div>
        <div style={{ fontFamily: "sans-serif", fontSize: 14, fontWeight: 700, color: B.charcoal }}>{title}</div>
      </div>
      {children && <div style={{ paddingLeft: 36 }}>{children}</div>}
    </div>
  );

  if (result) {
    const good = result === "ready";
    const partial = result === "partial";
    return (
      <div>
        <div style={{ width: 32, height: 1, background: "#B8955A", marginBottom: 18 }} />
        <H>{good ? "Your store is stocked." : partial ? "Almost there." : "That didn't finish."}</H>
        <Sub>
          {good && "Products, pages, and a collection are in your Shopify store. Log into your Shopify admin to see it, add your branding, and set it live."}
          {partial && "Your store connected and most of it built, but a couple of items didn't load. Head to your Shopify admin to check, or reach out and we'll finish it."}
          {!good && !partial && "The connection didn't complete. Double-check your store URL and try connecting again."}
        </Sub>
        <button onClick={() => setResult("")} style={{ padding: "12px 20px", background: B.charcoal, color: "#fff", border: "none", borderRadius: 2, fontFamily: "sans-serif", fontSize: 13, fontWeight: 700, letterSpacing: "0.02em", cursor: "pointer" }}>
          {good ? "Build another" : "Try again"}
        </button>
      </div>
    );
  }

  return (
    <div>
      <div style={{ width: 32, height: 1, background: "#B8955A", marginBottom: 18 }} />
      <H>Build your own store.</H>
      <Sub>Your own branded store, hosted on Chelgy. Customers pay you directly through Stripe, every order lands in your dashboard, and you fulfill with any supplier you like — no Shopify, no middleman taking a cut.</Sub>

      <WinningProductFinder />

      <div style={{ background: B.white, border: "1px solid " + B.stone, borderRadius: 4, padding: 20, marginBottom: 18 }}>
        <div style={{ fontFamily: "Georgia,serif", fontSize: 18, color: B.charcoal, marginBottom: 16 }}>How your store works</div>
        {[
          ["1", "Build your store & add products", "Open the Website tool to create your store, then add your products and prices in its Products tab. Your store gets a shareable link (and your own domain if you want one)."],
          ["2", "Connect Stripe to get paid", "In the Products tab, connect your Stripe account. Every sale is paid straight into your own Stripe — Chelgy only takes a small platform fee per order."],
          ["3", "Sell — customers check out on your site", "Shoppers add products to a cart and pay securely through Stripe, right on your store. No Shopify account needed, ever."],
          ["4", "Fulfill each order", "Every paid order shows up in your Orders tab with the customer's shipping address. Place the order with your supplier, then mark it shipped with a tracking number."],
        ].map(([n, t, d]) => (
          <div key={n} style={{ display: "flex", gap: 12, marginBottom: 15 }}>
            <div style={{ width: 24, height: 24, flexShrink: 0, borderRadius: "50%", background: "#B8955A", color: "#fff", display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "sans-serif", fontSize: 12, fontWeight: 700 }}>{n}</div>
            <div>
              <div style={{ fontFamily: "sans-serif", fontSize: 13.5, fontWeight: 700, color: B.charcoal }}>{t}</div>
              <div style={{ fontFamily: "sans-serif", fontSize: 12, color: B.mid, lineHeight: 1.5, marginTop: 3 }}>{d}</div>
            </div>
          </div>
        ))}
      </div>

      <div style={{ background: B.offwhite, border: "1px solid " + B.stone, borderRadius: 4, padding: 20 }}>
        <div style={{ fontFamily: "Georgia,serif", fontSize: 18, color: B.charcoal, marginBottom: 8 }}>Sourcing &amp; fulfillment with CJdropshipping <span style={{ fontFamily: "sans-serif", fontSize: 9, fontWeight: 700, letterSpacing: "0.1em", textTransform: "uppercase", color: B.mid, border: "1px solid " + B.stone, padding: "3px 7px", borderRadius: 20, verticalAlign: "middle", marginLeft: 6 }}>Optional</span></div>
        <div style={{ fontFamily: "sans-serif", fontSize: 13, color: B.mid, lineHeight: 1.6, marginBottom: 14 }}>
          Need a supplier that actually stocks and ships your products? Create a free <strong>CJdropshipping</strong> account. CJ is a real supplier with 50+ global warehouses — it holds inventory and ships orders itself, and sources from AliExpress when a product isn't in its catalog. It's <strong>free to join with no monthly fee</strong> — you only pay per order. When a sale comes in on your Chelgy store, place the order with CJ, then paste the tracking back into your Orders tab.
        </div>
        <div style={{ fontFamily: "sans-serif", fontSize: 11, fontWeight: 700, letterSpacing: "0.08em", textTransform: "uppercase", color: "#B8955A", marginBottom: 8 }}>Step 1 &middot; Create a free CJ account</div>
        <a href="https://www.cjdropshipping.com/register.html?token=4c381321-2ac5-4821-bd64-243b8e67b04f" target="_blank" rel="noopener noreferrer" style={{ display: "inline-block", padding: "10px 18px", background: B.white, color: B.charcoal, border: "1px solid " + B.charcoal, borderRadius: 2, fontFamily: "sans-serif", fontSize: 13, fontWeight: 700, textDecoration: "none", cursor: "pointer", marginBottom: 22 }}>
          Create your free CJ account &rarr;
        </a>
        <div style={{ fontFamily: "sans-serif", fontSize: 11, fontWeight: 700, letterSpacing: "0.08em", textTransform: "uppercase", color: "#B8955A", marginBottom: 8 }}>Step 2 &middot; Connect it to your store</div>
        <div style={{ fontFamily: "sans-serif", fontSize: 12.5, color: B.mid, lineHeight: 1.6, marginBottom: 12 }}>
          In CJ, open <strong>My CJ &rarr; Authorization &rarr; API</strong> and click <strong>Generate</strong> to create your API Key. Paste it below to link CJ to Chelgy so your orders can be fulfilled through it.
        </div>
        <CJConnect user={user} />
        <div style={{ fontFamily: "sans-serif", fontSize: 11, color: B.mid, lineHeight: 1.6, marginTop: 14, background: B.white, border: "1px solid " + B.stone, borderRadius: 3, padding: "10px 12px" }}>
          <strong style={{ color: B.charcoal }}>Good to know:</strong> Connecting CJ links your account so your store can source and ship through it. Automatic order fulfillment is being rolled out &mdash; for now, when a sale comes in you place the order through CJ (or any supplier &mdash; AliExpress, Amazon, a local one), then mark it shipped with tracking in your Orders tab.
        </div>
      </div>
    </div>
  );
}


