  function completeIntake(d){
    try { localStorage.setItem("chelgy_intake", JSON.stringify(d)); localStorage.setItem("chelgy_intake_done","1"); localStorage.setItem("chelgy_last_greeting", todayStr()); } catch(e){}
    setIntake(d);
    if(d.what && (!myBusiness)) setMyBusiness(d.what);
    if(user && user.id){ (user.access_token?Promise.resolve(user.access_token):freshToken()).then(tok=>{ if(tok) patchMyMember(tok, user.id, { intake: d, onboarded: true }); }).catch(()=>{}); }
    setShowIntake(false);
    generatePlan(d);
  }
  async function generatePlan(d){
    setPlanLoading(true); setShowPlan(true);
    const haveStr = (d.have && d.have.length) ? d.have.join(", ") : "nothing yet";
    const isIdea = d.hasBiz==="idea";
    const stage = d.hasBiz==="running" ? "Has a running business" : d.hasBiz==="starting" ? "Just starting out" : "Just an idea so far";
    const prompt =
`You are Chelgy — a warm, sharp AI business coach speaking directly to a member. Create their personalized business plan and roadmap from the intake answers below.

MEMBER'S ANSWERS
- Stage: ${stage}
- Business or idea: ${d.what||"(not specified)"}
- Field/industry: ${d.field||"(not specified)"}
- Name / website / social: ${d.bizNameSite||"(none given)"}
- Location: ${d.location||"(not specified)"}
- Already set up: ${haveStr}
- #1 goal right now: ${d.goal||"(not specified)"}
- Biggest challenge: ${d.challenge||"(not specified)"}
- Hours per week available: ${d.hours||"(not specified)"}

${`FIRST: Use web search to research their specific situation before writing. `}${d.bizNameSite && !isIdea ? `Look up "${d.bizNameSite}" and their main competitors in ${d.location||"their area"} within the ${d.field||"their"} field, and base your assessment on what you actually find (if you can't find them, say so plainly and assess from what they told you). ` : ``}Also search for where a ${d.field||"business like theirs"} in ${d.location||"their area"} actually gets found, listed, and marketed — the specific directories, listing sites, marketplaces, review platforms, and online communities their type of customer uses to find and book this kind of business. Prefer real, current, named platforms over generic advice.

Write the plan in clean markdown with these exact section headings:

## A note for you
Two warm, encouraging sentences addressed to them.

## Where you stand
${isIdea ? "Their honest starting point and the 2-3 things that matter most to do first." : "What they appear to be doing well and the biggest gaps, based on what you found online and what they told you."}

${!isIdea ? "## How you compare\nName 2-3 real competitors in their field/area and one specific thing each does well that this member could learn from or beat.\n" : ""}
## Your roadmap
A numbered, stage-by-stage list of the highest-impact moves to get from where they are now to their #1 goal (${d.goal||"their goal"}). Be specific to their field and location, and pace it for ${d.hours||"their available"} hours per week.

## Where your customers are
List the specific, real, named places their ideal customer actually finds and books a ${d.field||"business like theirs"} in ${d.location||"their area"} — the directories, listing sites, marketplaces, review platforms, and social or community spaces that matter for THIS niche (not generic "just be on social media" advice). For each one, give a single sentence on why it matters for them and the first thing to do there. Put the few highest-payoff ones first.

## How Chelgy fixes all of this
Before listing tools, write 2 to 4 warm, confident sentences that make this point clearly: everything flagged in this audit can be fixed right here inside Chelgy. They don't need to hire an agency, a designer, a copywriter, or a consultant, and they don't have to do it alone — Chelgy is their team. Make them feel capable and ready to start.

## Your Chelgy toolkit
For the key roadmap steps, name the EXACT Chelgy tool to use and one sentence on how to use it for that step. Only use tools from this list:
- Business Builder (builds their entire business — a complete published website, logo, brand strategy, social plan, and launch roadmap)
- Website Builder (writes and publishes a complete, ready-to-share website — and lets them buy & connect their own domain right inside it)
- AI Image Creator (logos, flyers, social graphics, product images)
- Product Studio (studio-quality product photos — clean packshots, lifestyle, or on a model)
- AI Video Studio & Viral Video Generator (video scripts, viral ideas, AI video)
- UGC Studio (build a consistent creator, then make authentic talking-to-camera UGC videos)
- Ad Campaign Builder (ad copy, targeting, budget for Facebook/Instagram/TikTok)
- Business Manager (clients/CRM, invoices with online payment links, proposals, contracts — all in one place)
- Business Audit & Competitors (scan your presence, compare to competitors)
- Backlink & Authority Builder (find real places to get listed, linked & featured, with the outreach written for them)
- AI Voiceover Studio (studio-quality voiceovers)
- Business Coach (stage-by-stage plans + a 24/7 AI coach)
- Grant Finder (search real grants and funding)
- AI Content Writer (captions, posts, blogs, emails, ad copy)
- Dropshipping Directory (vetted suppliers)
- Platform Setup Guides (set up Google Business, social profiles, etc.)
- AI Advisor (ask any marketing question anytime)

Keep it specific, encouraging, and skimmable. Short paragraphs. No fluff and no preamble before the first heading. End right after the toolkit — the best next step is for them to open their roadmap and start with today's highest-impact task.`;
    const result = await callClaude(prompt, 6000, true);
    setPlan(result);
    try { localStorage.setItem("chelgy_plan", result); } catch(e){}
    if(user && user.access_token && user.id) patchMyMember(user.access_token, user.id, { plan: result });
    setPlanLoading(false);
    buildTasks(d); // generate the checkable big tasks from the same answers
  }
  async function buildTasks(d){
    const haveStr = (d.have && d.have.length) ? d.have.join(", ") : "nothing yet";
    const stage = d.hasBiz==="running" ? "running business" : d.hasBiz==="starting" ? "just starting" : "just an idea";
    const prompt =
`Based on this member's situation, list their 6 most important "big tasks" to grow toward their #1 goal, in priority order (highest impact first).
Member: ${stage}; business/idea: ${d.what||"n/a"}; field: ${d.field||"n/a"}; location: ${d.location||"n/a"}; already has: ${haveStr}; #1 goal: ${d.goal||"n/a"}; biggest challenge: ${d.challenge||"n/a"}; hours/week: ${d.hours||"n/a"}.
For each task also pick the single best Chelgy tool to accomplish it, by its id, or "" if none fits. Tool ids:
launch = build the whole business (published website + logo + brand + social + launch plan); website = write & publish a complete website; images = make logos, flyers, graphics, product photos; productstudio = studio-quality product photos; video = video scripts & AI video; viral = viral video ideas; ugcstudio = UGC creator & authentic videos; ads = paid ad campaigns; audit = scan presence & competitors; manager = clients, invoices, proposals & contracts; voiceover = voiceovers; business = stage-by-stage plan + AI coach; grants = find funding; content = write posts/captions/emails/blogs; backlinks = get listed, linked & featured; dropshipping = find suppliers; platforms = set up Google Business & social profiles.
Return ONLY a JSON array — no markdown, no code fences, no preamble. Each item: {"title": short action under 9 words, "detail": one sentence on how or why, "time": estimate like "15 min" or "1 hour", "impact": integer 1-5, "tool": one tool id from the list or ""}.`;
    const raw = await callClaude(prompt, 1800, false);
    let tasks = [];
    try {
      const clean = raw.replace(/```json/gi,"").replace(/```/g,"").trim();
      const arr = JSON.parse(clean.slice(clean.indexOf("["), clean.lastIndexOf("]")+1));
      tasks = arr.map((t,i)=>({ id:"big-"+Date.now()+"-"+i, title:String(t.title||"").slice(0,80), detail:String(t.detail||""), time:String(t.time||""), impact:Math.max(1,Math.min(5,parseInt(t.impact,10)||3)), tool:(TOOL_LABELS[t.tool]?t.tool:""), done:false }));
    } catch { tasks = []; }
    if(tasks.length){
      setBigTasks(tasks);
      lsSet("chelgy_tasks", tasks);
      if(user && user.access_token && user.id) patchMyMember(user.access_token, user.id, { tasks });
    }
  }
  // Persist task progress
  useEffect(()=>{ lsSet("chelgy_tasks", bigTasks); if(user && user.access_token && user.id) patchMyMember(user.access_token, user.id, { tasks: bigTasks }); },[bigTasks]);
  useEffect(()=>{ lsSet("chelgy_daily_done", dailyDone); },[dailyDone]);
  useEffect(()=>{ lsSet("chelgy_completions", completions); },[completions]);
  function logCompletion(delta){ const day=todayStr(); setCompletions(c=>{ const n={...c}; n[day]=Math.max(0,(n[day]||0)+delta); return n; }); }
  function sumCompletions(days){ const now=new Date(); let total=0; for(const k of Object.keys(completions)){ const dt=new Date(k+"T00:00:00"); const diff=(now-dt)/86400000; if(diff>=0 && diff<days) total+=(completions[k]||0); } return total; }
  function computeStreak(){ let streak=0; const day=new Date(); if(!(completions[todayStr()]>0)) day.setDate(day.getDate()-1); while(completions[fmtDate(day)]>0){ streak++; day.setDate(day.getDate()-1); } return streak; }
  function celebrateDone(){ const lines=["Nice work — that's done.","Done! Momentum is everything.","One step closer. Keep going.","Checked off. You're building real progress."]; setCelebrate(lines[Math.floor(Math.random()*lines.length)]); setTimeout(()=>setCelebrate(""),2600); }
  function toggleBigTask(id){ setBigTasks(ts=>ts.map(t=>{ if(t.id===id){ const nd=!t.done; if(nd){ celebrateDone(); logCompletion(1); addPts(PTS.bigTask); } else logCompletion(-1); return {...t,done:nd}; } return t; })); }
  function toggleDaily(id){ setDailyDone(dd=>{ const nd={...dd}; if(nd[id]){ delete nd[id]; logCompletion(-1); } else { nd[id]=true; celebrateDone(); logCompletion(1); addPts(PTS.daily); } return nd; }); }
  function openTool(toolId){ if(!toolId||!TOOL_LABELS[toolId]) return; setShowTasks(false); setShowGreeting(false); goTab("tools", toolId); }
  // Generate today's free "on the house" gift. Rollover: the rotation only advances
  // the first time the member opens the app on a new day, so being away doesn't skip gifts.
  async function generateGift(){
    if(giftLoading) return;
    let idx, day=null;
    try{ idx = parseInt(localStorage.getItem("chelgy_gift_idx")||"NaN",10); day = localStorage.getItem("chelgy_gift_day"); }catch(e){}
    if(day !== todayStr()){
      idx = isNaN(idx) ? 0 : idx + 1;               // advance to the next gift for a new active day
      try{ localStorage.setItem("chelgy_gift_idx", String(idx)); localStorage.setItem("chelgy_gift_day", todayStr()); localStorage.removeItem("chelgy_gift_payload"); }catch(e){}
    } else if(isNaN(idx)){ idx = 0; }
    const g = giftTypeAt(idx);
    setGiftLoading(true);
    const ctx = bizContext();
    let payload = null;
    try{
      if(g.kind === "text"){
        const out = await callClaude(giftTextPrompt(g.key, ctx), 500);
        payload = { type:g.key, kind:"text", noun:g.noun, tool:g.tool, label:g.label, content:(out||"").trim() };
      } else {
        // Free image gift (server enforces the 3/week cap). If capped/failed, fall back to a free text gift.
        const tok = await freshToken();
        const res = await fetch("/api/gift-image", { method:"POST", headers:{ "Content-Type":"application/json", ...(tok?{Authorization:"Bearer "+tok}:{}) }, body:JSON.stringify({ prompt: giftImagePrompt(g.key, ctx), aspectRatio: g.key==="flyer"?"4:5":"1:1" }) });
        const d = await res.json().catch(()=>null);
        if(d && d.image){
          let url = d.image;
          try{ const up = await uploadSiteImage(d.image, ((user&&user.id)||"u")+"/gift-"+todayStr()+"-"+Math.random().toString(36).slice(2,6)+".png"); if(up) url = up; }catch(e){}
          payload = { type:g.key, kind:"image", noun:g.noun, tool:g.tool, label:g.label, content:url };
        }
        else {
          const fb = await callClaude(giftTextPrompt("caption", ctx), 500);
          payload = { type:"caption", kind:"text", noun:"social post", tool:"content", label:"Content Writer", content:(fb||"").trim(), fellBack:true };
        }
      }
    }catch(e){
      try{ const fb = await callClaude(giftTextPrompt("caption", ctx), 500); payload = { type:"caption", kind:"text", noun:"social post", tool:"content", label:"Content Writer", content:(fb||"").trim(), fellBack:true }; }catch(e2){}
    }
    if(payload){ setGift(payload); try{ localStorage.setItem("chelgy_gift_payload", JSON.stringify(payload)); localStorage.setItem("chelgy_gift_day", todayStr()); }catch(e){} }
    setGiftLoading(false);
  }
  // Short description of the member's business — fed to the AI so it "knows" them
  function bizContext(){
    const i = intake || {};
    const parts = [];
    if(isDemo || isMarketerSpace || (isTeamSpace && marketerStatus==="approved")) parts.push("IMPORTANT CONTEXT: You are assisting an independent marketer who runs marketing for MULTIPLE separate client businesses and mass-produces content, campaigns, images, ads and websites for them at volume. Assume any request is work for one of their clients. Produce polished, client-ready output; keep each client's brand voice distinct; and when it would change the output, briefly ask which client or brand this is for. Be fast and practical — they are producing a high volume of work");
    if(myName && myName!=="You" && myName!=="Member") parts.push("Member name: "+myName);
    if(i.what || myBusiness) parts.push("Business: "+(i.what||myBusiness));
    if(i.field) parts.push("Field: "+i.field);
    if(i.hasBiz) parts.push("Stage: "+({running:"up and running",starting:"just starting",idea:"idea stage"})[i.hasBiz]);
    if(i.location) parts.push("Location: "+i.location);
    if(i.goal) parts.push("Their #1 goal: "+i.goal);
    if(i.challenge) parts.push("Biggest challenge: "+i.challenge);
    return parts.join(". ");
  }
  async function openJournal(){ setShowJournal(true); await loadJournal(); }
  async function loadJournal(){
    const tok = await freshToken(); if(!tok || !user || !user.id) return;
    try {
      const res = await fetch(SUPABASE_URL+"/rest/v1/journal_entries?select=*&user_id=eq."+user.id+"&order=entry_date.desc,id.desc", { headers:{ apikey:SUPABASE_KEY, Authorization:"Bearer "+tok } });
      const rows = await res.json();
      if(!Array.isArray(rows)) return;
      setJournalEntries(rows);
      const todays = rows.find(r=>r.entry_date===todayStr());
      if(todays){ setJTodayId(todays.id); setJWins(todays.wins||""); setJStruggles(todays.struggles||""); setJResp(todays.ai_response||""); }
      else { setJTodayId(null); setJWins(""); setJStruggles(""); setJResp(""); }
    } catch(e){}
  }
  async function saveJournal(){
    if(!jWins.trim() && !jStruggles.trim()) return;
    const wasNew = !jTodayId;
    setJSaving(true);
    let aiResp = "";
    if(jStruggles.trim()){
      const prompt =
`You are Chelgy — a warm, encouraging business coach speaking directly to a member who is journaling today. ${bizContext()}.
Today they wrote:
WINS: ${jWins.trim()||"(none noted)"}
WHAT FELT HARD / STRESSFUL: ${jStruggles.trim()}
Respond directly to them in 3 to 5 warm sentences: briefly celebrate the win if there is one, then give one or two specific, practical suggestions for what's hard. If a Chelgy tool would genuinely help (Image Creator, Content Writer, Ad Campaign Builder, Business Audit, Grant Finder, Platform Setup Guides, AI Advisor), mention it by name. Be supportive and human, not preachy. No headings, no bullet points.`;
      aiResp = await callClaude(prompt, 1200, false);
    }
    const tok = await freshToken();
    if(tok && user && user.id){
      try {
        if(jTodayId){
          await fetch(SUPABASE_URL+"/rest/v1/journal_entries?id=eq."+jTodayId, { method:"PATCH", headers:{ apikey:SUPABASE_KEY, Authorization:"Bearer "+tok, "Content-Type":"application/json", Prefer:"return=minimal" }, body:JSON.stringify({ wins:jWins, struggles:jStruggles, ai_response:aiResp }) });
        } else {
          const res = await fetch(SUPABASE_URL+"/rest/v1/journal_entries", { method:"POST", headers:{ apikey:SUPABASE_KEY, Authorization:"Bearer "+tok, "Content-Type":"application/json", Prefer:"return=representation" }, body:JSON.stringify({ user_id:user.id, entry_date:todayStr(), wins:jWins, struggles:jStruggles, ai_response:aiResp }) });
          const rows = await res.json(); const row = Array.isArray(rows)?rows[0]:rows; if(row && row.id) setJTodayId(row.id);
        }
      } catch(e){}
    }
    setJResp(aiResp);
    setJSaving(false);
    if(wasNew) addPts(PTS.journal);
    if(jWins.trim()) celebrateDone();
    loadJournal();
  }
