  useEffect(()=>{
    // ─── Returning from an OAuth sign-in (Apple/Google)? Token was captured at load, before any URL rewrite ───
    const hash = CHELGY_INITIAL_HASH;
    if (hash.includes("access_token=")) {
      const hp = new URLSearchParams(hash.replace(/^#/, ""));
      const at = hp.get("access_token"); const rt = hp.get("refresh_token");
      if (at) {
        const payload = decodeJwtPayload(at) || {};
        const meta = payload.user_metadata || {};
        const sess = { id: payload.sub, email: payload.email || meta.email || "", name: meta.full_name || meta.name || ((payload.email||"").split("@")[0]) || "", access_token: at, refresh_token: rt };
        try { localStorage.setItem("chelgy_session", JSON.stringify(sess)); } catch {}
        setUser(sess); setMyName(sess.name || sess.email);
        let mem=false; try{ mem = localStorage.getItem("chelgy_member")==="1"; }catch{}
        setIsTrial(!mem);
        setPage("app");
        track("login", { method: "google" });
        try { window.history.replaceState({}, "", "/"); } catch {}
        return;
      }
    }
    // OAuth returned an ERROR (common with Apple when the Supabase provider config
    // is incomplete, or when Apple sends no email on a repeat sign-in). Surface the
    // real message instead of silently dropping to onboarding.
    if (hash.indexOf("error") > -1 || window.location.search.indexOf("error") > -1) {
      try {
        const raw = (hash.indexOf("error") > -1) ? hash.replace(/^#/, "") : window.location.search.replace(/^\?/, "");
        const ep = new URLSearchParams(raw);
        const desc = (ep.get("error_description") || ep.get("error") || "").replace(/\+/g, " ");
        if (desc) pushNotif("Sign-in error: " + decodeURIComponent(desc));
      } catch (e) {}
      setPage("onboarding");
      try { window.history.replaceState({}, "", "/"); } catch {}
      return;
    }
    const params = new URLSearchParams(window.location.search);
    const isAdminUrl = window.location.search.includes("admin");
    const isPay = params.get("payment")==="success";
    if (isPay) {
      let n = params.get("name");
      try { if(!n) n = localStorage.getItem("chelgy_name"); } catch {}
      setMyName(n||"Member"); setIsTrial(false); setPage("app");
      try { localStorage.setItem("chelgy_member","1"); } catch {}
      try { const ss=loadSession(); if(ss&&ss.access_token&&ss.id) patchMyMember(ss.access_token, ss.id, { status:"paid" }); } catch {}
    }
    if (isAdminUrl) {
      setPage("app"); setIsTrial(false); setIsAdmin(true); setAdminPanelOpen(true);
    }
    const isCreditsBuy = params.get("credits")==="success";
    if (isCreditsBuy) {
      pushNotif("Payment received — your new credits are being added to your balance.");
      const refresh = ()=>{ const ss=loadSession(); if(ss&&ss.access_token&&ss.id) getMyMember(ss.access_token, ss.id).then(m=>{ if(m){ const bal=(m.credits||0)+(m.credits_purchased||0); setCredits(bal); lsSet("chelgy_credits", bal); } }); };
      setTimeout(refresh, 2500); setTimeout(refresh, 7000); // webhook may take a moment
      try { window.history.replaceState({}, "", "/"); } catch {}
    }
    const isMembershipBuy = params.get("membership")==="success";
    if (isMembershipBuy) {
      pushNotif("Payment received — activating your marketer membership…");
      const refreshM = ()=>{ const ss=loadSession(); if(ss&&ss.access_token&&ss.id) getMyMember(ss.access_token, ss.id).then(m=>{ if(m&&m.status&&["paid","comp","admin","active"].includes(String(m.status).toLowerCase())){ setIsPaid(true); setIsTrial(false); try{localStorage.setItem("chelgy_member","1");}catch(e){} } }); };
      setTimeout(refreshM, 2500); setTimeout(refreshM, 7000); setTimeout(refreshM, 12000); // webhook may take a moment
      try { window.history.replaceState({}, "", "/?team"); } catch {}
    }
    const isMemberBuy = params.get("member")==="success";
    if (isMemberBuy) {
      pushNotif("Payment received — activating your membership…");
      const refreshMem = ()=>{ const ss=loadSession(); if(ss&&ss.access_token&&ss.id) getMyMember(ss.access_token, ss.id).then(m=>{ if(m&&m.status&&["paid","comp","admin","active"].includes(String(m.status).toLowerCase())){ setIsPaid(true); setIsTrial(false); try{localStorage.setItem("chelgy_member","1");}catch(e){} freshToken().then(t=>t?claimMonthlyCredits(t):null).then(tot=>{ if(typeof tot==="number"){ setCredits(tot); lsSet("chelgy_credits", tot); } }); } }); };
      setTimeout(refreshMem, 2500); setTimeout(refreshMem, 7000); setTimeout(refreshMem, 12000); // webhook may take a moment
      try { window.history.replaceState({}, "", "/"); } catch {}
    }
    const s = loadSession();
    if (s && s.email) {
      setUser(s);
      setMyName(s.name || s.email);
      let member = false; try { member = localStorage.getItem("chelgy_member")==="1"; } catch {}
      setIsTrial(!member);
      if (!isPay && !isAdminUrl) setPage("app");
    }
  },[]);

