  async function submitHelp() {
    setHelpErr("");
    if (!helpName.trim() || !helpEmail.trim() || !helpMsg.trim()) { setHelpErr("Please fill in your name, email, and message."); return; }
    if (!/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(helpEmail.trim())) { setHelpErr("Please enter a valid email address."); return; }
    setHelpSending(true);
    const entry = { id: Date.now(), name: helpName.trim(), email: helpEmail.trim(), message: helpMsg.trim(), time: new Date().toLocaleString() };
    // Save to Supabase so it appears in the admin panel on any device
    let saved = null;
    try { saved = await sbFetch("help_requests","POST",{ name: entry.name, email: entry.email, message: entry.message }); } catch(e){ saved = null; }
    setHelpSending(false);
    if (saved && saved.length) {
      // Keep a local copy too for instant feedback
      setHelpRequests(prev => [entry, ...prev]);
      setHelpDone(true); setHelpMsg("");
    } else {
      // Don't pretend it worked — let the person know so they can retry
      setHelpErr("Sorry — that didn't send. Please check your connection and try again in a moment.");
    }
  }

  async function submitNewsletter() {
    setSubErr("");
    const email = emailSub.trim();
    if (!email) { setSubErr("Please enter your email."); return; }
    if (!/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(email)) { setSubErr("Please enter a valid email address."); return; }
    setSubSending(true);
    let saved = null;
    try { saved = await sbFetch("subscribers","POST",{ email: email }); } catch(e){ saved = null; }
    setSubSending(false);
    if (saved && saved.length) {
      setSubscribed(true); setEmailSub("");
    } else {
      setSubErr("Sorry — that didn't go through. Please try again in a moment.");
    }
  }

